# 4. DECORATOR UTILITIES
# ══════════════════════════════════════════════════════════════════════════════
def safe_exec(default_return=(False, "Operation failed"), log_exc=True):
    """Decorator: catches all exceptions, returns default_return tuple.

    [V14.3-FIX-M10] Now surfaces the exception type+message in the default
    return so users see WHAT failed instead of a generic "Operation failed".
    Programming errors (TypeError, AttributeError) are re-raised so bugs
    don't hide behind the decorator.
    """
    def decorator(fn):
        @wraps(fn)
        def wrapper(*args, **kwargs):
            try:
                return fn(*args, **kwargs)
            except (TypeError, AttributeError, NameError) as e:
                # Programming errors — re-raise so bugs are visible, not swallowed
                if log_exc:
                    logger.error(f"{fn.__qualname__} programming error: {type(e).__name__}: {e}")
                raise
            except Exception as e:
                if log_exc:
                    logger.error(f"{fn.__qualname__} raised {type(e).__name__}: {e}")
                    logger.debug(traceback.format_exc())
                # [FIX-M10] surface the exception in the return message
                if isinstance(default_return, tuple) and len(default_return) == 2:
                    return (False, f"{default_return[1]}: {type(e).__name__}: {e}")
                return default_return
        return wrapper
    return decorator


# [C-1] FIX: require() now validates arg pairing at decoration time, not silently
def require(*flags_and_msgs):
    """
    Decorator: check availability flags before running.
    Usage: @require(PSUTIL_OK, "psutil not installed")
    FIXED: Raises TypeError at decoration time if args are not paired correctly.
    """
    # Validate at decoration time
    if len(flags_and_msgs) % 2 != 0:
        raise TypeError(
            f"@require expects paired (flag, message) args, got {len(flags_and_msgs)} args "
            f"(odd number). Example: @require(PSUTIL_OK, 'psutil not installed')"
        )

    def decorator(fn):
        @wraps(fn)
        def wrapper(*args, **kwargs):
            flags   = flags_and_msgs[::2]
            messages = flags_and_msgs[1::2]
            for flag, msg in zip(flags, messages):
                if not flag:
                    return False, msg
            return fn(*args, **kwargs)
        return wrapper
    return decorator


