# 4b. SHARED UTILITY FUNCTIONS (DRY consolidations)
# ══════════════════════════════════════════════════════════════════════════════
# The following utilities were extracted from duplicate implementations across
# FileManager, FileOps, BrowserController, ClipboardController, WindowController,
# PasswordManager, HabitTracker, NotesManager, and the V2 agent hierarchy.
# Each utility is documented with its origin classes.

def fuzzy_tokens_match(query: str, filename: str) -> bool:
    """Token-based fuzzy match for file search.

    Consolidated from FileManager._fuzzy_tokens_match and
    FileOps._fuzzy_tokens_match (identical implementations).

    Normalizes underscores, hyphens, dots, and whitespace to single spaces
    in both the query and filename, then checks that every query token
    (length > 1) appears somewhere in the normalized filename.

    Example: fuzzy_tokens_match("bus ticket pdf", "bus_ticket_confirmation.pdf")
             → True
    """
    def _norm(s: str) -> str:
        return re.sub(r'[_\-\.\s]+', ' ', s.lower()).strip()
    q_tokens = [t for t in _norm(query).split() if t and len(t) > 1]
    if not q_tokens:
        return False
    f_norm = _norm(filename)
    return all(tok in f_norm for tok in q_tokens)


def send_hotkey(*keys: str) -> Tuple[bool, str]:
    """Send a keyboard hotkey via pyautogui with a small settle delay.

    Consolidated from BrowserController._hk, ClipboardController._hk,
    and WindowController._hk (3 identical implementations). The 4th variant
    in BrowserFeatureManager._hk had a slightly different message format and
    try/except wrapper — it retains its own implementation for backward compat.

    Returns (True, "Done") on success, (False, "pyautogui not available") if
    pyautogui is not installed.
    """
    if not PAG_OK:
        return False, "pyautogui not available"
    pyautogui.hotkey(*keys)
    time.sleep(0.05)
    return True, "Done"


def load_json_file(path: Path, default: Any) -> Any:
    """Load JSON from a file, returning `default` if missing or invalid.

    Consolidated from the _load() methods of NotesManager, PasswordManager,
    and HabitTracker. Each used the same try/except pattern but different
    attribute names; this utility centralizes the file-reading logic.

    Args:
        path: Path to the JSON file.
        default: Value to return if file doesn't exist or contains invalid JSON.

    Returns:
        Parsed JSON value, or `default`.
    """
    if not path.exists():
        return default
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return default


def save_json_file(path: Path, data: Any, indent: int = 2, ensure_ascii: bool = False) -> None:
    """Save data as JSON to a file.

    Consolidated from the _save() methods of NotesManager, PasswordManager,
    and HabitTracker.

    Args:
        path: Destination file path.
        data: Value to serialize.
        indent: JSON indentation (default 2).
        ensure_ascii: If False (default), non-ASCII chars are written directly.
    """
    path.write_text(json.dumps(data, indent=indent, ensure_ascii=ensure_ascii), encoding="utf-8")


def test_llm_availability(ai_gateway: Any) -> bool:
    """Check if an AI gateway is reachable by sending a minimal probe.

    Consolidated from LLMCentricBrain._test_availability and
    LLMBrain._test_availability (identical implementations).

    Sends "reply with the word OK only" with max_tokens=5 and returns True
    if the gateway responds successfully.
    """
    try:
        ok, _ = ai_gateway.chat("reply with the word OK only", max_tokens=5)
        return bool(ok)
    except Exception:
        return False


def split_sentences(text: str) -> List[str]:
    """Split text into sentences for interruptible TTS playback.

    Consolidated from InterruptibleTTS.speak() and TTSCore.speak_streaming()
    (both used the same regex `(?<=[.!?])\\s+` to split on sentence-ending
    punctuation). Centralizing this ensures consistent splitting behavior
    across the TTS subsystem.

    Args:
        text: Full text to split.

    Returns:
        List of sentence strings (whitespace-stripped, empties removed).
    """
    if not text:
        return []
    raw = re.split(r'(?<=[.!?])\s+', text.strip())
    return [s.strip() for s in raw if s.strip()]


