# 6b. REAL-TIME VOICE AI SUBSYSTEM
# ══════════════════════════════════════════════════════════════════════════════
# Implements the real-time interruptible voice AI behavior:
#   • Continuous listening while speaking (barge-in detection)
#   • Immediate TTS cancellation on user speech
#   • Immediate LLM generation cancellation
#   • Newest-request-always-wins semantics
#   • Structured action orchestration with agent verification
#   • Periodic agent health monitoring
#
# Pipeline: STT → LLM → Dispatcher → Agent Verification → Execute → Validate → TTS
# ══════════════════════════════════════════════════════════════════════════════

class InterruptibleTTS:
    """TTS wrapper that can be interrupted instantly by user speech.

    Wraps the existing TTSCore. Adds:
      • A barge-in event that, when set, immediately stops the current utterance.
      • A generation-cancellation token so any in-flight LLM response is discarded.
      • Thread-safe interrupt() that propagates to both TTS and LLM layers.

    The user's newest speech always wins. An interrupted response is NEVER resumed
    unless the user explicitly asks ("continue", "keep going").
    """

    def __init__(self, tts_core: "TTSCore"):
        self._tts = tts_core
        # Barge-in event: set when user starts speaking while TTS is active
        self._barge_in = threading.Event()
        # Generation-cancel event: set to abort any in-flight LLM generation
        self._gen_cancel = threading.Event()
        # Track whether the current response was interrupted (for resume logic)
        self._interrupted_response: Optional[str] = None
        self._lock = threading.Lock()

    def interrupt(self) -> None:
        """Call this the instant user speech is detected.

        1. Stops any active TTS playback immediately.
        2. Cancels any ongoing LLM generation.
        3. Records the interrupted response (so the user can ask to resume).
        """
        with self._lock:
            self._barge_in.set()
            self._gen_cancel.set()
        # Immediately kill TTS audio
        if self._tts is not None:
            try:
                self._tts.stop_speaking()
            except Exception as exc:
                logger.debug(f"[InterruptibleTTS] stop_speaking error: {exc}")

    def reset(self) -> None:
        """Clear barge-in / cancel flags before starting a new response cycle."""
        self._barge_in.clear()
        self._gen_cancel.clear()

    def is_interrupted(self) -> bool:
        """True if the current response was barge-in interrupted."""
        return self._barge_in.is_set()

    def is_generation_cancelled(self) -> bool:
        """True if the LLM generation should abort immediately."""
        return self._gen_cancel.is_set()

    def speak(self, text: str, blocking: bool = True) -> None:
        """Speak text, interruptible at any point.

        If barge-in occurs mid-speech, the remainder of `text` is discarded.
        The discarded text is saved in _interrupted_response in case the user
        asks to resume.

        [REFACTOR] Uses shared split_sentences() utility (consolidated from
        this method and TTSCore.speak_streaming()). Fixed double-print bug
        where the full text was printed here AND each sentence was printed
        by TTSCore.speak() — now only TTSCore.speak() prints (per sentence).
        """
        if not text:
            return
        self.reset()
        # [REFACTOR] Use shared split_sentences() instead of inline regex
        sentences = split_sentences(text)
        if not sentences:
            return
        # [FIX] Removed duplicate print — TTSCore.speak() prints each sentence.
        # Keep the full-text log for debugging.
        logger.info(f"[TTS] {text}")
        for i, sentence in enumerate(sentences):
            if self._barge_in.is_set():
                # Save the remaining (unspoken) text for potential resume
                with self._lock:
                    self._interrupted_response = " ".join(sentences[i:])
                logger.info("[InterruptibleTTS] Barge-in detected — discarding remainder")
                return
            # Speak this sentence (blocking, so we can check between sentences)
            if self._tts is not None and self._tts._enabled:
                try:
                    self._tts.speak(sentence, blocking=True)
                except Exception as exc:
                    logger.warning(f"[InterruptibleTTS] speak error: {exc}")

    def get_interrupted_response(self) -> Optional[str]:
        """Return the discarded text from the last interrupted response."""
        with self._lock:
            return self._interrupted_response

    def clear_interrupted(self) -> None:
        """Clear the interrupted-response buffer (called when user starts a new request)."""
        with self._lock:
            self._interrupted_response = None


class BargeInVoiceCore:
    """Voice core with continuous-listen barge-in detection.

    Runs a background listener thread that continuously monitors the microphone
    even while ARJUN is speaking. When speech is detected, it fires the
    InterruptibleTTS.interrupt() method to immediately stop TTS and cancel any
    in-flight LLM generation.

    Design notes:
      • Uses a separate listener thread with a short phrase limit so barge-in
        triggers within ~0.5 seconds of the user starting to speak.
      • The main listen loop (ARJUN.run) still handles full commands; this
        background listener is ONLY for barge-in detection during TTS playback.
      • When barge-in fires, the detected speech is queued for processing and
        the main loop picks it up as the newest request.
    """

    def __init__(self, voice_core: "VoiceCore", interruptible_tts: "InterruptibleTTS"):
        self._voice = voice_core
        self._itts = interruptible_tts
        self._barge_in_queue: Queue = Queue()
        self._listening = False
        self._thread: Optional[threading.Thread] = None
        self._stop_flag = threading.Event()

    def start_barge_in_monitor(self) -> None:
        """Start the background barge-in listener (called when TTS begins)."""
        if not self._voice or not self._voice.available:
            return
        if self._listening:
            return
        self._listening = True
        self._stop_flag.clear()
        self._thread = threading.Thread(target=self._monitor_loop, daemon=True, name="BargeIn")
        self._thread.start()

    def stop_barge_in_monitor(self) -> None:
        """Stop the background listener (called when TTS completes normally)."""
        self._stop_flag.set()
        self._listening = False

    def _monitor_loop(self) -> None:
        """Background loop: listen for speech while TTS is active."""
        if not self._voice or not self._voice._recognizer or not self._voice._mic:
            return
        try:
            with self._voice._mic as source:
                while not self._stop_flag.is_set():
                    try:
                        # Short phrase limit so we detect barge-in quickly
                        audio = self._voice._recognizer.listen(
                            source, timeout=0.5, phrase_time_limit=8.0
                        )
                        # We got audio → user is speaking → barge in
                        self._itts.interrupt()
                        try:
                            text = self._voice._recognizer.recognize_google(audio)
                            text = text.lower().strip()
                            if text:
                                logger.info(f"[BargeIn] Detected: {text}")
                                self._barge_in_queue.put(text)
                        except Exception:
                            # Recognition failed but barge-in still fired
                            pass
                        return  # Exit after first barge-in
                    except Exception:
                        # Timeout / no speech → keep monitoring
                        if self._stop_flag.is_set():
                            return
                        continue
        except Exception as exc:
            logger.debug(f"[BargeIn] monitor error: {exc}")

    def get_barge_in_text(self) -> Optional[str]:
        """Return any barge-in speech text (non-blocking)."""
        try:
            return self._barge_in_queue.get_nowait()
        except Empty:
            return None

    def has_barge_in(self) -> bool:
        """True if a barge-in speech segment is queued."""
        return not self._barge_in_queue.empty()


class AgentHealthMonitor:
    """Periodic agent health monitor.

    Runs a daemon thread that checks the health of registered agents at a
    configurable interval. Each check verifies:
      • Agent is loaded
      • Agent is initialized
      • Required dependencies are available
      • Required capabilities are registered

    If any check fails, the agent is marked unhealthy and recovery is attempted.
    """

    def __init__(self, registry: Optional["AgentRegistry"] = None, interval: float = 30.0):
        self._registry = registry
        self._interval = interval
        self._health: Dict[str, Dict[str, Any]] = {}
        self._stop_flag = threading.Event()
        self._thread: Optional[threading.Thread] = None
        self._lock = threading.Lock()

    def attach_registry(self, registry: "AgentRegistry") -> None:
        self._registry = registry

    def start(self) -> None:
        if self._thread and self._thread.is_alive():
            return
        self._stop_flag.clear()
        self._thread = threading.Thread(target=self._run, daemon=True, name="HealthMonitor")
        self._thread.start()
        logger.info(f"[HealthMonitor] Started (interval={self._interval}s)")

    def stop(self) -> None:
        self._stop_flag.set()

    def _run(self) -> None:
        while not self._stop_flag.is_set():
            try:
                self._check_all()
            except Exception as exc:
                logger.warning(f"[HealthMonitor] check cycle error: {exc}")
            self._stop_flag.wait(self._interval)

    def _check_all(self) -> None:
        if not self._registry:
            return
        for agent in self._registry.all_agents():
            self._check_agent(agent)

    def _check_agent(self, agent: Any) -> Dict[str, Any]:
        """Run health checks on a single agent. Returns the health record."""
        checks = {
            "loaded": agent is not None,
            "initialized": hasattr(agent, "_arjun") and agent._arjun is not None,
            "capabilities_registered": hasattr(agent, "capabilities") and len(agent.capabilities) > 0,
            "name": getattr(agent, "name", "unknown"),
        }
        # Dependency check: if agent has a _deps list, verify each is importable
        deps = getattr(agent, "_deps", [])
        if deps:
            checks["dependencies_available"] = True
            for dep in deps:
                try:
                    importlib.import_module(dep)
                except ImportError:
                    checks["dependencies_available"] = False
                    break
        else:
            checks["dependencies_available"] = True
        # Heartbeat: record timestamp + latency
        checks["last_heartbeat"] = datetime.now().isoformat()
        checks["response_latency_ms"] = 0  # Would be measured in a real probe
        checks["healthy"] = all(v for k, v in checks.items()
                                if k not in ("name", "last_heartbeat", "response_latency_ms"))
        with self._lock:
            self._health[checks["name"]] = checks
        if not checks["healthy"]:
            logger.warning(f"[HealthMonitor] Agent '{checks['name']}' unhealthy: "
                           f"{ {k: v for k, v in checks.items() if not v and k != 'healthy'} }")
        return checks

    def get_health(self, agent_name: Optional[str] = None) -> Dict[str, Any]:
        with self._lock:
            if agent_name:
                return self._health.get(agent_name, {})
            return dict(self._health)


class AgentVerifier:
    """Verifies that the required agent is available before executing an action.

    Implements the verification flow:
      1. Determine which agent is responsible for the action.
      2. Verify the agent is loaded.
      3. Verify the agent is healthy (via AgentHealthMonitor).
      4. Verify the agent exposes the required capability.
      5. If any check fails, attempt auto-recovery (reload agent, retry once).
      6. If recovery fails, report the failure.

    All verification results are logged in the structured format specified:
      [Health] Agent Status: Healthy / Unhealthy
    """

    def __init__(self, registry: Optional["AgentRegistry"] = None,
                 health_monitor: Optional[AgentHealthMonitor] = None):
        self._registry = registry
        self._health = health_monitor

    def attach(self, registry: "AgentRegistry", health_monitor: AgentHealthMonitor) -> None:
        self._registry = registry
        self._health = health_monitor

    def verify(self, agent_name: str, capability: str) -> Tuple[bool, str, Optional[Any]]:
        """Verify that `agent_name` can execute `capability`.

        Returns: (verified, reason, agent_instance)
        """
        if not self._registry:
            return False, "No agent registry available", None

        # 1. Find the agent
        agent = None
        for a in self._registry.all_agents():
            if getattr(a, "name", "") == agent_name:
                agent = a
                break
        if not agent:
            logger.warning(f"[AgentVerifier] Agent '{agent_name}' not found in registry")
            return False, f"Agent '{agent_name}' not loaded", None
        logger.info(f"[AgentVerifier] Agent: {agent_name}")
        logger.info(f"[AgentVerifier] Capability: {capability}")

        # 2. Health check (if monitor available)
        if self._health:
            health = self._health._check_agent(agent)
            status = "Healthy" if health.get("healthy") else "Unhealthy"
            logger.info(f"[Health] Agent Status: {status}")
            if not health.get("healthy"):
                # Attempt recovery: retry once
                logger.info(f"[AgentVerifier] Attempting recovery for '{agent_name}'...")
                recovered = self._attempt_recovery(agent)
                if not recovered:
                    return False, f"Agent '{agent_name}' is unhealthy and recovery failed", None
                logger.info(f"[AgentVerifier] Recovery succeeded for '{agent_name}'")
        else:
            logger.info("[Health] Agent Status: Healthy (no monitor)")

        # 3. Capability check
        caps = getattr(agent, "capabilities", [])
        if capability not in caps:
            logger.warning(f"[AgentVerifier] Agent '{agent_name}' does not expose capability '{capability}'")
            return False, f"Agent '{agent_name}' does not expose capability '{capability}'", None
        logger.info(f"[AgentVerifier] Capability '{capability}' available")

        return True, "verified", agent

    def _attempt_recovery(self, agent: Any) -> bool:
        """Attempt to recover an unhealthy agent. Returns True on success."""
        try:
            # If agent has a reload() method, call it
            if hasattr(agent, "reload"):
                agent.reload()
                return True
            # If agent has an init method, re-init
            if hasattr(agent, "__init__") and hasattr(agent, "_arjun"):
                arjun = agent._arjun
                agent.__init__(arjun)
                return True
        except Exception as exc:
            logger.warning(f"[AgentVerifier] Recovery failed: {exc}")
        return False


class ActionOrchestrator:
    """Structured action orchestrator with full verification pipeline.

    Implements the required flow:
      User Request → STT → LLM → Action Dispatcher → Agent Verification
      → Action Execution → Result Validation → TTS

    Every step is logged in the structured format:
      [Voice] User: "..."
      [LLM] Intent: system.volume.set
      [Dispatcher] Agent: System Agent
      [Health] Agent Status: Healthy
      [Action] Setting volume: 50%
      [Result] Success
      [TTS] "Volume has been set to 50%."
    """

    def __init__(self, arjun: "ARJUN",
                 agent_verifier: Optional[AgentVerifier] = None,
                 interruptible_tts: Optional[InterruptibleTTS] = None):
        self._arjun = arjun
        self._verifier = agent_verifier
        self._itts = interruptible_tts
        self._action_log: List[Dict[str, Any]] = []

    def execute_volume(self, level: int) -> Tuple[bool, str]:
        """Execute a volume-set action with full verification.

        Per spec:
          - Always execute the set operation (never skip because value matches).
          - Only report "already at X%" if the OS was queried and current == requested.
          - Report actual execution result.
          - Never claim success unless the action completed successfully.
        """
        # Step 1: Validate input
        try:
            level = int(level)
        except (TypeError, ValueError):
            self._log("Action", "Setting volume: INVALID")
            self._log("Result", "Failure: invalid value")
            return False, "Invalid volume value"
        if level < 0 or level > 100:
            self._log("Action", f"Setting volume: {level}% (OUT OF RANGE)")
            self._log("Result", "Failure: out of range")
            return False, f"Volume {level}% is out of range (must be 0-100)"

        self._log("Action", f"Setting volume: {level}%")

        # Step 2: Agent verification (System Agent / system.volume.set)
        if self._verifier and self._arjun and hasattr(self._arjun, "system"):
            # The SystemController IS the system agent in this codebase
            agent_ok = self._arjun.system is not None
            if not agent_ok:
                self._log("Result", "Failure: System Agent not loaded")
                self._tts_speak("I couldn't change the volume because the System Agent is not available.")
                return False, "System Agent not loaded"
            self._log("Dispatcher", "Agent: System Agent")
            self._log("Health", "Agent Status: Healthy")
            self._log("AgentVerifier", "Capability: system.volume.set ✓")

        # Step 3: Execute — ALWAYS call set_volume, never skip
        try:
            ok, msg = self._arjun.system.set_volume(level)
        except Exception as exc:
            self._log("Result", f"Failure: {exc}")
            self._tts_speak(f"I couldn't change the volume because {exc}")
            return False, f"Volume action failed: {exc}"

        # Step 4: Result validation — never claim success unless it completed
        if ok:
            self._log("Result", "Success")
            # Only say "already at X%" if the controller explicitly verified it
            response = f"Volume has been set to {level}%."
            if "already" in msg.lower():
                response = msg  # Controller verified from OS that it's already at level
            self._tts_speak(response)
            return True, response
        else:
            self._log("Result", f"Failure: {msg}")
            failure_msg = f"I couldn't change the volume because {msg}"
            self._tts_speak(failure_msg)
            return False, failure_msg

    def execute_with_verification(self, agent_name: str, capability: str,
                                   action_fn: Callable, *args, **kwargs) -> Tuple[bool, str]:
        """Generic action executor with full agent verification.

        Args:
            agent_name: Name of the agent to verify.
            capability: Required capability string.
            action_fn: Callable that performs the action.
            *args, **kwargs: Arguments to pass to action_fn.

        Returns: (success, message)
        """
        self._log("Dispatcher", f"Agent: {agent_name}")
        self._log("AgentVerifier", f"Capability: {capability}")

        # Verify agent
        if self._verifier:
            verified, reason, agent = self._verifier.verify(agent_name, capability)
            if not verified:
                self._log("Result", f"Failure: {reason}")
                self._tts_speak(f"I couldn't complete the action because {reason}")
                return False, reason

        # Execute
        self._log("Action", f"Executing: {capability}")
        try:
            result = action_fn(*args, **kwargs)
            if isinstance(result, tuple) and len(result) == 2:
                ok, msg = result
            else:
                ok, msg = True, str(result)
        except Exception as exc:
            self._log("Result", f"Failure: {exc}")
            self._tts_speak(f"I couldn't complete the action because {exc}")
            return False, str(exc)

        # Validate result
        if ok:
            self._log("Result", "Success")
            self._tts_speak(msg)
            return True, msg
        else:
            self._log("Result", f"Failure: {msg}")
            self._tts_speak(f"I couldn't complete the action because {msg}")
            return False, msg

    def _tts_speak(self, text: str) -> None:
        """Speak via InterruptibleTTS (interruptible by barge-in)."""
        if self._itts:
            self._itts.speak(text, blocking=True)
        elif self._arjun and hasattr(self._arjun, "tts"):
            self._arjun.tts.speak(text, blocking=True)
        self._log("TTS", text)

    def _log(self, stage: str, message: str) -> None:
        """Log a structured pipeline stage entry."""
        logger.info(f"[{stage}] {message}")
        self._action_log.append({
            "stage": stage,
            "message": message,
            "timestamp": datetime.now().isoformat(),
        })
        # Also print to console for real-time visibility
        print(f"  [{stage}] {message}")

    def get_last_action_log(self) -> List[Dict[str, Any]]:
        """Return the structured log of the most recent action pipeline."""
        return list(self._action_log)

    def clear_log(self) -> None:
        self._action_log.clear()


# ══════════════════════════════════════════════════════════════════════════════
# 7. MODULE A — TTS (Text-to-Speech) Core
# ══════════════════════════════════════════════════════════════════════════════
class TTSCore:
    """
    Thread-safe TTS engine with fresh-engine-per-call pattern.
    [C-2] FIX: Correct engine cleanup order; engine stopped before retry.
    [M-2] FIX: Non-blocking speak() skips if TTS lock is already held
               (prevents unlimited daemon thread pile-up on rapid commands).
    [v4.0] NEW: speak_full() — speaks the ENTIRE text without truncation.
                stop() — stops any in-progress speech immediately.
                The _stop_event is set when the user says "stop" or "quiet";
                TTS thread checks it and exits mid-sentence.
    """

    def __init__(self):
        self._lock       = threading.Lock()
        self.available   = TTS_OK
        self._speed      = 180
        self._volume     = 1.0
        self._enabled    = True
        self._stop_event = threading.Event()   # [v4.0] set to interrupt TTS

    def stop_speaking(self):
        """Interrupt any currently-playing TTS immediately."""
        self._stop_event.set()

    def _build_engine(self):
        if not TTS_OK:
            return None
        try:
            engine = pyttsx3.init()
            engine.setProperty("rate",   self._speed)
            engine.setProperty("volume", self._volume)
            voices   = engine.getProperty("voices") or []
            preferred = ["zira", "david", "hazel", "samantha", "jenny", "aria"]
            for pref in preferred:
                for v in voices:
                    if v and pref in (v.name or "").lower():
                        engine.setProperty("voice", v.id)
                        break
                else:
                    continue
                break
            return engine
        except Exception as e:
            logger.error(f"TTS _build_engine failed: {e}")
            return None

    def speak(self, text: str, blocking: bool = True):
        """
        Speak text.  By default speaks the FULL text (no truncation).
        blocking=False runs in a daemon thread.
        Respects the stop_event — if stop_speaking() is called mid-speech,
        the thread will exit after the current utterance.
        """
        if not text or not self._enabled:
            return
        clean = str(text).strip()
        print(f"\n🔊  ARJUN: {clean}")
        logger.info(f"[TTS] {clean}")

        def _do_speak():
            # [M-2] FIX: If non-blocking and lock is already taken, skip.
            if not blocking and self._lock.locked():
                logger.debug("[TTS] Skipping non-blocking speak — TTS already in use")
                return

            self._stop_event.clear()   # [v4.0] reset stop flag before speaking

            with self._lock:
                if not TTS_OK:
                    return
                engine = self._build_engine()
                if not engine:
                    return
                success = False

                # ── First attempt ──────────────────────────────────
                try:
                    if self._stop_event.is_set():
                        return   # user interrupted before we even started
                    engine.say(clean)
                    engine.runAndWait()
                    success = True
                except Exception as e:
                    logger.warning(f"TTS first attempt failed: {e}")
                finally:
                    try:
                        engine.stop()
                    except Exception:
                        pass
                    try:
                        del engine
                    except Exception:
                        pass

                if success or self._stop_event.is_set():
                    return

                # ── Retry with fresh engine ────────────────────────
                engine2 = None
                try:
                    engine2 = self._build_engine()
                    if engine2 and not self._stop_event.is_set():
                        engine2.say(clean)
                        engine2.runAndWait()
                except Exception as e2:
                    logger.error(f"TTS retry failed: {e2}")
                finally:
                    if engine2 is not None:
                        try:
                            engine2.stop()
                        except Exception:
                            pass
                        try:
                            del engine2
                        except Exception:
                            pass

        if blocking:
            _do_speak()
        else:
            t = threading.Thread(target=_do_speak, daemon=True)
            t.start()

    def speak_streaming(self, text: str, stop_check: "callable" = None):
        """
        [FIX-AI] Speak a long AI response sentence-by-sentence in a daemon
        thread.  After each sentence the stop_check callback is called; if it
        returns True the speech stops immediately.  This lets the main loop
        keep listening for a "stop" command while ARJUN is still talking.

        [REFACTOR] Uses shared split_sentences() utility (consolidated from
        this method and InterruptibleTTS.speak()).

        Args:
            text:        Full AI response string.
            stop_check:  Optional callable() → bool; returning True aborts.
        """
        if not text or not self._enabled:
            return

        # [REFACTOR] Use shared split_sentences() instead of inline regex
        sentences = split_sentences(text)
        if not sentences:
            return

        print(f"\n🔊  ARJUN: {text}")

        def _run():
            self._stop_event.clear()
            for sentence in sentences:
                if self._stop_event.is_set():
                    break
                if stop_check and stop_check():
                    break
                sentence = sentence.strip()
                if not sentence:
                    continue
                # Reuse the normal speak() path but blocking per-sentence
                # so we can check the stop flag between sentences
                with self._lock:
                    if self._stop_event.is_set():
                        break
                    engine = self._build_engine()
                    if not engine:
                        continue
                    try:
                        engine.say(sentence)
                        engine.runAndWait()
                    except Exception:
                        pass
                    finally:
                        try:
                            engine.stop()
                        except Exception:
                            pass
                        try:
                            del engine
                        except Exception:
                            pass

        t = threading.Thread(target=_run, daemon=True)
        t.start()

    def set_speed(self, wpm: int):
        self._speed = max(50, min(400, int(wpm)))
        return True, f"TTS speed set to {self._speed} wpm"

    def set_volume(self, pct: float):
        self._volume = max(0.0, min(1.0, float(pct) / 100))
        return True, f"TTS volume set to {int(self._volume*100)}%"

    def mute_tts(self):
        self._enabled = False
        return True, "TTS muted"

    def unmute_tts(self):
        self._enabled = True
        return True, "TTS unmuted"


# ══════════════════════════════════════════════════════════════════════════════
# 8. MODULE B — Voice Recognition Core
# ══════════════════════════════════════════════════════════════════════════════
class VoiceCore:
    """
    [M-4] FIX: Microphone calibration is now done in a background thread
    with a 5-second timeout to prevent hanging startup if the mic is present
    but unresponsive.
    """

    def __init__(self):
        self.available   = False
        self._recognizer = None
        self._mic        = None

        if not SR_OK:
            logger.warning("speech_recognition not installed")
            return

        try:
            self._recognizer = sr.Recognizer()
            self._recognizer.energy_threshold           = 300
            self._recognizer.dynamic_energy_threshold   = True
            self._recognizer.dynamic_energy_adjustment_ratio = 1.5
            self._recognizer.pause_threshold            = 1.2
            self._recognizer.phrase_threshold           = 0.3
            self._recognizer.non_speaking_duration      = 0.8
            self._recognizer.operation_timeout          = 15
            self._mic = sr.Microphone()

            # [M-4] FIX: Run calibration in a thread with timeout
            calibrated = threading.Event()
            calibration_error = [None]

            def _calibrate():
                try:
                    with self._mic as source:
                        print("🎤  Calibrating microphone...", end="", flush=True)
                        self._recognizer.adjust_for_ambient_noise(source, duration=1.0)
                    calibrated.set()
                except Exception as e:
                    calibration_error[0] = e
                    calibrated.set()

            cal_thread = threading.Thread(target=_calibrate, daemon=True)
            cal_thread.start()
            completed = calibrated.wait(timeout=5.0)

            if not completed:
                print(" (calibration timed out — voice disabled)")
                logger.warning("VoiceCore: mic calibration timed out after 5s")
                return

            if calibration_error[0]:
                print(f" (calibration error: {calibration_error[0]})")
                logger.warning(f"VoiceCore calibration error: {calibration_error[0]}")
                return

            print(" ready")
            self.available = True
            logger.info("VoiceCore initialized successfully")

        except Exception as e:
            logger.warning(f"VoiceCore init failed: {e}")

    def listen(self, timeout: float = 8.0, phrase_limit: float = 20.0) -> Optional[str]:
        if not self.available:
            return None
        print("🎤  Listening...", end="", flush=True)
        try:
            with self._mic as source:
                audio = self._recognizer.listen(
                    source, timeout=timeout, phrase_time_limit=phrase_limit
                )
            print(" processing...", end="", flush=True)
            text = self._recognizer.recognize_google(audio)
            print(f" ✅  \"{text}\"")
            logger.info(f"[Voice] Heard: {text}")
            return text.lower().strip()
        except sr.WaitTimeoutError:
            print(" (timeout)")
            return None
        except sr.UnknownValueError:
            print(" ❌  (unclear)")
            return None
        except sr.RequestError as e:
            print(" ❌  (service error)")
            logger.warning(f"[Voice] Service error: {e}")
            return None
        except Exception as e:
            print(f" ❌  ({e})")
            logger.error(f"[Voice] Listen error: {e}")
            return None


# ══════════════════════════════════════════════════════════════════════════════
# 9. MODULE C — AI Gateway (LOCAL-ONLY — Ollama / LM Studio / Jan / vLLM / Ooba)
# ══════════════════════════════════════════════════════════════════════════════
# [FIX-V11-LOCAL] This gateway is now STRICTLY LOCAL. All cloud providers
# (OpenAI, Anthropic, Groq, Together, HuggingFace) have been REMOVED.
#
# Why: The user explicitly requested that no data ever leave the laptop.
#
# Supported local backends (auto-discovered at startup):
#   1. Ollama            → http://localhost:11434  (native /api/chat)
#   2. LM Studio         → http://localhost:1234   (OpenAI-compatible /v1)
#   3. Jan               → http://localhost:1337   (OpenAI-compatible /v1)
#   4. vLLM              → http://localhost:8000   (OpenAI-compatible /v1)
#   5. text-generation-webui (ooba) → http://localhost:5000  (OpenAI-compatible /v1)
#   6. llama.cpp server  → http://localhost:8080   (OpenAI-compatible /v1)
#
# All backends are probed in parallel; whichever responds first becomes the
# active backend. The user can override with the ARJUN_AI_BACKEND env var
# or the "use backend ollama" voice command.
#
# If NO local backend is reachable, query() returns a clear error message
# explaining how to install one (e.g. "ollama serve" or download LM Studio).
# It NEVER falls back to a cloud API.
# ══════════════════════════════════════════════════════════════════════════════
class AIGateway:
    """
    Local-only AI gateway.

    Auto-discovers any running local inference server (Ollama, LM Studio,
    Jan, vLLM, Ooba, llama.cpp) and routes chat completions to it. NO cloud
    APIs are ever contacted.

    Public API:
      • query(prompt)            → (ok, response)  — single-turn
      • chat(prompt, system=, max_tokens=) → (ok, response) — for LLMBrain
      • list_models()            → formatted string of available local models
      • list_ollama_models()     → same, Ollama-specific (kept for compat)
      • set_model(name)          → switch active model
      • set_backend(name)        → switch active backend ("ollama"|"lmstudio"|"jan"|...)
      • discover_backends()      → re-probe all known local servers
      • pull_ollama_model(name)  → ollama pull <name>
      • clear_history()
    """

    # All known local backends. The URL is the base URL; for OpenAI-compat
    # backends we append /v1/chat/completions. For Ollama we use /api/chat.
    _LOCAL_BACKENDS: Dict[str, Dict] = {
        "ollama": {
            "base_url":  "http://localhost:11434",
            "api_style": "ollama",  # uses /api/chat and /api/tags
            "desc":      "Ollama — easiest local LLM runtime (https://ollama.com)",
        },
        "lmstudio": {
            "base_url":  "http://localhost:1234",
            "api_style": "openai",  # OpenAI-compatible /v1/chat/completions
            "desc":      "LM Studio — GUI-based local model runner",
        },
        "jan": {
            "base_url":  "http://localhost:1337",
            "api_style": "openai",
            "desc":      "Jan — open-source ChatGPT alternative",
        },
        "vllm": {
            "base_url":  "http://localhost:8000",
            "api_style": "openai",
            "desc":      "vLLM — high-throughput inference server",
        },
        "ooba": {
            "base_url":  "http://localhost:5000",
            "api_style": "openai",
            "desc":      "text-generation-webui (OpenAI extension)",
        },
        "llamacpp": {
            "base_url":  "http://localhost:8080",
            "api_style": "openai",
            "desc":      "llama.cpp server (OpenAI-compatible build)",
        },
        "gpt4all": {
            "base_url":  "http://localhost:4891",
            "api_style": "openai",  # GPT4All v3+ exposes an OpenAI-compatible API
            "desc":      "GPT4All — desktop local LLM runtime (https://gpt4all.io)",
        },
        "koboldcpp": {
            "base_url":  "http://localhost:5001",
            "api_style": "openai",  # KoboldCpp has an OpenAI-compatible endpoint
            "desc":      "KoboldCpp — lightweight local LLM runtime",
        },
        "llamafile": {
            "base_url":  "http://localhost:8080",
            "api_style": "openai",  # llamafile serves an OpenAI-compatible API
            "desc":      "llamafile — single-file LLM distribution",
        },
    }

    def __init__(self):
        self._model: Optional[str] = None          # auto-pick first available
        self._backend: Optional[str] = None        # auto-pick first reachable
        self._history: List[Dict] = []
        self._max_history = 20
        self._system_prompt = (
            "You are ARJUN, an advanced AI assistant running entirely locally "
            "on the user's laptop. Be helpful, concise, and accurate. "
            "If asked to perform system actions, describe what you would do clearly."
        )
        # Allow env-var override for backend URLs
        for name, cfg in self._LOCAL_BACKENDS.items():
            env_var = f"{name.upper()}_URL"
            if os.environ.get(env_var):
                cfg["base_url"] = os.environ[env_var].rstrip("/")
        # Allow forcing a backend via env var
        forced = os.environ.get("ARJUN_AI_BACKEND", "").strip().lower()
        if forced and forced in self._LOCAL_BACKENDS:
            self._backend = forced
        # Cached list of discovered models per backend
        self._discovered_models: Dict[str, List[str]] = {}
        # Discover on init (best-effort, non-blocking on failure)
        try:
            self.discover_backends()
        except Exception as exc:
            logger.warning(f"[AIGateway] discovery failed: {exc}")

    # ── public configuration methods ─────────────────────────────────────

    def set_model(self, name: str) -> Tuple[bool, str]:
        name = name.strip()
        if not name:
            return False, "Empty model name"
        # Verify the model exists on the active backend (if we have one)
        if self._backend:
            available = self._discovered_models.get(self._backend, [])
            # Case-insensitive substring match
            match = next((m for m in available if name.lower() in m.lower()), None)
            if match:
                self._model = match
                return True, f"AI model set to: {match} (backend: {self._backend})"
            # Model not in the discovered list — but the user might know
            # better (e.g. they pulled it after discovery). Allow it.
            self._model = name
            return True, f"AI model set to: {name} (not in discovered list — will try)"
        self._model = name
        return True, f"AI model set to: {name} (no backend active yet)"

    def set_backend(self, name: str) -> Tuple[bool, str]:
        name = name.strip().lower()
        if name not in self._LOCAL_BACKENDS:
            available = ", ".join(self._LOCAL_BACKENDS.keys())
            return False, f"Unknown backend '{name}'. Available: {available}"
        # Verify it's actually reachable
        if not self._probe_backend(name):
            return False, f"{name} not reachable at {self._LOCAL_BACKENDS[name]['base_url']}"
        self._backend = name
        # Refresh model list for this backend
        self._refresh_model_list(name)
        # If current model isn't on this backend, pick the first available
        if self._discovered_models.get(name):
            if not self._model or self._model not in self._discovered_models[name]:
                self._model = self._discovered_models[name][0]
        return True, f"Active backend: {name} ({self._LOCAL_BACKENDS[name]['base_url']})"

    def list_models(self) -> str:
        lines = ["\n🤖  Local AI Models (no cloud):\n"]
        if not self._backend:
            lines.append("  ⚠ No local backend detected.")
            lines.append("  Install one of:")
            for name, cfg in self._LOCAL_BACKENDS.items():
                lines.append(f"    • {name:<10} — {cfg['desc']}")
            lines.append("\n  Then start it and run 'discover ai backends'.")
            return "\n".join(lines)
        lines.append(f"  Active backend: {self._backend}")
        lines.append(f"  URL: {self._LOCAL_BACKENDS[self._backend]['base_url']}\n")
        models = self._discovered_models.get(self._backend, [])
        if not models:
            lines.append("  (no models loaded on this backend)")
        else:
            for m in models:
                marker = " ◀ active" if m == self._model else ""
                lines.append(f"    • {m}{marker}")
        lines.append("\n  Other detected backends:")
        any_other = False
        for name, cfg in self._LOCAL_BACKENDS.items():
            if name == self._backend:
                continue
            if self._probe_backend(name):
                any_other = True
                lines.append(f"    • {name} — {cfg['base_url']}")
        if not any_other:
            lines.append("    (none)")
        return "\n".join(lines)

    def list_ollama_models(self) -> Tuple[bool, str]:
        """Backward-compat wrapper. Forces a fresh probe of the Ollama backend."""
        if not self._probe_backend("ollama"):
            return False, (
                "Cannot reach Ollama at "
                f"{self._LOCAL_BACKENDS['ollama']['base_url']}. "
                "Start it with: ollama serve"
            )
        self._refresh_model_list("ollama")
        models = self._discovered_models.get("ollama", [])
        if not models:
            return False, "No models pulled yet. Run: ollama pull llama3.2"
        return True, "Local Ollama models:\n" + "\n".join(f"  • {m}" for m in models)

    def pull_ollama_model(self, model: str) -> Tuple[bool, str]:
        try:
            subprocess.Popen(
                ["ollama", "pull", model],
                creationflags=_NO_WIN_FLAG
            )
            return True, f"Pulling model '{model}'... (runs in background)"
        except FileNotFoundError:
            return False, "Ollama not installed. Visit: https://ollama.com"
        except Exception as e:
            return False, str(e)

    def clear_history(self):
        self._history.clear()
        return True, "Conversation history cleared"

    def discover_backends(self) -> Dict[str, bool]:
        """
        Probe every known local backend URL. Returns {name: reachable}.
        Auto-selects the first reachable backend if none is active.
        """
        results: Dict[str, bool] = {}
        for name in self._LOCAL_BACKENDS:
            results[name] = self._probe_backend(name)
        # Auto-pick a backend if none is active
        if not self._backend or not results.get(self._backend, False):
            for name, ok in results.items():
                if ok:
                    self._backend = name
                    self._refresh_model_list(name)
                    if not self._model and self._discovered_models.get(name):
                        self._model = self._discovered_models[name][0]
                    logger.info(f"[AIGateway] auto-selected backend: {name}")
                    break
        logger.info(f"[AIGateway] discovery results: {results}")
        return results

    # ── internal helpers ─────────────────────────────────────────────────

    def _probe_backend(self, name: str) -> bool:
        """Quick health-check probe (2-second timeout)."""
        cfg = self._LOCAL_BACKENDS.get(name)
        if not cfg:
            return False
        base = cfg["base_url"]
        style = cfg["api_style"]
        try:
            if style == "ollama":
                url = f"{base}/api/tags"
            else:  # openai-compat
                url = f"{base}/v1/models"
            req = Request(url, headers={"Content-Type": "application/json"})
            with urlopen(req, timeout=2) as resp:
                if resp.status == 200:
                    return True
            return False
        except Exception:
            return False

    def _refresh_model_list(self, name: str) -> None:
        """Fetch the list of models available on the given backend."""
        cfg = self._LOCAL_BACKENDS.get(name)
        if not cfg:
            return
        base = cfg["base_url"]
        style = cfg["api_style"]
        models: List[str] = []
        try:
            if style == "ollama":
                url = f"{base}/api/tags"
                req = Request(url)
                with urlopen(req, timeout=5) as resp:
                    data = json.loads(resp.read())
                models = [m.get("name", "") for m in data.get("models", []) if m.get("name")]
            else:  # openai-compat
                url = f"{base}/v1/models"
                req = Request(url, headers={"Content-Type": "application/json"})
                with urlopen(req, timeout=5) as resp:
                    data = json.loads(resp.read())
                # OpenAI-compat returns {"data": [{"id": "model-name"}, ...]}
                models = [m.get("id", "") for m in data.get("data", []) if m.get("id")]
        except Exception as exc:
            logger.warning(f"[AIGateway] model list fetch failed for {name}: {exc}")
        self._discovered_models[name] = models

    def _active_model(self) -> str:
        if self._model:
            return self._model
        # Fall back to a sensible default per backend
        if self._backend == "ollama":
            return "llama3.2"
        return "local-model"

    def _ollama_chat(self, messages: List[Dict], model: str, base_url: str) -> str:
        url = f"{base_url}/api/chat"
        payload = json.dumps({
            "model":    model,
            "messages": messages,
            "stream":   False,
        }).encode()
        req = Request(url, data=payload, headers={"Content-Type": "application/json"})
        try:
            with urlopen(req, timeout=120) as resp:
                data = json.loads(resp.read())
                return data.get("message", {}).get("content", "No response")
        except URLError as e:
            raise ConnectionError(f"Ollama not reachable at {base_url}: {e}") from e

    def _openai_compat_chat(self, messages: List[Dict], model: str,
                             base_url: str, max_tokens: int = 2048) -> str:
        if not REQ_OK:
            # Fall back to urllib if requests is unavailable
            url = f"{base_url}/v1/chat/completions"
            payload = json.dumps({
                "model": model,
                "messages": messages,
                "max_tokens": max_tokens,
                "stream": False,
            }).encode()
            # No Authorization header — local servers typically don't need one
            req = Request(url, data=payload, headers={"Content-Type": "application/json"})
            with urlopen(req, timeout=120) as resp:
                data = json.loads(resp.read())
            return data["choices"][0]["message"]["content"]
        url = f"{base_url}/v1/chat/completions"
        headers = {"Content-Type": "application/json"}
        payload = {
            "model": model,
            "messages": messages,
            "max_tokens": max_tokens,
            "stream": False,
        }
        resp = requests.post(url, headers=headers, json=payload, timeout=120)
        resp.raise_for_status()
        return resp.json()["choices"][0]["message"]["content"]

    # ── main query / chat entry points ───────────────────────────────────

    def query(self, user_input: str, stream_callback: Callable = None) -> Tuple[bool, str]:
        """
        Single-turn query (also appends to internal history).
        Returns (ok, response_text).
        """
        if not user_input.strip():
            return False, "Empty query"
        return self._do_chat(user_input, system=self._system_prompt, max_tokens=2048)

    def chat(self, user_input: str, system: Optional[str] = None,
             max_tokens: int = 2048) -> Tuple[bool, str]:
        """
        Multi-turn chat with optional system prompt override.
        Used by LLMBrain.  Returns (ok, response_text).
        """
        if not user_input.strip():
            return False, "Empty query"
        return self._do_chat(user_input, system=system, max_tokens=max_tokens)

    def _do_chat(self, user_input: str, system: Optional[str],
                 max_tokens: int) -> Tuple[bool, str]:
        # Update history
        self._history.append({"role": "user", "content": user_input})
        max_entries = self._max_history * 2
        if len(self._history) > max_entries:
            self._history = self._history[-max_entries:]
        # Ensure history starts with a user turn
        while self._history and self._history[0]["role"] != "user":
            self._history.pop(0)

        sys_prompt = system or self._system_prompt
        messages = [{"role": "system", "content": sys_prompt}] + self._history

        # ── No backend available → clear error, NEVER cloud fallback ──
        if not self._backend:
            # Try one more discovery in case the user just started a server
            self.discover_backends()
        if not self._backend:
            install_hints = (
                "\n\n⚠ NO LOCAL AI BACKEND DETECTED.\n"
                "ARJUN refuses to use cloud APIs (OpenAI/Anthropic/etc.) per your privacy setting.\n"
                "To enable AI, install ONE of these local runtimes:\n"
                "  • Ollama       → https://ollama.com        then: ollama serve\n"
                "  • LM Studio    → https://lmstudio.ai       (start the local server)\n"
                "  • GPT4All      → https://gpt4all.io         (enable API server in settings)\n"
                "  • Jan          → https://jan.ai            (enable the API server)\n"
                "  • vLLM         → pip install vllm          then: python -m vllm.entrypoints.openai.api_server\n"
                "  • llama.cpp    → https://github.com/ggerganov/llama.cpp  (server mode)\n"
                "  • KoboldCpp    → https://github.com/LostRuins/koboldcpp\n"
                "After starting one, say: 'discover ai backends' or restart ARJUN."
            )
            return False, install_hints

        # ── Verify the cached/active model is still available ──
        # [V13-MODEL-SELECT] If the cached model is no longer on the backend
        # (e.g. user deleted it), inform and DON'T auto-switch.
        if not self.verify_model_available():
            avail = self._discovered_models.get(self._backend, [])
            if avail:
                msg = (
                    f"⚠ The selected AI model '{self._model}' is no longer available "
                    f"on backend '{self._backend}'.\n"
                    f"Available models:\n" + "\n".join(f"  • {m}" for m in avail) +
                     "\nSay 'switch ai model' to choose another."
                )
            else:
                msg = (
                    f"⚠ The selected AI model '{self._model}' is no longer available "
                    f"on backend '{self._backend}', and no other models are loaded.\n"
                    f"Say 'discover ai backends' after starting a local server."
                )
            # Clear the bad cache so we don't keep retrying
            self._model = None
            self._clear_cache()
            return False, msg

        cfg = self._LOCAL_BACKENDS[self._backend]
        model = self._active_model()
        try:
            if cfg["api_style"] == "ollama":
                response = self._ollama_chat(messages, model, cfg["base_url"])
            else:
                response = self._openai_compat_chat(
                    messages, model, cfg["base_url"], max_tokens=max_tokens
                )
            self._history.append({"role": "assistant", "content": response})
            return True, response
        except ConnectionError as e:
            msg = (
                f"❌ Local backend '{self._backend}' not reachable: {e}\n"
                f"   URL: {cfg['base_url']}\n"
                f"   Start it, then say 'discover ai backends'."
            )
            logger.error(msg)
            return False, msg
        except Exception as e:
            logger.error(f"[AIGateway] chat failed [{self._backend}/{model}]: {e}")
            return False, f"AI error ({self._backend}/{model}): {e}"

    # ── V13: model availability verification + persistent cache ──────────

    def verify_model_available(self, model: Optional[str] = None,
                                backend: Optional[str] = None) -> bool:
        """Check that the given (or active) model is currently available on
        the given (or active) backend. Refreshes the model list if stale.
        """
        b = backend or self._backend
        m = model or self._model
        if not b or not m:
            return False
        # Refresh model list for this backend if we haven't recently
        self._refresh_model_list(b)
        available = self._discovered_models.get(b, [])
        if not available:
            return False
        # Exact match
        if m in available:
            return True
        # Case-insensitive match (Ollama tags can vary in case)
        m_lower = m.lower()
        for a in available:
            if a.lower() == m_lower:
                return True
        # Substring match (e.g. "llama3" matches "llama3.2:latest")
        for a in available:
            if m_lower in a.lower() or a.lower() in m_lower:
                return True
        return False

    def current_status(self) -> str:
        """Human-readable status of the active backend + model."""
        if not self._backend:
            return "No local AI backend detected. Say 'discover ai backends'."
        display = self._LOCAL_BACKENDS[self._backend].get("desc", self._backend)
        url = self._LOCAL_BACKENDS[self._backend].get("base_url", "")
        model = self._model or "(none selected)"
        return (
            f"Active backend: {self._backend} — {display}\n"
            f"  URL:   {url}\n"
            f"  Model: {model}"
        )

    # ── V13: persistent model cache (~/.arjun/ai_model_cache.json) ───────
    # Caches the user's chosen backend + model so ARJUN doesn't re-prompt
    # on every startup. The cache is invalidated automatically when the
    # model becomes unavailable (verified at chat time).

    _CACHE_DIR = HOME / ".arjun"
    _CACHE_FILE = _CACHE_DIR / "ai_model_cache.json"

    def _load_cache(self) -> None:
        """Load cached backend+model from disk, if present and still valid."""
        try:
            if self._CACHE_FILE.exists():
                with open(self._CACHE_FILE, "r") as f:
                    data = json.load(f)
                cached_backend = data.get("backend")
                cached_model = data.get("model")
                cached_ts = data.get("timestamp", 0)
                # Cache is valid for 7 days; after that, re-verify
                import time as _time
                if _time.time() - cached_ts > 7 * 86400:
                    logger.info("[AIGateway] cache expired (>7 days), re-verifying")
                    return
                if cached_backend and cached_backend in self._LOCAL_BACKENDS:
                    self._backend = cached_backend
                    self._model = cached_model
                    logger.info(f"[AIGateway] loaded cache: backend={cached_backend} model={cached_model}")
        except Exception as exc:
            logger.warning(f"[AIGateway] cache load failed: {exc}")

    def _save_cache(self) -> None:
        """Persist the current backend+model to disk."""
        try:
            self._CACHE_DIR.mkdir(parents=True, exist_ok=True)
            import time as _time
            data = {
                "backend": self._backend,
                "model": self._model,
                "timestamp": _time.time(),
            }
            with open(self._CACHE_FILE, "w") as f:
                json.dump(data, f, indent=2)
            logger.info(f"[AIGateway] saved cache: backend={self._backend} model={self._model}")
        except Exception as exc:
            logger.warning(f"[AIGateway] cache save failed: {exc}")

    def _clear_cache(self) -> None:
        """Delete the cache file (used when model becomes unavailable)."""
        try:
            if self._CACHE_FILE.exists():
                self._CACHE_FILE.unlink()
                logger.info("[AIGateway] cache cleared")
        except Exception as exc:
            logger.warning(f"[AIGateway] cache clear failed: {exc}")


# ══════════════════════════════════════════════════════════════════════════════
# v13 MODULE — LocalModelSelector
# Interactive numbered-menu model selection. Prompts the user ONCE (on first
# startup), caches the choice, and only re-prompts when the model becomes
# unavailable. Fully local — no cloud APIs contacted at any point.
# ══════════════════════════════════════════════════════════════════════════════
class LocalModelSelector:
    """
    Interactive selector for local AI models.

    Workflow:
      1. discover() — probe every backend in AIGateway._LOCAL_BACKENDS
      2. list_all() — return a flat list of (backend, model) tuples
      3. prompt_user() — display a numbered menu and read the user's choice
      4. apply_choice() — set the backend+model on the AIGateway + cache it
      5. On later startups, load_cache() short-circuits the prompt

    Usage from Arjun.__init__:
        selector = LocalModelSelector(self.ai)
        selector.ensure_model_selected()

    Usage from voice command "switch ai model":
        selector = LocalModelSelector(self.ai)
        selector.prompt_user(interactive=True)
    """

    def __init__(self, gateway: "AIGateway"):
        self._ai = gateway
        # Flat list of (backend, model) tuples, populated by discover()
        self._choices: List[Tuple[str, str]] = []

    def discover(self) -> List[Tuple[str, str]]:
        """Probe all backends and build a flat list of (backend, model) pairs.
        Returns the list (also stored in self._choices).
        """
        self._choices = []
        results = self._ai.discover_backends()
        for backend_name, reachable in results.items():
            if not reachable:
                continue
            # Refresh model list for this backend
            self._ai._refresh_model_list(backend_name)
            models = self._ai._discovered_models.get(backend_name, [])
            for model in models:
                self._choices.append((backend_name, model))
        logger.info(f"[LocalModelSelector] discovered {len(self._choices)} model(s) "
                    f"across {sum(1 for r in results.values() if r)} backend(s)")
        return self._choices

    def format_menu(self) -> str:
        """Return the numbered menu as a printable string."""
        if not self._choices:
            return (
                "\n⚠ No local AI models detected.\n"
                "ARJUN refuses to use cloud APIs.\n"
                "Install/start ONE of:\n"
                "  • Ollama       → https://ollama.com        (ollama serve + ollama pull llama3.2)\n"
                "  • LM Studio    → https://lmstudio.ai       (load a model, start the server)\n"
                "  • GPT4All      → https://gpt4all.io         (enable API server)\n"
                "  • Jan          → https://jan.ai            (enable API server)\n"
                "  • vLLM         → pip install vllm          (python -m vllm.entrypoints.openai.api_server)\n"
                "  • llama.cpp    → https://github.com/ggerganov/llama.cpp  (server mode)\n"
                "  • KoboldCpp / llamafile / text-generation-webui also supported\n"
                "After starting one, say 'discover ai backends' or restart ARJUN.\n"
            )
        lines = ["\n🤖  I found the following local AI models:\n"]
        current_backend = None
        for i, (backend, model) in enumerate(self._choices, 1):
            if backend != current_backend:
                current_backend = backend
                desc = self._ai._LOCAL_BACKENDS[backend].get("desc", backend)
                lines.append(f"\n  [{backend}] — {desc}")
            active_marker = ""
            if (self._ai._backend == backend and self._ai._model == model):
                active_marker = "  ◀ active"
            lines.append(f"    {i:>3}. {model}{active_marker}")
        lines.append("\nPlease choose a model by number or name (or 'skip' to defer):")
        return "\n".join(lines)

    def prompt_user(self, interactive: bool = True,
                     input_fn: Callable = input) -> Tuple[bool, str]:
        """
        Display the menu and read the user's choice.

        Args:
            interactive: if False, just print the menu and return (don't block)
            input_fn:    override input() for testing

        Returns:
            (ok, message)
        """
        # Discover fresh model list
        self.discover()
        if not self._choices:
            msg = self.format_menu()
            print(msg)
            return False, "No local AI models detected."

        print(self.format_menu())
        if not interactive:
            return True, "Menu displayed (non-interactive)"

        # Read user choice
        try:
            choice = input_fn("> ").strip()
        except (EOFError, KeyboardInterrupt):
            return False, "Selection cancelled"

        if choice.lower() in ("skip", "cancel", "quit", "exit", ""):
            return False, "Selection deferred"

        # Parse choice: either a number or a model name
        backend, model = self._parse_choice(choice)
        if not backend:
            print(f"  ❌ Invalid choice: {choice!r}. Please try again.")
            return self.prompt_user(interactive=True, input_fn=input_fn)

        # Apply and cache
        ok, msg = self.apply_choice(backend, model)
        if ok:
            print(f"\n  ✅ Active AI model: {model} (backend: {backend})")
            print("  💾 Cached for future sessions. Say 'switch ai model' to change.")
        return ok, msg

    def _parse_choice(self, choice: str) -> Tuple[Optional[str], Optional[str]]:
        """Parse user input (number or name) into (backend, model)."""
        if not choice:
            return None, None
        # Number?
        if choice.isdigit():
            n = int(choice)
            if 1 <= n <= len(self._choices):
                return self._choices[n - 1]
            return None, None
        # Name? Search for substring match (case-insensitive)
        c_lower = choice.lower()
        # Exact match first
        for backend, model in self._choices:
            if model.lower() == c_lower:
                return backend, model
        # Substring match
        matches = [(b, m) for b, m in self._choices if c_lower in m.lower()]
        if len(matches) == 1:
            return matches[0]
        if len(matches) > 1:
            # Multiple matches — pick the shortest (most specific)
            matches.sort(key=lambda bm: len(bm[1]))
            return matches[0]
        # Try matching backend name
        for backend, model in self._choices:
            if c_lower in backend.lower():
                return backend, model
        return None, None

    def apply_choice(self, backend: str, model: str) -> Tuple[bool, str]:
        """Set the active backend+model on the gateway and persist to cache."""
        if backend not in self._ai._LOCAL_BACKENDS:
            return False, f"Unknown backend: {backend!r}"
        # Verify the model exists on this backend
        self._ai._refresh_model_list(backend)
        available = self._ai._discovered_models.get(backend, [])
        if model not in available:
            # Case-insensitive / substring match
            m_lower = model.lower()
            match = next((m for m in available if m.lower() == m_lower), None)
            if not match:
                match = next((m for m in available if m_lower in m.lower()), None)
            if match:
                model = match
            else:
                return False, f"Model {model!r} not found on backend {backend!r}"
        self._ai._backend = backend
        self._ai._model = model
        self._ai._save_cache()
        logger.info(f"[LocalModelSelector] applied: backend={backend} model={model}")
        return True, f"Active AI model: {model} (backend: {backend})"

    def ensure_model_selected(self, input_fn: Callable = input) -> bool:
        """
        Called on startup. Loads the cache; if no valid cached model, prompts
        the user interactively. Returns True if a model is now active.
        """
        # First try the cache
        self._ai._load_cache()
        if self._ai._backend and self._ai._model:
            # Verify the cached model is still available
            if self._ai.verify_model_available():
                logger.info(f"[LocalModelSelector] using cached model: "
                            f"{self._ai._backend}/{self._ai._model}")
                print(f"🤖  AI: {self._ai._model} ({self._ai._backend}) — cached")
                return True
            else:
                # Cached model no longer available — inform, don't auto-switch
                print(f"⚠ Cached AI model '{self._ai._model}' is no longer available "
                      f"on backend '{self._ai._backend}'.")
                self._ai._model = None
                self._ai._clear_cache()
        # No valid cache — prompt the user
        ok, msg = self.prompt_user(interactive=True, input_fn=input_fn)
        return ok


# ══════════════════════════════════════════════════════════════════════════════
# v16.1 MODULE — MODEL MANAGER (Role-Based Intelligent Model Selection)
# ══════════════════════════════════════════════════════════════════════════════
# [V16.1-MODEL-MGR] Centralized model management with:
#   • Model discovery + metadata enrichment (family, size, quant, capabilities)
#   • Role-based selection (chat, coding, reasoning, vision, embedding)
#   • Intelligent routing (planner/agents request model by role)
#   • Load/unload tracking
#   • User preferences persisted to ~/.arjun/model_roles.json
#   • First-time setup flow
#   • Fallback strategy (never silently switch)
#   • No cloud APIs — local only
#
# All agents MUST request models through the ModelManager, never directly
# from AIGateway. This ensures the correct model is used for each task.
# ══════════════════════════════════════════════════════════════════════════════

class ModelRole(Enum):
    """The 5 model roles. Each maps to a user-configurable default model."""
    CHAT = "chat"
    CODING = "coding"
    REASONING = "reasoning"
    VISION = "vision"
    EMBEDDING = "embedding"


class ModelMetadata:
    """Enriched metadata for a discovered model."""
    __slots__ = ("model_id", "backend", "name", "family", "param_size",
                 "quantization", "context_window", "capabilities",
                 "status", "loaded", "description")

    def __init__(self, model_id: str, backend: str, name: str):
        self.model_id = model_id      # "ollama:llama3.2:latest"
        self.backend = backend         # "ollama"
        self.name = name               # "llama3.2:latest"
        self.family = ""               # "llama"
        self.param_size = ""           # "3B", "7B", "13B", "70B"
        self.quantization = ""         # "q4_0", "fp16", "unknown"
        self.context_window = 0        # 4096, 8192, 32768
        self.capabilities: List[str] = []  # ["chat", "coding", "vision"]
        self.status = "available"      # "available", "loaded", "unloaded", "error"
        self.loaded = False
        self.description = ""

    def to_dict(self) -> Dict[str, Any]:
        return {k: getattr(self, k) for k in self.__slots__}


class ModelManager:
    """
    Centralized model manager. All agents request models through this class.

    Responsibilities:
      • Detect all installed local models across all backends
      • Enrich metadata (family, size, quant, capabilities) from model names
      • Manage role-based defaults (chat, coding, reasoning, vision, embedding)
      · Auto-select best model per role based on capabilities
      • Load/unload models (where supported)
      • Persist user preferences to ~/.arjun/model_roles.json
      • Provide models to agents via get_model_for_role()
      • Fallback strategy: never silently switch

    Usage:
        mgr = ModelManager(ai_gateway)
        mgr.discover()                    # scan all backends
        mgr.ensure_roles_configured()     # first-time setup
        model = mgr.get_model_for_role(ModelRole.CODING)
        # → returns ("ollama", "deepseek-coder:latest")
    """

    _ROLES_FILE = HOME / ".arjun" / "model_roles.json"

    # Known model families (lowercase prefix → family name)
    _FAMILY_PATTERNS = {
        "llama": "Llama", "llama2": "Llama", "llama3": "Llama",
        "mistral": "Mistral", "mixtral": "Mixtral",
        "qwen": "Qwen", "qwen2": "Qwen",
        "gemma": "Gemma", "gemma2": "Gemma",
        "phi": "Phi", "phi3": "Phi",
        "deepseek": "DeepSeek",
        "codellama": "CodeLlama", "code": "CodeLlama",
        "starcoder": "StarCoder", "starchat": "StarCoder",
        "llava": "LLaVA", "bakllava": "LLaVA",
        "orca": "Orca", "solar": "Solar",
        "dolphin": "Dolphin", "neural": "Neural",
        "nomic": "Nomic", "mxbai": "MXBAI",
        "bge": "BGE", "all-minilm": "MiniLM",
        "devstral": "Devstral", "command-r": "Command-R",
    }

    # Capability inference from model name keywords
    _CAPABILITY_KEYWORDS = {
        "coding": ["coder", "code", "codellama", "deepseek-coder", "starcoder",
                   "devstral", "codeqwen", "codestral"],
        "vision": ["llava", "bakllava", "vision", "vl", "multimodal",
                   "moondream", "llama3.2-vision"],
        "embedding": ["embed", "bge", "nomic-embed", "mxbai-embed", "minilm"],
        "reasoning": ["deepseek-r1", "qwq", "reasoning", "o1", "reflection",
                      "marco-o1"],
    }

    # Coding model ranking (higher = better for coding)
    _CODING_RANK = {
        "deepseek-coder": 100, "deepseek-coder-v2": 100,
        "codestral": 95, "codeqwen": 90, "qwen2.5-coder": 90,
        "codellama": 80, "starcoder2": 75, "starcoder": 70,
        "devstral": 85, "codegemma": 75,
    }

    # Reasoning model ranking
    _REASONING_RANK = {
        "deepseek-r1": 100, "qwq": 95, "reflection-llama": 85,
        "marco-o1": 80, "qwen2.5": 70, "llama3.1": 65, "mistral": 60,
    }

    def __init__(self, ai_gateway: "AIGateway"):
        self._ai = ai_gateway
        self._models: Dict[str, ModelMetadata] = {}  # model_id → metadata
        self._role_models: Dict[str, str] = {}  # role → model_id
        self._lock = threading.Lock()
        self._load_preferences()

    # ── Discovery ──────────────────────────────────────────────────

    def discover(self) -> List[ModelMetadata]:
        """Scan all backends and build enriched model list."""
        with self._lock:  # [V16.2-FIX-M1] thread-safe discovery
            self._models.clear()
            results = self._ai.discover_backends()
            for backend_name, reachable in results.items():
                if not reachable:
                    continue
                self._ai._refresh_model_list(backend_name)
                for model_name in self._ai._discovered_models.get(backend_name, []):
                    model_id = f"{backend_name}:{model_name}"
                    meta = ModelMetadata(model_id, backend_name, model_name)
                    self._enrich_metadata(meta)
                    self._models[model_id] = meta
            logger.info(f"[ModelManager] discovered {len(self._models)} model(s) "
                        f"across {sum(1 for r in results.values() if r)} backend(s)")
            return list(self._models.values())

    def _enrich_metadata(self, meta: ModelMetadata) -> None:
        """Infer family, param size, quantization, capabilities from model name."""
        name_lower = meta.name.lower()

        # Detect family
        for pattern, family in self._FAMILY_PATTERNS.items():
            if pattern in name_lower:
                meta.family = family
                break
        if not meta.family:
            meta.family = "Unknown"

        # Detect parameter size (e.g. "7b", "13b", "70b", "3b", "0.5b")
        # [REFACTOR] removed redundant 'import re as _re' — re already imported at module level
        size_match = re.search(r'(\d+(?:\.\d+)?)\s*[bx]', name_lower)
        if size_match:
            size = float(size_match.group(1))
            meta.param_size = f"{size:g}B"
        elif "mini" in name_lower or "nano" in name_lower:
            meta.param_size = "1-3B"
        elif "small" in name_lower:
            meta.param_size = "7B"
        elif "medium" in name_lower:
            meta.param_size = "14B"
        elif "large" in name_lower:
            meta.param_size = "70B+"

        # Detect quantization
        for quant in ["q4_0", "q4_1", "q4_k_m", "q4_k_s", "q5_0", "q5_1",
                       "q5_k_m", "q8_0", "fp16", "f16", "q2_k", "q3_k_m",
                       "q3_k_s", "q6_k"]:
            if quant in name_lower:
                meta.quantization = quant
                break
        if not meta.quantization:
            meta.quantization = "default"

        # Detect context window (from name or family defaults)
        ctx_defaults = {"llama3": 8192, "llama3.1": 131072, "mistral": 32768,
                        "mixtral": 32768, "qwen2": 32768, "qwen2.5": 32768,
                        "gemma2": 8192, "phi3": 128000, "deepseek": 4096,
                        "codellama": 16384, "llava": 4096}
        for pattern, ctx in ctx_defaults.items():
            if pattern in name_lower:
                meta.context_window = ctx
                break
        if not meta.context_window:
            meta.context_window = 4096  # safe default

        # Detect capabilities
        meta.capabilities = ["chat"]  # all models can chat
        for cap, keywords in self._CAPABILITY_KEYWORDS.items():
            if any(kw in name_lower for kw in keywords):
                if cap not in meta.capabilities:
                    meta.capabilities.append(cap)

        # Build description
        parts = [meta.family]
        if meta.param_size:
            parts.append(meta.param_size)
        parts.append(f"{meta.context_window // 1024}K ctx" if meta.context_window >= 1024 else f"{meta.context_window} ctx")
        if meta.quantization != "default":
            parts.append(meta.quantization)
        meta.description = " · ".join(parts)

    # ── Role-based selection ───────────────────────────────────────

    def get_model_for_role(self, role: ModelRole) -> Optional[Tuple[str, str]]:
        """Return (backend, model_name) for the given role.
        Uses user preference if set, otherwise auto-selects best.
        """
        role_str = role.value
        with self._lock:
            # Check user preference
            if role_str in self._role_models:
                model_id = self._role_models[role_str]
                if model_id in self._models:
                    meta = self._models[model_id]
                    return (meta.backend, meta.name)
                # Preferred model not available — return None, don't auto-switch
                logger.warning(f"[ModelManager] preferred model for {role_str} "
                              f"({model_id}) not available")
                return None

        # Auto-select best model for role
        return self._auto_select_for_role(role)

    def _auto_select_for_role(self, role: ModelRole) -> Optional[Tuple[str, str]]:
        """Automatically select the best model for a role based on capabilities."""
        if not self._models:
            return None
        role_str = role.value
        candidates = []

        for model_id, meta in self._models.items():
            if role_str in meta.capabilities:
                rank = self._rank_model(meta, role)
                candidates.append((rank, meta))

        if not candidates:
            # No specialized model — fall back to any chat-capable model
            candidates = [(0, m) for m in self._models.values()
                          if "chat" in m.capabilities]

        if not candidates:
            return None

        # Sort by rank descending
        candidates.sort(key=lambda x: x[0], reverse=True)
        best = candidates[0][1]
        return (best.backend, best.name)

    def _rank_model(self, meta: ModelMetadata, role: ModelRole) -> int:
        """Rank a model for a given role (higher = better)."""
        name_lower = meta.name.lower()
        if role == ModelRole.CODING:
            for pattern, rank in self._CODING_RANK.items():
                if pattern in name_lower:
                    return rank
            return 10  # generic chat model, low priority for coding
        elif role == ModelRole.REASONING:
            for pattern, rank in self._REASONING_RANK.items():
                if pattern in name_lower:
                    return rank
            return 20
        elif role == ModelRole.VISION:
            if "vision" in meta.capabilities:
                return 100
            return 0
        elif role == ModelRole.EMBEDDING:
            if "embedding" in meta.capabilities:
                return 100
            return 0
        else:  # CHAT
            # Prefer larger models for general chat
            if meta.param_size:
                try:
                    size = float(meta.param_size.replace("B", "").replace("+", ""))
                    return int(size * 10)
                except ValueError:
                    pass
            return 50

    def set_role_model(self, role: ModelRole, model_id: str) -> Tuple[bool, str]:
        """Set the user's preferred model for a role. Persists immediately."""
        if model_id not in self._models:
            return False, f"Model '{model_id}' not found. Available: {list(self._models.keys())[:5]}"
        with self._lock:
            self._role_models[role.value] = model_id
        self._save_preferences()
        meta = self._models[model_id]
        logger.info(f"[ModelManager] set {role.value} → {model_id}")
        return True, f"Default {role.value} model set to {meta.name} ({meta.backend})"

    def get_role_model(self, role: ModelRole) -> Optional[str]:
        """Get the model_id currently assigned to a role."""
        return self._role_models.get(role.value)

    def get_all_roles(self) -> Dict[str, Optional[str]]:
        """Return {role: model_id} for all 5 roles."""
        return {role.value: self._role_models.get(role.value) for role in ModelRole}

    # ── Model load/unload ──────────────────────────────────────────

    def load_model(self, model_id: str) -> Tuple[bool, str]:
        """Load a model into memory (Ollama only; others auto-load on first use)."""
        with self._lock:  # [V16.2-FIX-M3] thread-safe
            if model_id not in self._models:
                return False, f"Model '{model_id}' not found"
            meta = self._models[model_id]
            if meta.loaded:
                return True, f"{meta.name} is already loaded"
            meta.loaded = True
            meta.status = "loaded"
        logger.info(f"[ModelManager] loaded {model_id}")
        return True, f"Model {meta.name} loaded"

    def unload_model(self, model_id: str) -> Tuple[bool, str]:
        """Unload a model from memory."""
        with self._lock:  # [V16.2-FIX-M3] thread-safe
            if model_id not in self._models:
                return False, f"Model '{model_id}' not found"
            meta = self._models[model_id]
            meta.loaded = False
            meta.status = "available"
        logger.info(f"[ModelManager] unloaded {model_id}")
        return True, f"Model {meta.name} unloaded"

    # ── Querying ───────────────────────────────────────────────────

    def list_models(self) -> List[Dict[str, Any]]:
        """Return all discovered models with metadata."""
        return [m.to_dict() for m in self._models.values()]

    def get_model(self, model_id: str) -> Optional[ModelMetadata]:
        return self._models.get(model_id)

    def search_models(self, query: str) -> List[ModelMetadata]:
        """Search models by name, family, or capability."""
        q = query.lower()
        return [m for m in self._models.values()
                if q in m.name.lower() or q in m.family.lower()
                or any(q in c for c in m.capabilities)]

    # ── First-time setup ───────────────────────────────────────────

    def ensure_roles_configured(self, input_fn: Callable = input) -> bool:
        """First-time setup: detect models, display them, auto-assign roles,
        then ASK the user if they want to change any assignments.
        If user has already configured (cached), just show and skip.
        """
        # Already configured — verify models still exist, show and return
        if self._role_models:
            all_valid = True
            for role, model_id in self._role_models.items():
                if model_id not in self._models:
                    logger.warning(f"[ModelManager] {role} model '{model_id}' no longer available")
                    all_valid = False
            if all_valid:
                print("\n🤖  Model roles (from saved preferences):")
                for role, mid in self._role_models.items():
                    meta = self._models.get(mid)
                    print(f"    {role:12s} → {meta.name if meta else mid}")
                return True
            else:
                print("\n⚠ Some saved model preferences are no longer available. Reconfiguring...")

        if not self._models:
            print("\n⚠ No local AI models detected.")
            print("  To enable AI features, start a local inference server:")
            print("    • Ollama:    ollama serve  (then: ollama pull llama3.2)")
            print("    • LM Studio:  start the local server in the app")
            print("    • GPT4All:    enable API server in settings")
            print("  After starting one, say 'discover ai backends' or restart ARJUN.")
            return False

        # ── Display ALL detected models ──────────────────────────────
        print(f"\n{'='*60}")
        print(f"  🤖  DETECTED LOCAL AI MODELS ({len(self._models)} models)")
        print(f"{'='*60}")
        current_backend = None
        for i, (model_id, meta) in enumerate(self._models.items(), 1):
            if meta.backend != current_backend:
                current_backend = meta.backend
                print(f"\n  [{current_backend}]")
            caps_str = ", ".join(meta.capabilities)
            print(f"    {i:>3}. {meta.name:<35} {meta.family:<10} {meta.param_size:<8} [{caps_str}]")
        print(f"{'='*60}")

        # ── Auto-assign best model per role ──────────────────────────
        print("\n  📋 Auto-assigned model roles:")
        for role in ModelRole:
            best = self._auto_select_for_role(role)
            if best:
                backend, name = best
                model_id = f"{backend}:{name}"
                self._role_models[role.value] = model_id
                print(f"    {role.value:12s} → {name} ({backend})")
            else:
                print(f"    {role.value:12s} → (no suitable model found)")

        # ── Ask user if they want to change anything ─────────────────
        print("\n  Would you like to change any role assignments? (yes/no)")
        try:
            response = input_fn("> ").strip().lower()
        except (EOFError, KeyboardInterrupt):
            response = "no"

        if response in ("yes", "y", "ok", "change", "customize"):
            # Let user customize each role
            model_list = list(self._models.keys())
            for role in ModelRole:
                current = self._role_models.get(role.value)
                current_meta = self._models.get(current) if current else None
                current_name = current_meta.name if current_meta else "auto"
                print(f"\n  {role.value.upper()} role (current: {current_name})")
                print("  Available models:")
                for i, mid in enumerate(model_list, 1):
                    m = self._models[mid]
                    marker = " ◀" if mid == current else ""
                    print(f"    {i:>3}. {m.name} ({m.backend}){marker}")
                print("    0.  (keep auto-assignment)")
                try:
                    choice = input_fn(f"  Select model number for {role.value}: ").strip()
                except (EOFError, KeyboardInterrupt):
                    choice = "0"
                if choice.isdigit() and int(choice) > 0 and int(choice) <= len(model_list):
                    selected_id = model_list[int(choice) - 1]
                    self._role_models[role.value] = selected_id
                    meta = self._models[selected_id]
                    print(f"    ✅ {role.value} → {meta.name}")

        # ── Save and show final configuration ────────────────────────
        self._save_preferences()
        print(f"\n{'='*60}")
        print("  ✅  MODEL ROLE CONFIGURATION SAVED")
        print(f"{'='*60}")
        for role, model_id in self._role_models.items():
            meta = self._models.get(model_id)
            if meta:
                print(f"    {role:12s} → {meta.name} ({meta.backend})")
        print(f"{'='*60}")
        print("\n  💾 Preferences saved to ~/.arjun/model_roles.json")
        print("  💡 Say 'switch coding model' or 'use deepseek-coder' to change later.")
        return True

    # ── Persistence ────────────────────────────────────────────────

    def _load_preferences(self) -> None:
        """Load role preferences from disk."""
        try:
            if self._ROLES_FILE.exists():
                with open(self._ROLES_FILE) as f:
                    self._role_models = json.load(f)
                logger.info(f"[ModelManager] loaded preferences: {self._role_models}")
        except Exception as exc:
            logger.warning(f"[ModelManager] pref load failed: {exc}")

    def _save_preferences(self) -> None:
        """Save role preferences to disk."""
        try:
            self._ROLES_FILE.parent.mkdir(parents=True, exist_ok=True)
            with open(self._ROLES_FILE, "w") as f:
                json.dump(self._role_models, f, indent=2)
            logger.info(f"[ModelManager] saved preferences: {self._role_models}")
        except Exception as exc:
            logger.warning(f"[ModelManager] pref save failed: {exc}")

    # ── Dashboard data ─────────────────────────────────────────────

    def dashboard_data(self) -> Dict[str, Any]:
        """Return all data needed by the AI Models dashboard page."""
        return {
            "models": self.list_models(),
            "roles": self.get_all_roles(),
            "total_models": len(self._models),
            "total_backends": len(set(m.backend for m in self._models.values())),
            "active_model": getattr(self._ai, "_model", None),
            "active_backend": getattr(self._ai, "_backend", None),
        }


# ══════════════════════════════════════════════════════════════════════════════
# 10. MODULE D — Calculator (Safe AST)
# ══════════════════════════════════════════════════════════════════════════════
class SafeCalculator:
    """
    Pure AST evaluator — no eval/exec.
    [C-3] FIX: Exponent capped at MAX_EXPONENT to prevent DoS (preserved).
    [m-3] FIX: Caret ^ is normalised to ** before SAFE_RE strips non-numeric chars.
    """
    MAX_EXPONENT = 1000
    MAX_VALUE    = 1e300

    # [BUG-8/9] FIX: Prepositional patterns resolved BEFORE generic WORD_OPS to prevent
    # digit concatenation. "subtract 5 from 10" → "10 - 5"; "add 3 to 7" → "3 + 7"
    PREP_OPS = [
        (re.compile(r'\badd\s+(\d+(?:\.\d+)?)\s+to\s+(\d+(?:\.\d+)?)', re.I),
         lambda m: f"{m.group(1)} + {m.group(2)}"),
        (re.compile(r'\bsubtract\s+(\d+(?:\.\d+)?)\s+from\s+(\d+(?:\.\d+)?)', re.I),
         lambda m: f"{m.group(2)} - {m.group(1)}"),
        (re.compile(r'\bmultiply\s+(\d+(?:\.\d+)?)\s+by\s+(\d+(?:\.\d+)?)', re.I),
         lambda m: f"{m.group(1)} * {m.group(2)}"),
        (re.compile(r'\bdivide\s+(\d+(?:\.\d+)?)\s+by\s+(\d+(?:\.\d+)?)', re.I),
         lambda m: f"{m.group(1)} / {m.group(2)}"),
    ]
    WORD_OPS = [
        (r'\bplus\b', '+'),          (r'\bminus\b', '-'),
        (r'\btimes\b', '*'),         (r'\binto\b', '*'),
        (r'\bmultiplied\s+by\b', '*'), (r'\bdivided\s+by\b', '/'),
        (r'\bdivide\b', '/'),        (r'\bover\b', '/'),
        (r'\bmod(?:ulo)?\b', '%'),   (r'\bpercent\s+of\b', '/100*'),
        (r'\bsquared\b', '**2'),     (r'\bcubed\b', '**3'),
        (r'\bto\s+the\s+power\s+of\b', '**'),
        (r'\braised\s+to\b', '**'),  (r'\bsubtract\b', '-'),
        (r'\badd\b', '+'),           (r'\bx\b', '*'),
    ]
    SQRT_RE = re.compile(r'square\s+root\s+of\s+(\d+(?:\.\d+)?)', re.I)
    CUBE_RE = re.compile(r'cube\s+root\s+of\s+(\d+(?:\.\d+)?)', re.I)
    # FIX: Pattern now captures optional leading minus so 'log of -5' is caught
    # by the validation branch (v <= 0) rather than falling through to the
    # generic evaluator which would just return -5 as if it were valid.
    LOG_RE  = re.compile(r'log(?:arithm)?\s+of\s+(-?\d+(?:\.\d+)?)', re.I)
    # [m-3] FIX: SAFE_RE now excludes ^ so caret-style exponents survive until normalisation
    SAFE_RE = re.compile(r'[^0-9+\-*/().%^\s]')
    FILLER  = re.compile(
        r'\b(what\s+is|what\'?s|calculate|compute|equals?|'
        r'evaluate|solve|find|the\s+answer\s+to|tell\s+me)\b', re.I
    )
    _OPS: Dict = {
        ast.Add: operator.add,   ast.Sub: operator.sub,
        ast.Mult: operator.mul,  ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Pow: operator.pow,   ast.Mod: operator.mod,
        ast.USub: operator.neg,  ast.UAdd: operator.pos,
    }

    def _ast_eval(self, node) -> float:
        if isinstance(node, ast.Constant) and isinstance(node.value, (int, float)):
            return float(node.value)
        # Python 3.14+ removes ast.Num; use hasattr guard
        if hasattr(ast, 'Num') and isinstance(node, ast.Num):  # Python < 3.8 compat
            return float(node.n)
        if isinstance(node, ast.BinOp):
            op_t  = type(node.op)
            if op_t not in self._OPS:
                raise ValueError(f"Unsupported operator: {op_t.__name__}")
            left  = self._ast_eval(node.left)
            right = self._ast_eval(node.right)
            # [C-3] Cap exponent to prevent DoS
            if op_t == ast.Pow:
                if abs(right) > self.MAX_EXPONENT:
                    raise ValueError(f"Exponent {right} exceeds max ({self.MAX_EXPONENT})")
            result = self._OPS[op_t](left, right)
            if abs(result) > self.MAX_VALUE:
                raise OverflowError("Result too large")
            return result
        if isinstance(node, ast.UnaryOp):
            op_t = type(node.op)
            if op_t not in self._OPS:
                raise ValueError(f"Unsupported unary: {op_t.__name__}")
            return self._OPS[op_t](self._ast_eval(node.operand))
        raise ValueError(f"Unsupported AST node: {type(node).__name__}")

    def evaluate(self, expr: str) -> Tuple[bool, str]:
        expr = expr.lower().strip()
        # Special forms
        m = self.SQRT_RE.search(expr)
        if m:
            return True, f"√{m.group(1)} = {math.sqrt(float(m.group(1))):.6g}"
        m = self.CUBE_RE.search(expr)
        if m:
            return True, f"∛{m.group(1)} = {float(m.group(1))**(1/3):.6g}"
        m = self.LOG_RE.search(expr)
        if m:
            v = float(m.group(1))
            if v <= 0:
                return False, "Logarithm undefined for non-positive numbers"
            return True, f"log({m.group(1)}) = {math.log10(v):.6g}  (ln = {math.log(v):.6g})"
        # [BUG-8/9] FIX: Prepositional phrases first to avoid digit concatenation
        for pat, repl in self.PREP_OPS:
            expr = pat.sub(repl, expr)
        # Word replacements
        expr = self.SQRT_RE.sub(lambda x: f"({x.group(1)}**0.5)", expr)
        expr = self.CUBE_RE.sub(lambda x: f"({x.group(1)}**(1/3))", expr)
        for pat, repl in self.WORD_OPS:
            expr = re.sub(pat, repl, expr, flags=re.I)
        expr = self.FILLER.sub("", expr).strip()
        # [m-3] FIX: Normalise caret ^ to ** BEFORE SAFE_RE strips it
        expr = expr.replace("^", "**")
        expr = self.SAFE_RE.sub("", expr).strip()
        expr = re.sub(r'\s+', '', expr)
        if not expr:
            return False, "Empty expression"
        try:
            tree   = ast.parse(expr, mode="eval")
            result = self._ast_eval(tree.body)
            if isinstance(result, float):
                if result.is_integer() and abs(result) < 1e15:
                    result = int(result)
                else:
                    result = round(result, 8)
            return True, f"Result: {result}"
        except ZeroDivisionError:
            return False, "Cannot divide by zero"
        except OverflowError as e:
            return False, str(e)
        except (ValueError, SyntaxError, TypeError) as e:
            logger.debug(f"Calculator: '{expr}' → {e}")
            return False, f"Cannot evaluate: {e}"
        except Exception as e:
            logger.error(f"Calculator unexpected error: {e}")
            return False, f"Error: {e}"

# ══════════════════════════════════════════════════════════════════════════════
# 11. MODULE E — Application Controller
# ══════════════════════════════════════════════════════════════════════════════
class AppController:
    """
    [C-6] FIX: UWP apps are no longer blindly marked installed=True.
               Only mark UWP installed=True if on Windows; launch failure
               surfaces a clear message rather than a silent false positive.
    [M-5] FIX: File Explorer (explorer.exe) is now in the process list and
               can be properly targeted by close(); the old unconditional
               skip of explorer.exe is removed — it only skips if the user
               didn't explicitly ask to close it (which they can via
               "close file explorer").
    """

    def __init__(self):
        self._cache         : Dict = {}
        self._dynamic_apps  : Dict = {}
        self._scan_static()
        if IS_WINDOWS:
            self._scan_registry()
            self._scan_startapps()

    def _scan_static(self):
        for key, entry in APP_DATABASE.items():
            record = {**entry, "installed": False, "resolved_path": None}
            for raw in entry.get("paths", []):
                if "*" in raw:
                    matches = glob.glob(raw)
                    if matches:
                        record["installed"]     = True
                        record["resolved_path"] = matches[0]
                        break
                elif os.path.exists(raw):
                    record["installed"]     = True
                    record["resolved_path"] = raw
                    break
            if not record["installed"] and entry.get("cmd"):
                if shutil.which(entry["cmd"]):
                    record["installed"] = True

            # [C-6] FIX v7: Do NOT assume UWP apps are installed.
            # Previously this marked all UWP entries as installed on Windows,
            # causing File Explorer to open when app missing (e.g., WhatsApp).
            if not record["installed"] and entry.get("uwp"):
                record["installed"] = False  # will be verified on launch
            self._cache[key] = record

    def _scan_registry(self):
        if not WINREG_OK:
            return
        reg_paths = [
            (winreg.HKEY_LOCAL_MACHINE,
             r"SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall"),
            (winreg.HKEY_LOCAL_MACHINE,
             r"SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\Uninstall"),
            (winreg.HKEY_CURRENT_USER,
             r"SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall"),
        ]
        for hive, path in reg_paths:
            try:
                with winreg.OpenKey(hive, path) as key:
                    for i in range(winreg.QueryInfoKey(key)[0]):
                        try:
                            sub = winreg.EnumKey(key, i)
                            with winreg.OpenKey(key, sub) as sk:
                                try:
                                    dn = winreg.QueryValueEx(sk, "DisplayName")[0]
                                except (FileNotFoundError, OSError):
                                    continue
                                try:
                                    il = winreg.QueryValueEx(sk, "InstallLocation")[0]
                                except (FileNotFoundError, OSError):
                                    il = ""
                                try:
                                    di = winreg.QueryValueEx(sk, "DisplayIcon")[0]
                                except (FileNotFoundError, OSError):
                                    di = ""
                                exe = None
                                if di and di.lower().endswith(".exe"):
                                    exe = di.split(",")[0].strip('"')
                                elif il and os.path.isdir(il):
                                    exes = glob.glob(os.path.join(il, "*.exe"))
                                    if exes:
                                        exe = exes[0]
                                norm = dn.lower().strip()
                                if norm not in self._cache and norm not in self._dynamic_apps:
                                    self._dynamic_apps[norm] = {
                                        "display": dn, "paths": [exe] if exe else [],
                                        "process": [os.path.basename(exe)] if exe else [],
                                        "aliases": [], "source": "registry",
                                        "installed": bool(exe and os.path.exists(exe)),
                                        "resolved_path": exe if (exe and os.path.exists(exe)) else None,
                                    }
                        except OSError:
                            continue
            except OSError:
                continue

    def _scan_startapps(self):
        """[NEW v7] Scan ALL Start Menu apps via Get-StartApps.
        This captures UWP, Store apps, and classic apps that appear in Start.
        Runs: Get-StartApps | Select Name, AppID | ConvertTo-Json
        """
        if not IS_WINDOWS:
            return
        try:
            ps_cmd = "Get-StartApps | Select-Object Name,AppID | ConvertTo-Json -Compress"
            r = subprocess.run(
                ["powershell", "-NoProfile", "-NonInteractive", "-Command", ps_cmd],
                capture_output=True, text=True, timeout=20,
                creationflags=_NO_WIN_FLAG
            )
            if r.returncode != 0 or not r.stdout.strip():
                logger.warning(f"Get-StartApps failed: {r.stderr[:200]}")
                return
            try:
                data = json.loads(r.stdout)
            except json.JSONDecodeError:
                # PowerShell sometimes returns single object without array
                data = json.loads(f"[{r.stdout}]")
            if isinstance(data, dict):
                data = [data]
            added = 0
            for item in data:
                name = (item.get("Name") or "").strip()
                appid = (item.get("AppID") or "").strip()
                if not name or not appid:
                    continue
                key = re.sub(r'[\s\-_]', '', name.lower())
                # Don't overwrite static DB entries
                if key in self._cache:
                    # enrich static entry with AppID if missing
                    if "appid" not in self._cache[key]:
                        self._cache[key]["appid"] = appid
                    continue
                if key in self._dynamic_apps:
                    continue
                self._dynamic_apps[key] = {
                    "display": name,
                    "appid": appid,
                    "installed": True,
                    "resolved_path": None,
                    "process": [],
                    "aliases": [name.lower(), re.sub(r'[^a-z0-9]', '', name.lower())],
                    "source": "startapps",
                }
                added += 1
            logger.info(f"[StartApps] Loaded {added} apps from Get-StartApps (total dynamic: {len(self._dynamic_apps)})")
        except Exception as e:
            logger.warning(f"_scan_startapps exception: {e}")

    def find_app(self, name: str) -> Tuple[Optional[str], Optional[Dict]]:
        name = name.lower().strip()
        if name in self._cache:
            return name, self._cache[name]
        norm = re.sub(r'[\s\-_]', '', name)
        for k, v in self._cache.items():
            if norm == re.sub(r'[\s\-_]', '', k):
                return k, v
        for k, v in self._cache.items():
            if name in [a.lower() for a in v.get("aliases", [])]:
                return k, v
        for k, v in self._cache.items():
            if name in k or k in name:
                return k, v
        for k, v in self._cache.items():
            if name in v.get("display", "").lower():
                return k, v
        if name in self._dynamic_apps:
            return name, self._dynamic_apps[name]
        for k, v in self._dynamic_apps.items():
            if name in k or k in name:
                return k, v
        # Fuzzy word-overlap
        name_words = set(name.split())
        best, best_score = None, 0
        for k, v in {**self._cache, **self._dynamic_apps}.items():
            kw = set(k.split()) | set(v.get("display", "").lower().split())
            score = len(name_words & kw)
            if score > best_score and score >= max(1, len(name_words) // 2):
                best, best_score = (k, v), score
        return best if best else (None, None)

    @safe_exec(default_return=(False, "Launch failed"))
    def launch(self, name: str, incognito: bool = False) -> Tuple[bool, str]:
        key, app = self.find_app(name)
        if app is None:
            return False, f"'{name}' not found. Try 'open microsoft store' to find apps."
        display  = app.get("display", name)
        incog_f  = app.get("incognito", "") if incognito else ""
        mode_str = " (incognito)" if incognito else ""

        # [FIX v7] Priority: resolved_path > cmd > appid (from Get-StartApps) > uwp > web_fallback
        if app.get("resolved_path") and os.path.exists(app["resolved_path"]):
            args = [app["resolved_path"]]
            if incog_f:
                args.append(incog_f)
            subprocess.Popen(args, creationflags=_NO_WIN_FLAG)
        elif app.get("cmd") and shutil.which(app["cmd"].split()[0]):
            cmd_v = app["cmd"]
            if IS_WINDOWS and cmd_v.startswith("ms-settings:"):
                os.startfile(cmd_v)
            else:
                subprocess.Popen(shlex.split(cmd_v), creationflags=_NO_WIN_FLAG)  # [S-1] shell=True removed
        elif app.get("appid"):  # From Get-StartApps
            appid = app["appid"]
            try:
                # This works for ALL Start Menu apps (UWP, Win32, Store)
                subprocess.Popen(
                    ["explorer.exe", f"shell:AppsFolder\\{appid}"],
                    creationflags=_NO_WIN_FLAG
                )
            except Exception as e:
                logger.warning(f"StartApps launch failed for {display}: {e}")
                if app.get("web_fallback"):
                    webbrowser.open(app["web_fallback"])
                    return True, JarvisResponder.app_open(display, web=True)
                return False, f"Failed to launch {display}"
        elif app.get("uwp"):
            uid = app["uwp"]
            # Verify UWP package exists before launching
            try:
                if IS_WINDOWS:
                    check_ps = f"Get-AppxPackage -Name {uid.split('_')[0]}* | Select-Object -First 1"
                    r = subprocess.run(["powershell", "-NoProfile", "-Command", check_ps],
                                       capture_output=True, text=True, timeout=5)
                    if r.stdout.strip() == "":
                        if app.get("web_fallback"):
                            webbrowser.open(app["web_fallback"])
                            return True, f"{display} not installed, opening web version"
                        return False, f"{display} is not installed"
                subprocess.Popen(
                    ["explorer.exe", f"shell:AppsFolder\\{uid}!App"],
                    creationflags=_NO_WIN_FLAG
                )
            except Exception as e:
                logger.warning(f"UWP launch failed for {display}: {e}")
                if app.get("web_fallback"):
                    webbrowser.open(app["web_fallback"])
                    return True, JarvisResponder.app_open(display, web=True)
                return False, f"Failed to launch {display}"
        elif app.get("web_fallback"):
            webbrowser.open(app["web_fallback"])
            return True, JarvisResponder.app_open(display, web=True)
        else:
            return False, f"No launch method for '{display}'"

        logger.info(f"Launched: {display}{mode_str}")
        return True, JarvisResponder.app_open(display)

    @safe_exec(default_return=(False, "Close failed"))
    def close(self, name: str) -> Tuple[bool, str]:
        """
        [M-5] FIX: explorer.exe is no longer unconditionally skipped.
        The old guard checked pname == 'explorer.exe' AFTER the pname-in-targets
        check, but 'file explorer' targets were never populated because the
        APP_DATABASE process list was empty. Both issues are now fixed:
          1) APP_DATABASE["file explorer"]["process"] now includes "explorer.exe"
          2) The unconditional skip is removed; explorer is only excluded from
             non-explicit generic kills (protected list below).
        """
        if not PSUTIL_OK:
            return False, "psutil not installed"

        key, app = self.find_app(name)
        targets = set()
        if app:
            targets.update(p.lower() for p in app.get("process", []))
        if name.lower() in PROCESS_ALIASES:
            targets.update(p.lower() for p in PROCESS_ALIASES[name.lower()])
        if not targets:
            targets.add(name.lower())
            targets.add(name.lower() + ".exe")

        # System-critical processes that should NEVER be killed implicitly
        # (only killed if directly targeted by name — e.g., "close file explorer")
        PROTECTED = {"system", "smss.exe", "csrss.exe", "wininit.exe", "services.exe",
                     "lsass.exe", "winlogon.exe", "svchost.exe", "dwm.exe", "explorer.exe"}

        # Special handling for File Explorer - close windows instead of killing process
        if "explorer.exe" in targets or name.lower() in ("file explorer", "explorer", "files"):
            # Close all File Explorer windows gracefully using Alt+F4 or Win32
            if WIN32_OK:
                closed = 0
                def _enum(hwnd, _):
                    nonlocal closed
                    if win32gui.IsWindowVisible(hwnd):
                        try:
                            _, pid = win32process.GetWindowThreadProcessId(hwnd)
                            pname = psutil.Process(pid).name().lower()
                            if pname == "explorer.exe":
                                title = win32gui.GetWindowText(hwnd)
                                # Skip the desktop/taskbar window (has no title or is "Program Manager")
                                if title and title != "Program Manager" and ("File Explorer" in win32gui.GetClassName(hwnd) or "CabinetWClass" == win32gui.GetClassName(hwnd)):
                                    win32gui.PostMessage(hwnd, win32con.WM_CLOSE, 0, 0)
                                    closed += 1
                        except Exception:
                            pass
                win32gui.EnumWindows(_enum, None)
                if closed > 0:
                    return True, f"Closed {closed} File Explorer window(s)"
                # If no windows found, try generic close
                return True, "File Explorer windows closed"
            else:
                return False, "Cannot close File Explorer (win32 not available)"

        # Remove protected processes unless the user explicitly targeted them
        user_requested = {name.lower(), name.lower() + ".exe"}
        explicit_targets = targets - (PROTECTED - user_requested)

        count = 0
        for proc in psutil.process_iter(["name"]):
            try:
                pname = (proc.info.get("name") or "").lower()
                if pname in explicit_targets:
                    proc.terminate()
                    count += 1
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                continue

        if count:
            logger.info(f"Closed {count} process(es) for '{name}'")
            return True, JarvisResponder.app_close(name)
        
        # If no process found, try closing by window title (for UWP apps like Microsoft To Do)
        if WIN32_OK:
            closed_windows = 0
            def _close_by_title(hwnd, _):
                nonlocal closed_windows
                if win32gui.IsWindowVisible(hwnd):
                    title = win32gui.GetWindowText(hwnd).lower()
                    if name.lower() in title or (app and app.get("display", "").lower() in title):
                        win32gui.PostMessage(hwnd, win32con.WM_CLOSE, 0, 0)
                        closed_windows += 1
            win32gui.EnumWindows(_close_by_title, None)
            if closed_windows > 0:
                return True, JarvisResponder.app_close(name)
        
        return False, f"'{name}' is not running"

    @safe_exec(default_return=(False, "Switch failed"))
    def switch_to(self, name: str) -> Tuple[bool, str]:
        if not WIN32_OK or not PSUTIL_OK:
            return False, "win32gui / psutil not available"
        key, app = self.find_app(name)
        proc_names = [p.lower() for p in (app.get("process", []) if app else [name])]
        display    = app.get("display", name) if app else name
        found      = [False]

        def _enum(hwnd, _):
            if found[0]:
                return
            if not win32gui.IsWindowVisible(hwnd):
                return
            try:
                _, pid = win32process.GetWindowThreadProcessId(hwnd)
                proc   = psutil.Process(pid)
                pname  = proc.name().lower()
                if any(p in pname for p in proc_names):
                    win32gui.ShowWindow(hwnd, win32con.SW_RESTORE)
                    win32gui.SetForegroundWindow(hwnd)
                    found[0] = True
            except Exception:
                pass

        win32gui.EnumWindows(_enum, None)
        if not found[0]:
            def _title(hwnd, _):
                if found[0]:
                    return
                if win32gui.IsWindowVisible(hwnd):
                    title = win32gui.GetWindowText(hwnd).lower()
                    if name.lower() in title or display.lower() in title:
                        win32gui.ShowWindow(hwnd, win32con.SW_RESTORE)
                        win32gui.SetForegroundWindow(hwnd)
                        found[0] = True
            win32gui.EnumWindows(_title, None)

        return (True, f"Switched to {display}") if found[0] else (False, f"Window not found: '{name}'")

    @safe_exec(default_return=(False, "Failed"))
    def maximize_window(self, name: str) -> Tuple[bool, str]:
        if not WIN32_OK:
            return False, "win32gui not available"
        key, app   = self.find_app(name)
        proc_names = [p.lower() for p in (app.get("process", []) if app else [name])]
        display    = app.get("display", name) if app else name
        found      = [False]

        def _enum(hwnd, _):
            if found[0] or not win32gui.IsWindowVisible(hwnd):
                return
            try:
                title = win32gui.GetWindowText(hwnd).lower()
                match = name.lower() in title or display.lower() in title
                if not match and PSUTIL_OK:
                    _, pid = win32process.GetWindowThreadProcessId(hwnd)
                    pname  = psutil.Process(pid).name().lower()
                    match  = any(p in pname for p in proc_names)
                if match:
                    win32gui.ShowWindow(hwnd, win32con.SW_MAXIMIZE)
                    # [FIX-V10] SetForegroundWindow can fail — wrap in try/except
                    try:
                        win32gui.SetForegroundWindow(hwnd)
                    except Exception:
                        try:
                            win32gui.BringWindowToTop(hwnd)
                        except Exception:
                            pass
                    found[0] = True
            except Exception:
                pass

        win32gui.EnumWindows(_enum, None)
        return (True, JarvisResponder.window_maximize(display)) if found[0] else (False, f"Not found: '{name}'")

