class TerminalAgent(BaseAgent):
    """Execute shell commands, manage dev environments. ALWAYS confirms."""
    name = "terminal"
    description = "Execute terminal/shell commands, install packages, run scripts, manage virtual environments"
    capabilities = [
        "run_command", "install_package", "run_script",
        "create_venv", "activate_venv",
    ]
    destructive_actions = ["run_command", "install_package", "run_script",
                           "create_venv"]  # all terminal ops need confirmation

    def execute(self, action: str, params: Dict[str, Any],
                context: Dict[str, Any]) -> AgentResult:
        if not self._arjun:
            return AgentResult(success=False, message="ARJUN not attached")
        command = params.get("command", "")
        # [V14.1-FIX-4.1] Whitelist managers + interpreters to prevent shell injection
        _ALLOWED_MANAGERS = {"pip", "pip3", "npm", "yarn", "cargo", "apt", "apt-get",
                             "brew", "dnf", "pacman", "go"}
        _ALLOWED_INTERPRETERS = {"python", "python3", "node", "bash", "sh", "ruby", "perl"}
        try:
            if action == "run_command":
                # [V14.2-FIX-H1] command allowlist to prevent arbitrary shell execution
                # [V16.2-FIX-C6] Extended allowlist for deployment commands
                _ALLOWED_CMDS = {"ls", "pwd", "echo", "cat", "grep", "find", "df",
                                 "du", "ps", "top", "whoami", "date", "cal", "uptime",
                                 "free", "lscpu", "uname", "hostname", "ip", "ifconfig",
                                 "netstat", "ss", "head", "tail", "wc", "sort", "uniq",
                                 "diff", "file", "stat", "which", "whereis", "env",
                                 "git", "python", "python3", "node", "npm", "pip", "pip3",
                                 "cargo", "go", "mvn", "gradle", "make",
                                 "docker", "kubectl", "helm",
                                 "bash", "sh", "powershell"}
                try:
                    parts = shlex.split(command)
                except ValueError as exc:
                    return AgentResult(success=False, message=f"Invalid command syntax: {exc}")
                if not parts:
                    return AgentResult(success=False, message="Empty command")
                # [V16.2-FIX-C6] Check first command against allowlist
                if parts[0] not in _ALLOWED_CMDS:
                    return AgentResult(success=False,
                                       message=f"Rejected: command {parts[0]!r} not in allowed list. "
                                               f"Allowed: {sorted(_ALLOWED_CMDS)[:15]}...")
                # [V16.2-FIX-C6] If command has shell operators (&&, ||, |, >, 2>&1),
                # use shell=True with cwd (needed for deploy commands like "cd X && pip install")
                shell_ops = any(op in command for op in ["&&", "||", "|", "2>&1", ">", "<"])
                cwd = params.get("cwd") or params.get("working_dir")
                if shell_ops or cwd:
                    # Shell mode — first command must still be allowlisted (checked above)
                    result = subprocess.run(
                        command, shell=True, capture_output=True, text=True,
                        timeout=120, cwd=cwd
                    )
                else:
                    # Safe mode — no shell, split command
                    result = subprocess.run(
                        parts, shell=False, capture_output=True, text=True, timeout=60,
                        cwd=cwd
                    )
                output = (result.stdout or "") + (result.stderr or "")
                ok = result.returncode == 0
                return AgentResult(success=ok, message=output[:2000] or "Command completed",
                                   data={"returncode": result.returncode, "command": command})
            elif action == "install_package":
                pkg = params.get("package", "")
                manager = params.get("manager", "pip")
                # [FIX-4.1] validate manager against whitelist
                if manager not in _ALLOWED_MANAGERS:
                    return AgentResult(success=False,
                                       message=f"Rejected: package manager {manager!r} not in allowed list {sorted(_ALLOWED_MANAGERS)}")
                if not pkg or not pkg.strip():
                    return AgentResult(success=False, message="No package name provided")
                # [FIX-4.1] shlex.quote the package name to prevent injection
                safe_pkg = shlex.quote(pkg.strip())
                cmd = f"{manager} install {safe_pkg}"
                result = subprocess.run(cmd, shell=True, capture_output=True,
                                        text=True, timeout=300)
                return AgentResult(success=result.returncode == 0,
                                   message=result.stdout[:2000] or result.stderr[:2000],
                                   data={"command": cmd})
            elif action == "run_script":
                script = params.get("script", "")
                interpreter = params.get("interpreter", "python")
                # [FIX-4.1] validate interpreter against whitelist
                if interpreter not in _ALLOWED_INTERPRETERS:
                    return AgentResult(success=False,
                                       message=f"Rejected: interpreter {interpreter!r} not in allowed list {sorted(_ALLOWED_INTERPRETERS)}")
                if not script or not script.strip():
                    return AgentResult(success=False, message="No script path provided")
                # [FIX-4.1] shlex.quote the script path
                safe_script = shlex.quote(script.strip())
                cmd = f"{interpreter} {safe_script}"
                result = subprocess.run(cmd, shell=True, capture_output=True,
                                        text=True, timeout=120)
                return AgentResult(success=result.returncode == 0,
                                   message=result.stdout[:2000] or result.stderr[:2000],
                                   data={"command": cmd})
            elif action == "create_venv":
                venv_name = params.get("name", "venv")
                # [FIX-4.1] sanitize venv name (no path traversal)
                safe_name = os.path.basename(venv_name)
                result = subprocess.run(
                    [sys.executable, "-m", "venv", safe_name],
                    capture_output=True, text=True, timeout=60
                )
                return AgentResult(success=result.returncode == 0,
                                   message=f"Created virtual environment: {safe_name}",
                                   data={"venv": safe_name})
            else:
                return AgentResult(success=False, message=f"Unknown terminal action: {action}")
        except subprocess.TimeoutExpired:
            return AgentResult(success=False, message="Command timed out (>60s)")
        except Exception as exc:
            logger.error(f"[TerminalAgent] {action} failed: {exc}", exc_info=True)
            return AgentResult(success=False, message=f"Terminal action failed: {exc}")


class CodingAgent(BaseAgent):
    """Generate, explain, debug, refactor, translate code via the local LLM."""
    name = "coding"
    description = "Generate code, explain code, debug programs, refactor, translate between languages, write SQL, build scripts"
    capabilities = [
        "generate_code", "explain_code", "debug_code", "refactor_code",
        "translate_code", "write_sql", "create_project", "solve_problem",
    ]

    def execute(self, action: str, params: Dict[str, Any],
                context: Dict[str, Any]) -> AgentResult:
        if not self._arjun:
            return AgentResult(success=False, message="ARJUN not attached")
        ai = self._arjun.ai
        task_desc = params.get("task", params.get("code", params.get("query", "")))
        language = params.get("language", "")
        prompts = {
            "generate_code": f"Write {language} code for: {task_desc}\n\nReturn only the code in a markdown code block, then a brief explanation.",
            "explain_code": f"Explain this {language} code clearly:\n\n```\n{task_desc}\n```",
            "debug_code": f"Debug this {language} code. Identify errors and provide a corrected version:\n\n```\n{task_desc}\n```",
            "refactor_code": f"Refactor this {language} code to be cleaner and more idiomatic:\n\n```\n{task_desc}\n```",
            "translate_code": f"Translate this code to {language}:\n\n```\n{task_desc}\n```",
            "write_sql": f"Write a SQL query for: {task_desc}\n\nReturn only the SQL, then a brief explanation.",
            "create_project": f"Design a project structure for: {task_desc}\n\nList the files and folders, then provide the main entry-point code.",
            "solve_problem": f"Solve this programming problem step by step:\n\n{task_desc}\n\nProvide the solution code and an explanation.",
        }
        prompt = prompts.get(action)
        if not prompt:
            return AgentResult(success=False, message=f"Unknown coding action: {action}")
        try:
            # [V16.2] Use ModelManager to get the coding model if available
            mgr = getattr(self._arjun, "model_manager", None)
            if mgr:
                coding_model = mgr.get_model_for_role(ModelRole.CODING)
                if coding_model:
                    backend, model_name = coding_model
                    # Temporarily switch to the coding model
                    orig_backend = ai._backend
                    orig_model = ai._model
                    ai._backend = backend
                    ai._model = model_name
                    logger.info(f"[CodingAgent] using coding model: {model_name} ({backend})")
                    try:
                        ok, response = ai.chat(prompt, max_tokens=2048)
                    finally:
                        # Restore original model
                        ai._backend = orig_backend
                        ai._model = orig_model
                else:
                    ok, response = ai.chat(prompt, max_tokens=2048)
            else:
                ok, response = ai.chat(prompt, max_tokens=2048)
            if not ok:
                return AgentResult(success=False, message=f"AI error: {response}")
            return AgentResult(success=True, message=response,
                               data={"action": action, "language": language})
        except Exception as exc:
            logger.error(f"[CodingAgent] {action} failed: {exc}", exc_info=True)
            return AgentResult(success=False, message=f"Coding action failed: {exc}")


class ResearchAgent(BaseAgent):
    """Research topics, gather info, summarize, compare. Uses LLM + optional web search."""
    name = "research"
    description = "Research topics, gather information, summarize findings, compare technologies, produce structured reports, search the web"
    capabilities = [
        "research_topic", "summarize_text", "compare_options",
        "gather_information", "structured_report",
        "web_search", "search_web", "find_information", "search",
        "summarize", "compile_findings",
    ]

    def execute(self, action: str, params: Dict[str, Any],
                context: Dict[str, Any]) -> AgentResult:
        if not self._arjun:
            return AgentResult(success=False, message="ARJUN not attached")
        ai = self._arjun.ai
        topic = params.get("topic", params.get("query", params.get("text",
                params.get("search_query", params.get("subject", "")))))

        # Action aliases — map LLM-returned action names to actual prompts
        action_map = {
            "web_search": "web_search",
            "search_web": "web_search",
            "search": "web_search",
            "find_information": "gather_information",
            "summarize": "summarize_text",
            "compile_findings": "structured_report",
        }
        actual_action = action_map.get(action, action)

        prompts = {
            "research_topic": f"Research the topic: {topic}\n\nProvide a comprehensive overview with key points, applications, and considerations.",
            "summarize_text": f"Summarize the following text clearly and concisely:\n\n{topic}",
            "compare_options": f"Compare these options: {topic}\n\nProvide a comparison table and a recommendation.",
            "gather_information": f"Gather information about: {topic}\n\nList key facts, sources, and important considerations.",
            "structured_report": f"Write a structured report on: {topic}\n\nInclude an introduction, key findings, analysis, and conclusion.",
            "web_search": f"Search for information about: {topic}\n\nProvide the most relevant and up-to-date findings. Include specific details like prices, ratings, features, and URLs where applicable. Format as a clear list with key details for each result.",
        }
        prompt = prompts.get(actual_action)
        if not prompt:
            return AgentResult(success=False, message=f"Unknown research action: {action}")
        try:
            ok, response = ai.chat(prompt, max_tokens=2048)
            if not ok:
                return AgentResult(success=False, message=f"AI error: {response}")
            return AgentResult(success=True, message=response,
                               data={"action": actual_action, "topic": topic})
        except Exception as exc:
            logger.error(f"[ResearchAgent] {action} failed: {exc}", exc_info=True)
            return AgentResult(success=False, message=f"Research action failed: {exc}")


