class ProductivityAgent(BaseAgent):
    """Notes, to-do lists, reminders, timers, scheduling."""
    name = "productivity"
    description = "Manage notes, to-do lists, reminders, timers, and scheduling"
    capabilities = [
        "add_note", "list_notes", "search_notes", "delete_note",
        "add_todo", "list_todos", "complete_todo",
        "set_timer", "stop_timer", "timer_status",
        "set_reminder", "start_pomodoro", "stop_pomodoro", "pomodoro_status",
    ]
    destructive_actions = ["delete_note"]

    def execute(self, action: str, params: Dict[str, Any],
                context: Dict[str, Any]) -> AgentResult:
        if not self._arjun:
            return AgentResult(success=False, message="ARJUN not attached")
        notes = self._arjun.notes
        timer = self._arjun.timer
        pomodoro = self._arjun.pomodoro
        try:
            if action == "add_note":
                # NotesManager.add(text, tags) — combine title+content into text
                text = params.get("title", "")
                if params.get("content"):
                    text = f"{text}\n{params['content']}"
                ok, m = notes.add(text)
            elif action == "list_notes":
                ok, m = notes.read()
            elif action == "search_notes":
                ok, m = notes.read(search=params.get("query", ""))
            elif action == "delete_note":
                ok, m = notes.delete_note(params.get("id", ""))
            elif action == "add_todo":
                # [V14.2] todos not implemented in NotesManager — store as a note
                ok, m = notes.add(f"TODO: {params.get('task', '')}")
            elif action == "list_todos":
                ok, m = notes.read(search="TODO:")
            elif action == "complete_todo":
                # Mark by deleting the todo note
                ok, m = notes.delete_note(params.get("id", ""))
            elif action == "set_timer":
                # TimerManager.set_timer(text) — encode duration in the text
                secs = int(params.get("seconds", params.get("duration", 60)))
                label = params.get("label", "timer")
                ok, m = timer.set_timer(f"{label} {secs}s")
            elif action == "stop_timer":
                ok, m = timer.list_timers()  # list + user cancels manually
            elif action == "timer_status":
                ok, m = timer.list_timers()
            elif action == "start_pomodoro":
                ok, m = pomodoro.start()
            elif action == "stop_pomodoro":
                ok, m = pomodoro.stop()
            elif action == "pomodoro_status":
                ok, m = pomodoro.status()
            else:
                return AgentResult(success=False, message=f"Unknown productivity action: {action}")
            return AgentResult(success=ok, message=m, data={"action": action})
        except Exception as exc:
            logger.error(f"[ProductivityAgent] {action} failed: {exc}", exc_info=True)
            return AgentResult(success=False, message=f"Productivity action failed: {exc}")


