# v15 MODULE — AI OPERATING SYSTEM UPGRADE
# ══════════════════════════════════════════════════════════════════════════════
# [V15-AIOS] Upgrades ARJUN from a voice assistant into a resilient AI OS:
#
#   1. WorkflowEngine      — durable state, checkpoints, resume, retry, rollback
#   2. LongTermMemory      — persistent knowledge graph with semantic search
#   3. PluginLifecycle     — install/remove/update, sandboxing, hot reload
#   4. ObservabilitySystem — metrics, tracing, timelines, token/CPU tracking
#   5. DeploymentOrchestrator — detect → build → test → deploy → health → rollback
#   6. AutonomousRecovery  — diagnose failures, retry, alternative paths
#   7. ProjectDetector     — auto-detect language/framework/build system
#   8. AdvancedPlanner     — sequential/parallel/conditional/replanning
#
# All subsystems persist to ~/.arjun/ and survive restarts.
# ══════════════════════════════════════════════════════════════════════════════
import sqlite3 as _sqlite3
from enum import Enum as _Enum


# ─── Workflow State Enums ─────────────────────────────────────────────────────
class WorkflowState(_Enum):
    PENDING = "pending"
    RUNNING = "running"
    PAUSED = "paused"
    COMPLETED = "completed"
    FAILED = "failed"
    ROLLED_BACK = "rolled_back"
    CANCELLED = "cancelled"


class TaskState(_Enum):
    PENDING = "pending"
    RUNNING = "running"
    COMPLETED = "completed"
    FAILED = "failed"
    SKIPPED = "skipped"
    ROLLED_BACK = "rolled_back"


# ══════════════════════════════════════════════════════════════════════════════
# 1. DURABLE WORKFLOW ENGINE
# ══════════════════════════════════════════════════════════════════════════════
class WorkflowStep:
    """A single step in a workflow. Persisted to SQLite."""
    __slots__ = ("id", "workflow_id", "step_index", "name", "agent", "action",
                 "params", "depends_on", "condition", "state", "result",
                 "checkpoint", "attempts", "max_retries", "started_at", "completed_at")

    def __init__(self, workflow_id: str, step_index: int, name: str,
                 agent: str = "", action: str = "", params: Dict = None,
                 depends_on: List[int] = None, condition: str = "",
                 max_retries: int = 3):
        self.id = str(uuid.uuid4())
        self.workflow_id = workflow_id
        self.step_index = step_index
        self.name = name
        self.agent = agent
        self.action = action
        self.params = params or {}
        self.depends_on = depends_on or []
        self.condition = condition  # Python expr evaluated against workflow context
        self.state = TaskState.PENDING
        self.result: Optional[AgentResult] = None
        self.checkpoint: Optional[Dict] = None  # snapshot before execution
        self.attempts = 0
        self.max_retries = max_retries
        self.started_at: Optional[str] = None
        self.completed_at: Optional[str] = None

    def to_dict(self) -> Dict:
        return {
            "id": self.id, "workflow_id": self.workflow_id,
            "step_index": self.step_index, "name": self.name,
            "agent": self.agent, "action": self.action,
            "params": self.params, "depends_on": self.depends_on,
            "condition": self.condition, "state": self.state.value,
            "checkpoint": self.checkpoint, "attempts": self.attempts,
            "max_retries": self.max_retries,
            "started_at": self.started_at, "completed_at": self.completed_at,
            "result_success": self.result.success if self.result else None,
            "result_message": self.result.message if self.result else None,
        }


class Workflow:
    """A durable workflow with checkpoints. Survives crashes."""
    __slots__ = ("id", "name", "description", "steps", "context", "state",
                 "created_at", "updated_at", "parent_workflow_id", "tags")

    def __init__(self, name: str, description: str = "",
                 parent_workflow_id: Optional[str] = None):
        self.id = str(uuid.uuid4())
        self.name = name
        self.description = description
        self.steps: List[WorkflowStep] = []
        self.context: Dict[str, Any] = {}  # shared state between steps
        self.state = WorkflowState.PENDING
        self.created_at = datetime.now().isoformat()
        self.updated_at = self.created_at
        self.parent_workflow_id = parent_workflow_id
        self.tags: List[str] = []

    def add_step(self, name: str, agent: str = "", action: str = "",
                 params: Dict = None, depends_on: List[int] = None,
                 condition: str = "", max_retries: int = 3) -> WorkflowStep:
        step = WorkflowStep(self.id, len(self.steps), name, agent, action,
                            params, depends_on, condition, max_retries)
        self.steps.append(step)
        self.updated_at = datetime.now().isoformat()
        return step

    def to_dict(self) -> Dict:
        return {
            "id": self.id, "name": self.name, "description": self.description,
            "state": self.state.value, "created_at": self.created_at,
            "updated_at": self.updated_at, "parent_workflow_id": self.parent_workflow_id,
            "tags": self.tags, "context": self.context,
            "steps": [s.to_dict() for s in self.steps],
        }


def _safe_eval_condition(condition: str, context: Dict[str, Any]) -> bool:
    """[V16.2-FIX-C4] Safely evaluate a workflow condition expression.
    Only allows: True, False, None, string literals, and/or/not, ==, !=,
    in, not in, and context variable lookups. NO arbitrary code execution.
    """
    if not condition:
        return True
    try:
        tree = ast.parse(condition, mode="eval")
        return _eval_ast_node(tree.body, context)
    except Exception as exc:
        logger.warning(f"[WorkflowEngine] condition eval failed: {exc} | condition={condition!r}")
        return True  # default to True (run the step) on eval failure

def _eval_ast_node(node, context: Dict[str, Any]) -> Any:
    """Recursively evaluate an AST node safely."""
    if isinstance(node, ast.Constant):
        return node.value
    if isinstance(node, ast.Name):
        return context.get(node.id)
    if isinstance(node, ast.BoolOp):
        if isinstance(node.op, ast.And):
            return all(_eval_ast_node(v, context) for v in node.values)
        if isinstance(node.op, ast.Or):
            return any(_eval_ast_node(v, context) for v in node.values)
    if isinstance(node, ast.UnaryOp) and isinstance(node.op, ast.Not):
        return not _eval_ast_node(node.operand, context)
    if isinstance(node, ast.Compare):
        left = _eval_ast_node(node.left, context)
        for op, comp in zip(node.ops, node.comparators):
            right = _eval_ast_node(comp, context)
            if isinstance(op, ast.Eq):
                if not (left == right): return False
            elif isinstance(op, ast.NotEq):
                if not (left != right): return False
            elif isinstance(op, ast.In):
                if left not in right: return False
            elif isinstance(op, ast.NotIn):
                if left in right: return False
            else:
                raise ValueError(f"Unsupported comparison: {type(op).__name__}")
            left = right
        return True
    raise ValueError(f"Unsupported AST node: {type(node).__name__}")


class WorkflowEngine:
    """
    Durable workflow engine with SQLite-backed persistence.

    Features:
      • Persist workflow + step state to ~/.arjun/workflows.db
      • Checkpoint before each step (rollback point)
      • Resume from last successful checkpoint after crash
      • Retry failed steps (up to max_retries)
      • Rollback completed steps on failure (if step has rollback action)
      • Branching (conditional execution via `condition` expr)
      • Parallel execution (steps with no unmet dependencies run concurrently)
      • Scheduled execution (delay_until)
      • Long-running (state survives process restart)

    The engine is abstracted — swap SQLite for Temporal/Prefect by
    implementing the same persist/load interface.
    """

    def __init__(self, registry: Optional[AgentRegistry] = None,
                 memory: Optional[ConversationMemory] = None,
                 db_path: Optional[Path] = None):
        self._registry = registry
        self._memory = memory
        self._db_path = db_path or (HOME / ".arjun" / "workflows.db")
        self._db_path.parent.mkdir(parents=True, exist_ok=True)
        self._save_lock = threading.Lock()  # [V16.2-FIX-M5] serialize saves
        self._init_db()
        self._active_workflows: Dict[str, Workflow] = {}

    def _init_db(self) -> None:
        # [V16.2-FIX-M5] Use plain sqlite3.connect (Path has no .connect())
        with _sqlite3.connect(str(self._db_path)) as conn:
            conn.execute("PRAGMA journal_mode=WAL")  # [FIX-M5] WAL for concurrent reads
            conn.executescript("""
                CREATE TABLE IF NOT EXISTS workflows (
                    id TEXT PRIMARY KEY,
                    name TEXT NOT NULL,
                    description TEXT,
                    state TEXT NOT NULL DEFAULT 'pending',
                    created_at TEXT,
                    updated_at TEXT,
                    parent_workflow_id TEXT,
                    tags TEXT,
                    context_json TEXT,
                    full_json TEXT
                );
                CREATE TABLE IF NOT EXISTS workflow_steps (
                    id TEXT PRIMARY KEY,
                    workflow_id TEXT NOT NULL,
                    step_index INTEGER,
                    name TEXT,
                    agent TEXT,
                    action TEXT,
                    params_json TEXT,
                    depends_on_json TEXT,
                    condition TEXT,
                    state TEXT DEFAULT 'pending',
                    checkpoint_json TEXT,
                    attempts INTEGER DEFAULT 0,
                    max_retries INTEGER DEFAULT 3,
                    started_at TEXT,
                    completed_at TEXT,
                    result_success INTEGER,
                    result_message TEXT,
                    FOREIGN KEY (workflow_id) REFERENCES workflows(id)
                );
                CREATE INDEX IF NOT EXISTS idx_steps_workflow ON workflow_steps(workflow_id);
                CREATE INDEX IF NOT EXISTS idx_workflows_state ON workflows(state);
            """)

    def _conn(self):
        return _sqlite3.connect(str(self._db_path))

    def save(self, workflow: Workflow) -> None:
        """Persist a workflow and all its steps to SQLite."""
        with self._save_lock:  # [V16.2-FIX-M5] serialize saves across threads
            wf_data = workflow.to_dict()
            with self._conn() as conn:
                conn.execute("""
                    INSERT OR REPLACE INTO workflows
                    (id, name, description, state, created_at, updated_at,
                     parent_workflow_id, tags, context_json, full_json)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """, (workflow.id, workflow.name, workflow.description,
                      workflow.state.value, workflow.created_at, workflow.updated_at,
                      workflow.parent_workflow_id, json.dumps(workflow.tags),
                      json.dumps(workflow.context), json.dumps(wf_data)))
                for step in workflow.steps:
                    conn.execute("""
                        INSERT OR REPLACE INTO workflow_steps
                        (id, workflow_id, step_index, name, agent, action,
                         params_json, depends_on_json, condition, state,
                         checkpoint_json, attempts, max_retries,
                         started_at, completed_at, result_success, result_message)
                        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                    """, (step.id, step.workflow_id, step.step_index, step.name,
                          step.agent, step.action, json.dumps(step.params),
                          json.dumps(step.depends_on), step.condition,
                          step.state.value, json.dumps(step.checkpoint),
                          step.attempts, step.max_retries,
                          step.started_at, step.completed_at,
                          step.result.success if step.result else None,
                          step.result.message if step.result else None))

    def load(self, workflow_id: str) -> Optional[Workflow]:
        """Load a workflow from SQLite (for crash recovery)."""
        with self._conn() as conn:
            row = conn.execute("SELECT full_json FROM workflows WHERE id=?",
                               (workflow_id,)).fetchone()
            if not row:
                return None
            data = json.loads(row[0])
            wf = Workflow(data["name"], data.get("description", ""))
            wf.id = data["id"]
            wf.state = WorkflowState(data["state"])
            wf.created_at = data["created_at"]
            wf.updated_at = data["updated_at"]
            wf.parent_workflow_id = data.get("parent_workflow_id")
            wf.tags = data.get("tags", [])
            wf.context = data.get("context", {})
            for s_data in data.get("steps", []):
                step = WorkflowStep(wf.id, s_data["step_index"], s_data["name"],
                                    s_data.get("agent", ""), s_data.get("action", ""),
                                    s_data.get("params", {}),
                                    s_data.get("depends_on", []),
                                    s_data.get("condition", ""),
                                    s_data.get("max_retries", 3))
                step.id = s_data["id"]
                step.state = TaskState(s_data["state"])
                step.checkpoint = s_data.get("checkpoint")
                step.attempts = s_data.get("attempts", 0)
                step.started_at = s_data.get("started_at")
                step.completed_at = s_data.get("completed_at")
                if s_data.get("result_success") is not None:
                    step.result = AgentResult(
                        success=s_data["result_success"],
                        message=s_data.get("result_message", "")
                    )
                wf.steps.append(step)
            return wf

    def list_workflows(self, state: Optional[str] = None) -> List[Dict]:
        """List all workflows, optionally filtered by state."""
        with self._conn() as conn:
            if state:
                rows = conn.execute(
                    "SELECT id, name, state, created_at, updated_at FROM workflows WHERE state=? ORDER BY updated_at DESC",
                    (state,)).fetchall()
            else:
                rows = conn.execute(
                    "SELECT id, name, state, created_at, updated_at FROM workflows ORDER BY updated_at DESC").fetchall()
            return [{"id": r[0], "name": r[1], "state": r[2],
                     "created_at": r[3], "updated_at": r[4]} for r in rows]

    def resume(self, workflow_id: str, input_fn: Callable = input) -> Optional[Workflow]:
        """Resume an interrupted workflow from its last successful checkpoint."""
        wf = self.load(workflow_id)
        if not wf:
            return None
        logger.info(f"[WorkflowEngine] resuming workflow {wf.id} ({wf.name}) from state {wf.state.value}")
        wf.state = WorkflowState.RUNNING
        self.save(wf)
        self._active_workflows[wf.id] = wf
        return self._run(wf, input_fn)

    def execute(self, workflow: Workflow, input_fn: Callable = input) -> Workflow:
        """Execute a workflow. Persists state; survives crashes."""
        workflow.state = WorkflowState.RUNNING
        self.save(workflow)
        self._active_workflows[workflow.id] = workflow
        return self._run(workflow, input_fn)

    def _run(self, wf: Workflow, input_fn: Callable) -> Workflow:
        """Internal execution loop with checkpoint/retry/rollback."""
        logger.info(f"[WorkflowEngine] starting workflow '{wf.name}' ({len(wf.steps)} steps)")
        max_parallel = 4  # max concurrent steps
        completed_indices: Set[int] = set()

        while True:
            # Find steps ready to run (all deps completed, condition met, state pending)
            ready = []
            for i, step in enumerate(wf.steps):
                if step.state not in (TaskState.PENDING, TaskState.FAILED):
                    continue
                if i in completed_indices:
                    continue
                # Check dependencies
                deps_met = all(wf.steps[d].state == TaskState.COMPLETED for d in step.depends_on)
                if not deps_met:
                    continue
                # Check condition (if any)
                if step.condition:
                    try:
                        # [V16.2-FIX-C4] Replace eval() with safe expression evaluator
                        if not _safe_eval_condition(step.condition, wf.context):
                            step.state = TaskState.SKIPPED
                            wf.updated_at = datetime.now().isoformat()
                            self.save(wf)
                            completed_indices.add(i)
                            continue
                    except Exception as exc:
                        logger.warning(f"[WorkflowEngine] condition eval failed for step {i}: {exc}")
                ready.append((i, step))

            if not ready:
                # Check if all steps are done
                pending = [s for s in wf.steps if s.state in (TaskState.PENDING, TaskState.RUNNING, TaskState.FAILED)]
                if not pending:
                    # All done — check if any failed
                    failed = [s for s in wf.steps if s.state == TaskState.FAILED]
                    if failed:
                        wf.state = WorkflowState.FAILED
                        logger.warning(f"[WorkflowEngine] workflow '{wf.name}' FAILED — {len(failed)} step(s) failed")
                    else:
                        wf.state = WorkflowState.COMPLETED
                        logger.info(f"[WorkflowEngine] workflow '{wf.name}' COMPLETED")
                    wf.updated_at = datetime.now().isoformat()
                    self.save(wf)
                    return wf
                # Still have pending steps but none ready — must be waiting on failed deps
                break

            # Execute ready steps (up to max_parallel in parallel)
            ready = ready[:max_parallel]
            threads = []
            results_lock = threading.Lock()

            def _exec_step(idx: int, step: WorkflowStep):
                self._execute_step(wf, step, input_fn)
                with results_lock:
                    completed_indices.add(idx)

            for idx, step in ready:
                t = threading.Thread(target=_exec_step, args=(idx, step), daemon=True)
                threads.append(t)
                t.start()
            for t in threads:
                t.join(timeout=300)  # 5-min per step

            wf.updated_at = datetime.now().isoformat()
            self.save(wf)

        wf.state = WorkflowState.FAILED
        self.save(wf)
        return wf

    def _execute_step(self, wf: Workflow, step: WorkflowStep, input_fn: Callable):
        """Execute a single step with checkpoint, retry, and rollback."""
        # Checkpoint: snapshot the workflow context before execution
        step.checkpoint = {"context": deepcopy(wf.context), "step_index": step.step_index}
        step.state = TaskState.RUNNING
        step.started_at = datetime.now().isoformat()
        step.attempts += 1
        self.save(wf)

        # Get the agent
        agent = None
        if self._registry and step.agent:
            agent = self._registry.get(step.agent)

        if not agent:
            step.state = TaskState.FAILED
            step.result = AgentResult(success=False, message=f"Agent '{step.agent}' not found")
            step.completed_at = datetime.now().isoformat()
            self.save(wf)
            return

        # Try execution with retries
        while step.attempts <= step.max_retries:
            try:
                context = {"workflow_id": wf.id, "workflow_context": wf.context,
                           "memory": self._memory.context_for_llm() if self._memory else {}}
                result = agent.execute(step.action, step.params, context)
                step.result = result
                if result.success:
                    step.state = TaskState.COMPLETED
                    step.completed_at = datetime.now().isoformat()
                    # Store result in workflow context for downstream steps
                    wf.context[f"step_{step.step_index}_result"] = result.message[:500]
                    logger.info(f"[WorkflowEngine] step {step.step_index} '{step.name}' COMPLETED (attempt {step.attempts})")
                    self.save(wf)
                    return
                else:
                    logger.warning(f"[WorkflowEngine] step {step.step_index} '{step.name}' failed (attempt {step.attempts}/{step.max_retries}): {result.message[:200]}")
            except Exception as exc:
                step.result = AgentResult(success=False, message=f"Exception: {exc}")
                logger.error(f"[WorkflowEngine] step {step.step_index} exception: {exc}", exc_info=True)

            # Retry?
            if step.attempts < step.max_retries:
                step.attempts += 1
                time.sleep(1 * step.attempts)  # exponential backoff
                self.save(wf)
            else:
                break

        # All retries exhausted — mark failed
        step.state = TaskState.FAILED
        step.completed_at = datetime.now().isoformat()
        self.save(wf)
        logger.error(f"[WorkflowEngine] step {step.step_index} '{step.name}' FAILED after {step.attempts} attempts")


