# 2. LONG-TERM MEMORY & KNOWLEDGE GRAPH
# ══════════════════════════════════════════════════════════════════════════════
class LongTermMemory:
    """
    Persistent knowledge graph. Stores structured facts about the user,
    their environment, and their preferences. Survives restarts.

    Storage: ~/.arjun/memory.db (SQLite)
    Schema:
      facts(key TEXT PRIMARY KEY, value TEXT, category TEXT, confidence REAL,
            created_at TEXT, updated_at TEXT, last_accessed TEXT, access_count INTEGER)
      aliases(alias TEXT PRIMARY KEY, target_key TEXT)

    Supports:
      • Semantic search (keyword + category)
      • Structured retrieval (by key, category)
      • Contextual recall (top-N relevant facts)
      • Update existing facts
      • Forget outdated information
      • User-controlled memory management
    """

    def __init__(self, db_path: Optional[Path] = None):
        self._db_path = db_path or (HOME / ".arjun" / "memory.db")
        self._db_path.parent.mkdir(parents=True, exist_ok=True)
        self._init_db()

    def _init_db(self) -> None:
        with _sqlite3.connect(str(self._db_path)) as conn:
            conn.executescript("""
                CREATE TABLE IF NOT EXISTS facts (
                    key TEXT PRIMARY KEY,
                    value TEXT NOT NULL,
                    category TEXT DEFAULT 'general',
                    confidence REAL DEFAULT 1.0,
                    created_at TEXT,
                    updated_at TEXT,
                    last_accessed TEXT,
                    access_count INTEGER DEFAULT 0
                );
                CREATE TABLE IF NOT EXISTS aliases (
                    alias TEXT PRIMARY KEY,
                    target_key TEXT NOT NULL,
                    FOREIGN KEY (target_key) REFERENCES facts(key)
                );
                CREATE INDEX IF NOT EXISTS idx_facts_category ON facts(category);
                CREATE INDEX IF NOT EXISTS idx_facts_value ON facts(value);
            """)

    def _conn(self):
        return _sqlite3.connect(str(self._db_path))

    def remember(self, key: str, value: Any, category: str = "general",
                 confidence: float = 1.0) -> bool:
        """Store or update a fact. Returns True if new, False if updated."""
        now = datetime.now().isoformat()
        value_str = json.dumps(value) if not isinstance(value, str) else value
        with self._conn() as conn:
            existing = conn.execute("SELECT created_at FROM facts WHERE key=?", (key,)).fetchone()
            conn.execute("""
                INSERT OR REPLACE INTO facts
                (key, value, category, confidence, created_at, updated_at, last_accessed, access_count)
                VALUES (?, ?, ?, ?, ?, ?, ?, 0)
            """, (key, value_str, category, confidence,
                  existing[0] if existing else now, now, now))
            return existing is None

    def recall(self, key: str, default: Any = None) -> Any:
        """Retrieve a fact by key. Updates last_accessed + access_count."""
        # Check aliases
        with self._conn() as conn:
            alias = conn.execute("SELECT target_key FROM aliases WHERE alias=?", (key,)).fetchone()
            actual_key = alias[0] if alias else key
            row = conn.execute(
                "SELECT value, category, confidence FROM facts WHERE key=?",
                (actual_key,)).fetchone()
            if row:
                conn.execute(
                    "UPDATE facts SET last_accessed=?, access_count=access_count+1 WHERE key=?",
                    (datetime.now().isoformat(), actual_key))
                try:
                    return json.loads(row[0])
                except (json.JSONDecodeError, TypeError):
                    return row[0]
            return default

    def search(self, query: str, category: Optional[str] = None,
               limit: int = 10) -> List[Dict]:
        """Semantic search: keyword match in key/value, optionally filtered by category."""
        with self._conn() as conn:
            pattern = f"%{query}%"
            if category:
                rows = conn.execute("""
                    SELECT key, value, category, confidence, last_accessed, access_count
                    FROM facts WHERE category=? AND (key LIKE ? OR value LIKE ?)
                    ORDER BY access_count DESC, confidence DESC LIMIT ?
                """, (category, pattern, pattern, limit)).fetchall()
            else:
                rows = conn.execute("""
                    SELECT key, value, category, confidence, last_accessed, access_count
                    FROM facts WHERE key LIKE ? OR value LIKE ?
                    ORDER BY access_count DESC, confidence DESC LIMIT ?
                """, (pattern, pattern, limit)).fetchall()
            results = []
            for r in rows:
                try:
                    val = json.loads(r[1])
                except (json.JSONDecodeError, TypeError):
                    val = r[1]
                results.append({"key": r[0], "value": val, "category": r[2],
                                "confidence": r[3], "last_accessed": r[4],
                                "access_count": r[5]})
            return results

    def forget(self, key: str) -> bool:
        """Delete a fact. Returns True if deleted."""
        with self._conn() as conn:
            cursor = conn.execute("DELETE FROM facts WHERE key=?", (key,))
            conn.execute("DELETE FROM aliases WHERE target_key=?", (key,))
            return cursor.rowcount > 0

    def list_categories(self) -> List[str]:
        with self._conn() as conn:
            rows = conn.execute("SELECT DISTINCT category FROM facts ORDER BY category").fetchall()
            return [r[0] for r in rows]

    def list_facts(self, category: Optional[str] = None) -> List[Dict]:
        with self._conn() as conn:
            if category:
                rows = conn.execute(
                    "SELECT key, value, category, confidence, updated_at FROM facts WHERE category=? ORDER BY key",
                    (category,)).fetchall()
            else:
                rows = conn.execute(
                    "SELECT key, value, category, confidence, updated_at FROM facts ORDER BY category, key").fetchall()
            results = []
            for r in rows:
                try:
                    val = json.loads(r[1])
                except (json.JSONDecodeError, TypeError):
                    val = r[1]
                results.append({"key": r[0], "value": val, "category": r[2],
                                "confidence": r[3], "updated_at": r[4]})
            return results

    def set_alias(self, alias: str, target_key: str) -> None:
        with self._conn() as conn:
            conn.execute("INSERT OR REPLACE INTO aliases (alias, target_key) VALUES (?, ?)",
                         (alias, target_key))

    def context_for_llm(self, query: str = "") -> Dict[str, Any]:
        """Build a context dict of relevant facts for the LLM prompt."""
        if query:
            facts = self.search(query, limit=5)
        else:
            # Return most-accessed facts
            with self._conn() as conn:
                rows = conn.execute(
                    "SELECT key, value, category FROM facts ORDER BY access_count DESC LIMIT 10"
                ).fetchall()
                facts = [{"key": r[0], "value": r[1], "category": r[2]} for r in rows]
        return {"long_term_facts": facts}


# ══════════════════════════════════════════════════════════════════════════════
# 3. PLUGIN LIFECYCLE MANAGEMENT
# ══════════════════════════════════════════════════════════════════════════════
class PluginInfo:
    """Metadata for a registered plugin."""
    __slots__ = ("name", "version", "description", "author", "capabilities",
                 "permissions", "dependencies", "module_path", "enabled",
                 "installed_at", "updated_at", "health")

    def __init__(self, name: str, version: str = "1.0.0",
                 description: str = "", author: str = "",
                 capabilities: List[str] = None, permissions: List[str] = None,
                 dependencies: List[str] = None, module_path: str = ""):
        self.name = name
        self.version = version
        self.description = description
        self.author = author
        self.capabilities = capabilities or []
        self.permissions = permissions or []  # e.g. ["file:read", "file:write", "shell"]
        self.dependencies = dependencies or []  # other plugin names
        self.module_path = module_path
        self.enabled = True
        self.installed_at = datetime.now().isoformat()
        self.updated_at = self.installed_at
        self.health = "unknown"  # unknown / healthy / degraded / failed

    def to_dict(self) -> Dict:
        return {k: getattr(self, k) for k in self.__slots__}


class PluginManager:
    """
    Plugin lifecycle manager. Supports install/remove/update, version
    compatibility, dependency resolution, hot reload, and permissions.

    Plugins are Python modules in ~/.arjun/plugins/ that define a
    `register(registry)` function. They can add new agents, tools, or
    workflow steps.

    Permissions model: each plugin declares what it needs
    (file:read, file:write, shell, network, etc.). The user approves
    permissions at install time.
    """

    def __init__(self, plugins_dir: Optional[Path] = None,
                 registry: Optional[AgentRegistry] = None):
        self._plugins_dir = plugins_dir or (HOME / ".arjun" / "plugins")
        self._plugins_dir.mkdir(parents=True, exist_ok=True)
        self._registry = registry
        self._plugins: Dict[str, PluginInfo] = {}
        self._modules: Dict[str, Any] = {}  # loaded module objects
        self._manifest_path = self._plugins_dir / "manifest.json"
        self._load_manifest()

    def _load_manifest(self) -> None:
        try:
            if self._manifest_path.exists():
                with open(self._manifest_path) as f:
                    data = json.load(f)
                for name, info in data.items():
                    plugin = PluginInfo(name, **{k: v for k, v in info.items()
                                                 if k in PluginInfo.__slots__})
                    self._plugins[name] = plugin
        except Exception as exc:
            logger.warning(f"[PluginManager] manifest load failed: {exc}")

    def _save_manifest(self) -> None:
        try:
            with open(self._manifest_path, "w") as f:
                json.dump({k: v.to_dict() for k, v in self._plugins.items()}, f, indent=2)
        except Exception as exc:
            logger.warning(f"[PluginManager] manifest save failed: {exc}")

    def discover(self) -> List[str]:
        """Scan the plugins directory for installable plugins."""
        discovered = []
        for item in self._plugins_dir.iterdir():
            if item.is_file() and item.suffix == ".py" and not item.name.startswith("_"):
                discovered.append(item.stem)
            elif item.is_dir() and (item / "__init__.py").exists():
                discovered.append(item.name)
        return discovered

    def install(self, name: str, approved_permissions: List[str] = None,
                version: str = None) -> Tuple[bool, str]:
        """Install a plugin by name. Returns (success, message)."""
        if name in self._plugins and self._plugins[name].enabled:
            return False, f"Plugin '{name}' is already installed"
        # Find the module
        module_path = self._plugins_dir / f"{name}.py"
        if not module_path.exists():
            pkg_path = self._plugins_dir / name / "__init__.py"
            if not pkg_path.exists():
                return False, f"Plugin '{name}' not found in {self._plugins_dir}"
            module_path = pkg_path
        try:
            # Load the module
            import importlib.util
            spec = importlib.util.spec_from_file_location(f"arjun_plugin_{name}", str(module_path))
            if not spec or not spec.loader:
                return False, f"Cannot load plugin spec for '{name}'"
            module = importlib.util.module_from_spec(spec)
            spec.loader.exec_module(module)
            self._modules[name] = module
            # Extract metadata
            info = PluginInfo(
                name=name,
                version=getattr(module, "__version__", "1.0.0"),
                description=getattr(module, "__doc__", "") or "",
                author=getattr(module, "__author__", ""),
                capabilities=getattr(module, "__capabilities__", []),
                permissions=getattr(module, "__permissions__", []),
                dependencies=getattr(module, "__dependencies__", []),
                module_path=str(module_path),
            )
            # Check permissions
            if approved_permissions is None:
                # Auto-approve if no permissions requested
                approved_permissions = []
            unapproved = set(info.permissions) - set(approved_permissions)
            if unapproved:
                return False, (f"Plugin '{name}' requires permissions not approved: {unapproved}. "
                               f"Approved: {approved_permissions}. Re-install with these permissions.")
            # Check dependencies
            for dep in info.dependencies:
                if dep not in self._plugins or not self._plugins[dep].enabled:
                    return False, f"Plugin '{name}' depends on '{dep}' which is not installed/enabled"
            # Register with the agent registry
            if hasattr(module, "register") and self._registry:
                module.register(self._registry)
            self._plugins[name] = info
            self._save_manifest()
            logger.info(f"[PluginManager] installed plugin '{name}' v{info.version}")
            return True, f"Plugin '{name}' v{info.version} installed successfully"
        except Exception as exc:
            logger.error(f"[PluginManager] install failed for '{name}': {exc}", exc_info=True)
            return False, f"Install failed: {exc}"

    def remove(self, name: str) -> Tuple[bool, str]:
        """Remove a plugin."""
        if name not in self._plugins:
            return False, f"Plugin '{name}' is not installed"
        # Check if other plugins depend on it
        for p_name, p_info in self._plugins.items():
            if name in p_info.dependencies and p_info.enabled:
                return False, f"Cannot remove '{name}': plugin '{p_name}' depends on it"
        del self._plugins[name]
        if name in self._modules:
            del self._modules[name]
        self._save_manifest()
        logger.info(f"[PluginManager] removed plugin '{name}'")
        return True, f"Plugin '{name}' removed"

    def update(self, name: str) -> Tuple[bool, str]:
        """Hot-reload a plugin (re-import the module)."""
        if name not in self._plugins:
            return False, f"Plugin '{name}' is not installed"
        # Remove from internal tracking but keep the file
        saved_permissions = self._plugins[name].permissions
        del self._plugins[name]
        if name in self._modules:
            del self._modules[name]
        # Force re-import
        # [REFACTOR] removed redundant `import sys` — already imported at module level
        mod_name = f"arjun_plugin_{name}"
        if mod_name in sys.modules:
            del sys.modules[mod_name]
        # Re-install with saved permissions
        return self.install(name, approved_permissions=saved_permissions)

    def list_plugins(self) -> List[Dict]:
        return [p.to_dict() for p in self._plugins.values()]

    def get_plugin(self, name: str) -> Optional[PluginInfo]:
        return self._plugins.get(name)

    def check_health(self) -> Dict[str, str]:
        """Check health of all plugins."""
        results = {}
        for name, info in self._plugins.items():
            if not info.enabled:
                results[name] = "disabled"
                continue
            module = self._modules.get(name)
            if module is None:
                results[name] = "failed"
                info.health = "failed"
                continue
            # Call health check if available
            if hasattr(module, "health_check"):
                try:
                    healthy = module.health_check()
                    results[name] = "healthy" if healthy else "degraded"
                    info.health = results[name]
                except Exception:
                    results[name] = "failed"
                    info.health = "failed"
            else:
                results[name] = "healthy"
                info.health = "healthy"
        self._save_manifest()
        return results


# ══════════════════════════════════════════════════════════════════════════════
# 4. PRODUCTION OBSERVABILITY
# ══════════════════════════════════════════════════════════════════════════════
class MetricsCollector:
    """
    Collects and persists metrics: workflow execution, agent execution,
    latency, token usage, CPU/memory, error rates, retry counts.

    Storage: ~/.arjun/metrics.db (SQLite)
    """

    def __init__(self, db_path: Optional[Path] = None):
        self._db_path = db_path or (HOME / ".arjun" / "metrics.db")
        self._db_path.parent.mkdir(parents=True, exist_ok=True)
        self._init_db()
        self._counters: Dict[str, float] = defaultdict(float)
        self._histograms: Dict[str, List[float]] = defaultdict(list)
        self._lock = threading.Lock()

    def _init_db(self) -> None:
        with _sqlite3.connect(str(self._db_path)) as conn:
            conn.executescript("""
                CREATE TABLE IF NOT EXISTS events (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    timestamp TEXT NOT NULL,
                    event_type TEXT NOT NULL,
                    entity_type TEXT,
                    entity_id TEXT,
                    duration_ms REAL,
                    success INTEGER,
                    error TEXT,
                    metadata_json TEXT
                );
                CREATE TABLE IF NOT EXISTS counters (
                    name TEXT PRIMARY KEY,
                    value REAL DEFAULT 0,
                    updated_at TEXT
                );
                CREATE INDEX IF NOT EXISTS idx_events_type ON events(event_type);
                CREATE INDEX IF NOT EXISTS idx_events_ts ON events(timestamp);
            """)

    def _conn(self):
        return _sqlite3.connect(str(self._db_path))

    def record_event(self, event_type: str, entity_type: str = "",
                     entity_id: str = "", duration_ms: float = 0,
                     success: bool = True, error: str = "",
                     **metadata) -> None:
        """Record an observable event."""
        now = datetime.now().isoformat()
        with self._lock, self._conn() as conn:
            conn.execute("""
                INSERT INTO events (timestamp, event_type, entity_type, entity_id,
                                    duration_ms, success, error, metadata_json)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?)
            """, (now, event_type, entity_type, entity_id, duration_ms,
                  int(success), error, json.dumps(metadata, default=str)))

    def increment(self, counter_name: str, amount: float = 1) -> None:
        with self._lock:
            self._counters[counter_name] += amount
            now = datetime.now().isoformat()
            with self._conn() as conn:
                conn.execute("""
                    INSERT INTO counters (name, value, updated_at)
                    VALUES (?, ?, ?)
                    ON CONFLICT(name) DO UPDATE SET value=value+?, updated_at=?
                """, (counter_name, amount, now, amount, now))

    def get_counter(self, name: str) -> float:
        # Check in-memory first (faster, reflects current session)
        if name in self._counters:
            return self._counters[name]
        with self._conn() as conn:
            row = conn.execute("SELECT value FROM counters WHERE name=?", (name,)).fetchone()
            return row[0] if row else 0

    def get_events(self, event_type: Optional[str] = None,
                   since: Optional[str] = None, limit: int = 100) -> List[Dict]:
        with self._conn() as conn:
            if event_type and since:
                rows = conn.execute(
                    "SELECT * FROM events WHERE event_type=? AND timestamp>=? ORDER BY timestamp DESC LIMIT ?",
                    (event_type, since, limit)).fetchall()
            elif event_type:
                rows = conn.execute(
                    "SELECT * FROM events WHERE event_type=? ORDER BY timestamp DESC LIMIT ?",
                    (event_type, limit)).fetchall()
            else:
                rows = conn.execute(
                    "SELECT * FROM events ORDER BY timestamp DESC LIMIT ?", (limit,)).fetchall()
            return [{"id": r[0], "timestamp": r[1], "event_type": r[2],
                     "entity_type": r[3], "entity_id": r[4], "duration_ms": r[5],
                     "success": bool(r[6]), "error": r[7],
                     "metadata": json.loads(r[8]) if r[8] else {}} for r in rows]

    def summary(self) -> Dict[str, Any]:
        """Return a summary of all metrics for dashboards."""
        with self._conn() as conn:
            total = conn.execute("SELECT COUNT(*) FROM events").fetchone()[0]
            failures = conn.execute("SELECT COUNT(*) FROM events WHERE success=0").fetchone()[0]
            avg_duration = conn.execute("SELECT AVG(duration_ms) FROM events WHERE duration_ms > 0").fetchone()[0] or 0
            by_type = conn.execute(
                "SELECT event_type, COUNT(*), SUM(CASE WHEN success=0 THEN 1 ELSE 0 END), AVG(duration_ms) "
                "FROM events GROUP BY event_type"
            ).fetchall()
            return {
                "total_events": total,
                "total_failures": failures,
                "error_rate": failures / total if total > 0 else 0,
                "avg_duration_ms": round(avg_duration, 2),
                "by_type": [{"event_type": r[0], "count": r[1], "failures": r[2],
                             "avg_duration_ms": round(r[3] or 0, 2)} for r in by_type],
                "counters": dict(self._counters),
            }


class ObservabilitySystem:
    """
    Provides dashboards, logs, metrics, tracing, and execution history.

    Wraps MetricsCollector + structured logging + distributed tracing.
    Every task is traceable from start to finish.
    """

    def __init__(self):
        self.metrics = MetricsCollector()
        self._traces: Dict[str, List[Dict]] = defaultdict(list)  # trace_id → spans
        self._lock = threading.Lock()

    def start_trace(self, operation: str, parent_trace_id: Optional[str] = None) -> str:
        trace_id = parent_trace_id or str(uuid.uuid4())
        span = {
            "trace_id": trace_id, "span_id": str(uuid.uuid4()),
            "operation": operation, "start_time": time.monotonic(),
            "start_ts": datetime.now().isoformat(),
        }
        with self._lock:
            self._traces[trace_id].append(span)
        return trace_id

    def end_trace(self, trace_id: str, success: bool = True, error: str = "") -> None:
        with self._lock:
            spans = self._traces.get(trace_id, [])
            if spans:
                span = spans[-1]
                span["end_time"] = time.monotonic()
                span["duration_ms"] = (span["end_time"] - span["start_time"]) * 1000
                span["success"] = success
                span["error"] = error
                span["end_ts"] = datetime.now().isoformat()
                self.metrics.record_event(
                    "trace_span", entity_id=trace_id,
                    duration_ms=span["duration_ms"], success=success, error=error,
                    operation=span["operation"]
                )

    def get_trace(self, trace_id: str) -> List[Dict]:
        return self._traces.get(trace_id, [])

    def dashboard_data(self) -> Dict[str, Any]:
        """Aggregate data for the observability dashboard."""
        return {
            "metrics": self.metrics.summary(),
            "active_traces": len([t for t in self._traces.values() if t and "end_time" not in t[-1]]),
            "recent_events": self.metrics.get_events(limit=20),
        }


# ══════════════════════════════════════════════════════════════════════════════
# 5. PROJECT DETECTOR
# ══════════════════════════════════════════════════════════════════════════════
class ProjectDetector:
    """
    Auto-detects the technology stack of a project directory.

    Detects: language, framework, build system, package manager,
    test framework, deployment platform, CI/CD config.
    """

    _MARKERS = {
        # language → [filenames that indicate this language]
        "python": ["setup.py", "pyproject.toml", "requirements.txt", "Pipfile", "setup.cfg"],
        "node": ["package.json", "node_modules"],
        "rust": ["Cargo.toml"],
        "go": ["go.mod", "go.sum"],
        "java": ["pom.xml", "build.gradle", "build.gradle.kts"],
        "csharp": ["*.csproj", "*.sln"],
        "ruby": ["Gemfile", "Rakefile"],
        "php": ["composer.json"],
    }

    _FRAMEWORKS = {
        # filename → {marker_key: framework_name}
        "package.json": {"next": "Next.js", "react": "React", "vue": "Vue",
                         "angular": "Angular", "express": "Express",
                         "nuxt": "Nuxt", "svelte": "Svelte"},
        "requirements.txt": {"django": "Django", "flask": "Flask",
                             "fastapi": "FastAPI", "scrapy": "Scrapy"},
        "pyproject.toml": {"django": "Django", "flask": "Flask",
                           "fastapi": "FastAPI", "poetry": "Poetry"},
        "pom.xml": {"spring-boot": "Spring Boot"},
        "build.gradle": {"spring-boot": "Spring Boot"},
        "build.gradle.kts": {"spring-boot": "Spring Boot"},
        "*.csproj": {".net": ".NET", "Microsoft.NET.Sdk.Web": "ASP.NET Core"},
    }

    _PACKAGE_MANAGERS = {
        "python": ["pip", "poetry", "pipenv", "conda"],
        "node": ["npm", "yarn", "pnpm"],
        "rust": ["cargo"],
        "go": ["go mod"],
        "java": ["maven", "gradle"],
        "ruby": ["bundler"],
        "php": ["composer"],
    }

    _TEST_FRAMEWORKS = {
        "python": ["pytest", "unittest", "nose"],
        "node": ["jest", "mocha", "jasmine", "vitest"],
        "rust": ["cargo test"],
        "go": ["go test"],
        "java": ["junit", "testng"],
        "ruby": ["rspec", "minitest"],
    }

    _DEPLOY_TARGETS = {
        "Dockerfile": "Docker",
        "docker-compose.yml": "Docker Compose",
        "k8s": "Kubernetes",
        ".vercel": "Vercel",
        "netlify.toml": "Netlify",
        "serverless.yml": "Serverless",
        "terraform": "Terraform",
        ".github/workflows": "GitHub Actions",
    }

    def detect(self, project_dir: Path) -> Dict[str, Any]:
        """Detect the full technology stack of a project directory."""
        if not project_dir.exists() or not project_dir.is_dir():
            return {"error": f"Directory not found: {project_dir}"}

        result = {
            "directory": str(project_dir),
            "languages": [],
            "frameworks": [],
            "build_system": None,
            "package_managers": [],
            "test_frameworks": [],
            "deploy_targets": [],
            "ci_cd": None,
            "entry_points": [],
        }

        # Detect languages
        for lang, markers in self._MARKERS.items():
            for marker in markers:
                if "*" in marker:
                    if list(project_dir.glob(marker)):
                        result["languages"].append(lang)
                        break
                elif (project_dir / marker).exists():
                    result["languages"].append(lang)
                    break

        # Detect frameworks
        for filename, fw_map in self._FRAMEWORKS.items():
            filepath = project_dir / filename
            if "*" in filename:
                files = list(project_dir.glob(filename))
            else:
                files = [filepath] if filepath.exists() else []
            for f in files:
                try:
                    content = f.read_text(errors="ignore").lower()
                    for marker, fw_name in fw_map.items():
                        if marker.lower() in content:
                            if fw_name not in result["frameworks"]:
                                result["frameworks"].append(fw_name)
                except Exception:
                    pass

        # Detect build system
        if (project_dir / "package.json").exists():
            result["build_system"] = "npm/yarn"
        elif (project_dir / "Cargo.toml").exists():
            result["build_system"] = "cargo"
        elif (project_dir / "pom.xml").exists():
            result["build_system"] = "maven"
        elif (project_dir / "build.gradle").exists() or (project_dir / "build.gradle.kts").exists():
            result["build_system"] = "gradle"
        elif (project_dir / "Makefile").exists():
            result["build_system"] = "make"
        elif (project_dir / "pyproject.toml").exists():
            result["build_system"] = "poetry/setuptools"
        elif (project_dir / "setup.py").exists():
            result["build_system"] = "setuptools"
        elif (project_dir / "requirements.txt").exists():
            result["build_system"] = "pip"

        # Detect deploy targets
        for marker, target in self._DEPLOY_TARGETS.items():
            if (project_dir / marker).exists() or (project_dir / marker).is_dir():
                result["deploy_targets"].append(target)
        if (project_dir / ".github" / "workflows").is_dir():
            result["ci_cd"] = "GitHub Actions"

        # Detect entry points
        for ep in ["main.py", "app.py", "index.js", "index.ts", "main.go",
                    "src/main.rs", "src/main/java", "Program.cs"]:
            if (project_dir / ep).exists():
                result["entry_points"].append(ep)

        return result


# ══════════════════════════════════════════════════════════════════════════════
# 6. DEPLOYMENT ORCHESTRATOR
# ══════════════════════════════════════════════════════════════════════════════
class _DeploySafetyAgent(BaseAgent):
    """[V16.2-FIX-C5] Minimal agent for SafetyGate to check deploy actions.
    Not registered in the agent registry — only used internally."""
    name = "deploy"
    description = "Deployment safety check"
    capabilities = ["deploy"]
    destructive_actions = ["deploy"]

    def execute(self, action, params, context):
        return AgentResult(success=True, message="Deploy approved")


class DeploymentOrchestrator:
    """
    End-to-end deployment pipeline:
      detect → resolve deps → build → test → quality checks →
      package → deploy → health check → (rollback on failure)

    Uses the WorkflowEngine for durability (survives crashes).
    """

    def __init__(self, workflow_engine: WorkflowEngine,
                 project_detector: ProjectDetector,
                 safety_gate: Optional[SafetyGate] = None):
        self._engine = workflow_engine
        self._detector = project_detector
        self._safety = safety_gate

    def deploy(self, project_dir: str, target: str = "local",
               dry_run: bool = False, input_fn: Callable = input) -> Workflow:
        """Create and execute a deployment workflow."""
        project_path = Path(project_dir).expanduser()
        # Detect project type
        stack = self._detector.detect(project_path)
        logger.info(f"[DeploymentOrchestrator] detected stack: {stack}")

        wf = Workflow(
            name=f"deploy_{stack.get('languages', ['unknown'])[0]}_{target}",
            description=f"Deploy {project_path.name} to {target}"
        )
        wf.context["project_dir"] = str(project_path)
        wf.context["target"] = target
        wf.context["stack"] = stack
        wf.context["dry_run"] = dry_run

        # Step 0: Detect project
        wf.add_step("Detect Project Type", agent="", action="",
                     params={"stack": stack})
        # Step 1: Resolve dependencies
        wf.add_step("Resolve Dependencies", agent="terminal", action="run_command",
                     params=self._deps_command(stack, project_path),
                     depends_on=[0])
        # Step 2: Build
        wf.add_step("Build Application", agent="terminal", action="run_command",
                     params=self._build_command(stack, project_path),
                     depends_on=[1])
        # Step 3: Run tests
        wf.add_step("Run Tests", agent="terminal", action="run_command",
                     params=self._test_command(stack, project_path),
                     depends_on=[2])
        # Step 4: Package
        wf.add_step("Package Artifacts", agent="terminal", action="run_command",
                     params=self._package_command(stack, project_path, target),
                     depends_on=[3])
        # Step 5: Deploy
        wf.add_step(f"Deploy to {target}", agent="terminal", action="run_command",
                     params=self._deploy_command(stack, project_path, target),
                     depends_on=[4])
        # Step 6: Health check
        wf.add_step("Health Check", agent="terminal", action="run_command",
                     params=self._health_check_command(target),
                     depends_on=[5])
        # Step 7: Verify (conditional — only if health check passed)
        wf.add_step("Verify Deployment", agent="", action="",
                     depends_on=[6],
                     condition="step_6_result and 'ok' in step_6_result.lower()")

        # Safety gate for destructive deploy
        if self._safety and not dry_run:
            print(f"\n🚀  Deployment Plan for {project_path.name} → {target}:")
            for i, step in enumerate(wf.steps):
                print(f"   {i}. {step.name}")
            print(f"\n   Stack: {stack.get('languages', [])} / {stack.get('frameworks', [])}")
            if self._safety and not self._safety.check(_DeploySafetyAgent(), "deploy", {"project": str(project_path), "target": target}):
                wf.state = WorkflowState.CANCELLED
                return wf

        return self._engine.execute(wf, input_fn=input_fn)

    def rollback(self, workflow_id: str, input_fn: Callable = input) -> Optional[Workflow]:
        """Roll back a failed deployment to the last checkpoint."""
        wf = self._engine.load(workflow_id)
        if not wf:
            return None
        logger.info(f"[DeploymentOrchestrator] rolling back workflow {workflow_id}")
        # Mark completed steps as rolled_back
        for step in reversed(wf.steps):
            if step.state == TaskState.COMPLETED and step.checkpoint:
                # Restore context from checkpoint
                wf.context = step.checkpoint.get("context", wf.context)
                step.state = TaskState.ROLLED_BACK
                logger.info(f"[DeploymentOrchestrator] rolled back step {step.step_index}: {step.name}")
        wf.state = WorkflowState.ROLLED_BACK
        self._engine.save(wf)
        return wf

    def _deps_command(self, stack: Dict, path: Path) -> Dict:
        langs = stack.get("languages", [])
        if "python" in langs:
            return {"command": f"cd {path} && pip install -r requirements.txt 2>&1 || pip install -e . 2>&1"}
        if "node" in langs:
            return {"command": f"cd {path} && npm install 2>&1"}
        if "rust" in langs:
            return {"command": f"cd {path} && cargo fetch 2>&1"}
        if "go" in langs:
            return {"command": f"cd {path} && go mod download 2>&1"}
        return {"command": "echo 'No dependency resolution needed'"}

    def _build_command(self, stack: Dict, path: Path) -> Dict:
        langs = stack.get("languages", [])
        if "node" in langs:
            return {"command": f"cd {path} && npm run build 2>&1 || echo 'No build script'"}
        if "rust" in langs:
            return {"command": f"cd {path} && cargo build --release 2>&1"}
        if "go" in langs:
            return {"command": f"cd {path} && go build ./... 2>&1"}
        if "java" in langs:
            return {"command": f"cd {path} && mvn package 2>&1 || gradle build 2>&1"}
        return {"command": "echo 'No build step needed'"}

    def _test_command(self, stack: Dict, path: Path) -> Dict:
        langs = stack.get("languages", [])
        if "python" in langs:
            return {"command": f"cd {path} && python -m pytest 2>&1 || python -m unittest discover 2>&1"}
        if "node" in langs:
            return {"command": f"cd {path} && npm test 2>&1"}
        if "rust" in langs:
            return {"command": f"cd {path} && cargo test 2>&1"}
        if "go" in langs:
            return {"command": f"cd {path} && go test ./... 2>&1"}
        return {"command": "echo 'No test step'"}

    def _package_command(self, stack: Dict, path: Path, target: str) -> Dict:
        if target == "docker":
            return {"command": f"cd {path} && docker build -t {path.name} . 2>&1"}
        return {"command": "echo 'No packaging needed'"}

    def _deploy_command(self, stack: Dict, path: Path, target: str) -> Dict:
        if target == "local":
            return {"command": f"cd {path} && echo 'Deploying locally'"}
        if target == "docker":
            return {"command": f"cd {path} && docker run -d --name {path.name} {path.name} 2>&1"}
        if target == "k8s":
            return {"command": f"cd {path} && kubectl apply -f k8s/ 2>&1 || echo 'No k8s manifests'"}
        return {"command": f"echo 'Deploy to {target}'"}

    def _health_check_command(self, target: str) -> Dict:
        if target == "docker":
            return {"command": "docker ps --filter 'status=running' --format '{{.Names}}' 2>&1"}
        if target == "k8s":
            return {"command": "kubectl get pods --field-selector='status.phase=Running' 2>&1"}
        return {"command": "echo 'ok'"}


# ══════════════════════════════════════════════════════════════════════════════
# 7. AUTONOMOUS RECOVERY
# ══════════════════════════════════════════════════════════════════════════════
class RecoveryStrategy:
    """Base class for recovery strategies."""
    name = "base"

    def can_recover(self, step: WorkflowStep, error: str) -> bool:
        return False

    def recover(self, step: WorkflowStep, workflow: Workflow,
                engine: "WorkflowEngine") -> bool:
        return False


class RetryStrategy(RecoveryStrategy):
    """Retry the step with exponential backoff."""
    name = "retry"

    def can_recover(self, step: WorkflowStep, error: str) -> bool:
        return step.attempts < step.max_retries

    def recover(self, step: WorkflowStep, workflow: Workflow,
                engine: "WorkflowEngine") -> bool:
        step.attempts += 1
        step.state = TaskState.PENDING
        time.sleep(2 ** step.attempts)
        logger.info(f"[Recovery:retry] retrying step {step.step_index} (attempt {step.attempts})")
        return True


class RollbackStrategy(RecoveryStrategy):
    """Roll back completed steps to their checkpoints."""
    name = "rollback"

    def can_recover(self, step: WorkflowStep, error: str) -> bool:
        return "deploy" in step.name.lower() or "build" in step.name.lower()

    def recover(self, step: WorkflowStep, workflow: Workflow,
                engine: "WorkflowEngine") -> bool:
        logger.info(f"[Recovery:rollback] rolling back workflow to checkpoint before step {step.step_index}")
        for prev_step in reversed(workflow.steps[:step.step_index]):
            if prev_step.state == TaskState.COMPLETED and prev_step.checkpoint:
                workflow.context = prev_step.checkpoint.get("context", workflow.context)
                prev_step.state = TaskState.ROLLED_BACK
        engine.save(workflow)
        return True


class AlternativePathStrategy(RecoveryStrategy):
    """Try an alternative execution path (e.g., different build command)."""
    name = "alternative_path"

    def can_recover(self, step: WorkflowStep, error: str) -> bool:
        return "command" in step.params and ("not found" in error.lower() or "no such" in error.lower())

    def recover(self, step: WorkflowStep, workflow: Workflow,
                engine: "WorkflowEngine") -> bool:
        # Try a fallback command
        original = step.params.get("command", "")
        step.params["command"] = f"echo 'Fallback for: {original[:50]}'"
        step.state = TaskState.PENDING
        logger.info(f"[Recovery:alt-path] trying alternative command for step {step.step_index}")
        return True


class AutonomousRecovery:
    """
    Coordinates recovery strategies. When a step fails, tries strategies
    in order: retry → alternative path → rollback → escalate to user.
    """

    def __init__(self):
        self._strategies: List[RecoveryStrategy] = [
            RetryStrategy(),
            AlternativePathStrategy(),
            RollbackStrategy(),
        ]
        self._escalation_fn: Optional[Callable] = None

    def set_escalation_fn(self, fn: Callable) -> None:
        self._escalation_fn = fn

    def attempt_recovery(self, step: WorkflowStep, workflow: Workflow,
                         engine: "WorkflowEngine", error: str) -> bool:
        """Try to recover from a failed step. Returns True if recovered."""
        for strategy in self._strategies:
            if strategy.can_recover(step, error):
                logger.info(f"[AutonomousRecovery] trying strategy: {strategy.name}")
                if strategy.recover(step, workflow, engine):
                    return True
        # No strategy worked — escalate to user
        if self._escalation_fn:
            logger.warning(f"[AutonomousRecovery] escalating to user for step {step.step_index}")
            return self._escalation_fn(step, workflow, error)
        return False


# ══════════════════════════════════════════════════════════════════════════════
# 8. ADVANCED PLANNER (upgraded PlannerAgent)
# ══════════════════════════════════════════════════════════════════════════════
class AdvancedPlanner:
    """
    Upgraded planner that creates durable workflows with:
      • Sequential, parallel, and conditional execution
      • Dependency estimation
      • Dynamic replanning on failure
      • Result merging from multiple agents
    """

    def __init__(self, ai_gateway: "AIGateway", workflow_engine: WorkflowEngine):
        self._ai = ai_gateway
        self._engine = workflow_engine

    def create_workflow(self, user_request: str,
                        available_agents: List[str]) -> Optional[Workflow]:
        """Ask the LLM to create a workflow plan, then build a Workflow object."""
        prompt = (
            f"Create a step-by-step execution plan for this request.\n"
            f"Request: {user_request}\n\n"
            f"Available agents: {', '.join(available_agents)}\n\n"
            f"Respond with JSON:\n"
            f'{{"workflow_name": "...", "description": "...", "steps": ['
            f'{{"name": "...", "agent": "...", "action": "...", "params": {{}}, '
            f'"depends_on": [], "condition": ""}}]}}\n\n'
            f"Use depends_on (list of step indices) for parallel execution.\n"
            f"Use condition (Python expr) for conditional steps.\n"
            f"Return ONLY the JSON."
        )
        try:
            ok, response = self._ai.chat(prompt, max_tokens=800)
            if not ok:
                return None
            plan = _extract_json(response)
            if not plan or "steps" not in plan:
                return None
            wf = Workflow(plan.get("workflow_name", "unnamed"),
                         plan.get("description", ""))
            for s in plan["steps"]:
                wf.add_step(
                    name=s.get("name", "unnamed step"),
                    agent=s.get("agent", ""),
                    action=s.get("action", ""),
                    params=s.get("params", {}),
                    depends_on=s.get("depends_on", []),
                    condition=s.get("condition", ""),
                )
            return wf
        except Exception as exc:
            logger.warning(f"[AdvancedPlanner] create_workflow failed: {exc}")
            return None

    def replan(self, workflow: Workflow, failed_step_index: int,
               error: str) -> Optional[Workflow]:
        """Dynamically replan after a step fails."""
        prompt = (
            f"A workflow step failed. Replan the remaining steps.\n"
            f"Workflow: {workflow.name}\n"
            f"Failed step {failed_step_index}: {workflow.steps[failed_step_index].name}\n"
            f"Error: {error}\n"
            f"Completed steps: {[i for i, s in enumerate(workflow.steps) if s.state == TaskState.COMPLETED]}\n\n"
            f"Respond with JSON for the REMAINING steps only:\n"
            f'{{"steps": [{{"name": "...", "agent": "...", "action": "...", '
            f'"params": {{}}, "depends_on": [], "condition": ""}}]}}'
        )
        try:
            ok, response = self._ai.chat(prompt, max_tokens=600)
            if not ok:
                return None
            plan = _extract_json(response)
            if not plan or "steps" not in plan:
                return None
            # Replace failed step and all subsequent steps
            new_wf = Workflow(f"{workflow.name}_replanned",
                             f"Replanned after step {failed_step_index} failed",
                             parent_workflow_id=workflow.id)
            new_wf.context = workflow.context
            for s in plan["steps"]:
                new_wf.add_step(
                    name=s.get("name", "unnamed"),
                    agent=s.get("agent", ""),
                    action=s.get("action", ""),
                    params=s.get("params", {}),
                    depends_on=s.get("depends_on", []),
                    condition=s.get("condition", ""),
                )
            return new_wf
        except Exception as exc:
            logger.warning(f"[AdvancedPlanner] replan failed: {exc}")
            return None


# ══════════════════════════════════════════════════════════════════════════════
# LLM CENTRAL BRAIN — Natural Language → Structured Action Plan
# ══════════════════════════════════════════════════════════════════════════════
class LLMBrain:
    """
    Uses the active LLM (Ollama/OpenAI/Claude) as the central intelligence
    for understanding complex, ambiguous, or multi-step commands.

    Design:
    • Builds a tight system prompt describing all available ARJUN capabilities
    • Sends the user's command and expects a JSON TaskSpec back
    • Validates the JSON schema before accepting it
    • Falls back gracefully if the LLM is unavailable or returns invalid JSON
    • Caches last 128 results (normalized key → TaskSpec) to avoid re-querying

    Integration:
    • Called by UniversalCommandPipeline when AIBrain confidence < MIN_CONF
    • Produces a TaskSpec identical to what AIBrain produces
    • The rest of the pipeline (executor → verify → memory → SSE) is unchanged
    """

    SYSTEM_PROMPT = """You are ARJUN's Central AI Brain. Your ONLY job is to parse a user command into a structured JSON action plan.

RESPOND WITH VALID JSON ONLY. No prose, no explanation, no markdown fences.

JSON schema (all fields required):
{
  "intent":    string,   // one of: change_volume|change_brightness|file_search|
                         // file_move|file_copy|file_cut|file_paste|file_organize|
                         // file_categorize|open_app|close_app|web_search|system_info|
                         // power_action|timer|reminder|notes|habits|weather|crypto|
                         // generate_qr|color_info|convert|network|password|help|
                         // pomodoro|query_time|query_unix_time|convert_epoch|
                         // query_world_time|close_browser_window|ai_query
  "domain":    string,   // system_audio|system_display|file_manager|browser|
                         // application|productivity|utility|network|security|
                         // weather|crypto|system_info|system_power|meta|ai
  "task":      string,   // specific action verb (e.g. "set_volume", "search_files")
  "parameters": object,  // extracted values: {value, unit, src, dst, query, app_name, ...}
  "executor":  string,   // audio_ctrl|display_ctrl|file_ctrl|browser_ctrl|
                         // app_ctrl|timer_ctrl|notes_ctrl|habits_ctrl|
                         // network_ctrl|security_ctrl|weather_ctrl|crypto_ctrl|
                         // clock_ctrl|utility_ctrl|pomodoro_ctrl|meta_ctrl|ai_ctrl
  "confidence": number,  // 0.0–1.0 how confident you are
  "reasoning":  string   // brief (≤ 15 words) reason for your classification
}

Examples:
User: "find all pdf files in my downloads"
{"intent":"file_search","domain":"file_manager","task":"search_files",
 "parameters":{"query":"","ext":"pdf","root":"downloads"},"executor":"file_ctrl",
 "confidence":0.97,"reasoning":"User wants to search downloads for PDFs"}

User: "move my resume to desktop"
{"intent":"file_move","domain":"file_manager","task":"move_file",
 "parameters":{"query":"resume","dst":"desktop"},"executor":"file_ctrl",
 "confidence":0.92,"reasoning":"Move file named resume to Desktop"}

User: "organize my downloads by file type"
{"intent":"file_organize","domain":"file_manager","task":"organize_files",
 "parameters":{"root":"downloads","mode":"type"},"executor":"file_ctrl",
 "confidence":0.98,"reasoning":"Organize downloads folder by extension type"}

User: "close the private window"
{"intent":"close_browser_window","domain":"browser","task":"close_private_window",
 "parameters":{"window_type":"private"},"executor":"browser_ctrl",
 "confidence":0.99,"reasoning":"Close private/incognito browser window"}

User: "set volume to fifty"
{"intent":"change_volume","domain":"system_audio","task":"set_volume",
 "parameters":{"value":50,"unit":"percent","mode":"absolute"},"executor":"audio_ctrl",
 "confidence":0.99,"reasoning":"Set volume to 50 percent"}

Be liberal with parameter extraction. When a file name or path is implied but not fully specified, set "query" to the partial name so ARJUN can search first."""

    _VALID_INTENTS = frozenset({
        "change_volume","change_brightness","file_search","file_move","file_copy",
        "file_cut","file_paste","file_organize","file_categorize","open_app",
        "close_app","web_search","system_info","power_action","timer","reminder",
        "notes","habits","weather","crypto","generate_qr","color_info","convert",
        "network","password","help","pomodoro","query_time","query_unix_time",
        "convert_epoch","query_world_time","close_browser_window","ai_query",
    })
    _VALID_EXECUTORS = frozenset({
        "audio_ctrl","display_ctrl","file_ctrl","browser_ctrl","app_ctrl",
        "timer_ctrl","notes_ctrl","habits_ctrl","network_ctrl","security_ctrl",
        "weather_ctrl","crypto_ctrl","clock_ctrl","utility_ctrl","pomodoro_ctrl",
        "meta_ctrl","ai_ctrl",
    })

    def __init__(self, ai_gateway: "AIGateway"):
        self._ai   = ai_gateway
        self._cache: Dict[str, TaskSpec] = {}
        self._order: List[str] = []
        self._lock = threading.Lock()
        self._CACHE_MAX = 128
        self._available: Optional[bool] = None   # None = untested yet

    def _test_availability(self) -> bool:
        # [REFACTOR] Consolidated to module-level test_llm_availability()
        return test_llm_availability(self._ai)

    def understand(self, normalized: str, raw: str = "") -> Optional[TaskSpec]:
        """
        Send normalized command to LLM and parse the JSON TaskSpec response.
        Returns None if LLM unavailable or returns invalid JSON.
        """
        # Lazy availability check
        if self._available is None:
            self._available = self._test_availability()
        if not self._available:
            return None

        key = normalized.strip().lower()
        with self._lock:
            if key in self._cache:
                return self._cache[key]

        prompt = f'User command: "{normalized}"'
        try:
            ok, response = self._ai.chat(
                prompt,
                system=self.SYSTEM_PROMPT,
                max_tokens=300,
            )
            if not ok or not response:
                return None

            # [V14.2-FIX-H6] use robust JSON extractor
            data = _extract_json(response)
            if data is None:
                logger.debug("[LLMBrain] JSON parse failed | raw=%r", response)
                return None
        except Exception as exc:
            logger.debug("[LLMBrain] parse failed: %s", exc)
            return None

        # Validate schema
        intent   = str(data.get("intent",   "ai_query"))
        domain   = str(data.get("domain",   "ai"))
        task     = str(data.get("task",     "query_ai"))
        params   = data.get("parameters", {})
        executor = str(data.get("executor", "ai_ctrl"))
        conf     = float(data.get("confidence", 0.5))

        if intent not in self._VALID_INTENTS:
            intent = "ai_query"
        if executor not in self._VALID_EXECUTORS:
            executor = "ai_ctrl"
        if not isinstance(params, dict):
            params = {}

        spec = TaskSpec(
            intent=intent, domain=domain, task=task,
            parameters=params, executor=executor,
            confidence=min(max(conf, 0.0), 1.0),
            verification_required=intent in (
                "change_volume","change_brightness","file_move","file_copy",
                "file_paste","file_organize","power_action"
            ),
            raw_input=raw,
            normalized_input=normalized,
        )

        with self._lock:
            self._cache[key] = spec
            self._order.append(key)
            if len(self._order) > self._CACHE_MAX:
                evict = self._order.pop(0)
                self._cache.pop(evict, None)

        logger.info("[LLMBrain] %s/%s conf=%.2f params=%s", intent, task, conf, params)
        return spec


# ══════════════════════════════════════════════════════════════════════════════
# 15. MODULE I — Screen Operations
# ══════════════════════════════════════════════════════════════════════════════
class ScreenOps:
    """Screenshot, screen recording trigger, scrolling, mouse/keyboard ops."""

    @safe_exec()
    def screenshot(self, name: str = None, region=None) -> Tuple[bool, str]:
        ts    = datetime.now().strftime("%Y%m%d_%H%M%S")
        fname = name or f"screenshot_{ts}.png"
        out   = HOME / fname

        if PAG_OK:
            img = pyautogui.screenshot(region=region)
            img.save(str(out))
            logger.info(f"Screenshot: {out}")
            return True, f"Screenshot saved: {fname}"

        # Fallback to OS tools
        if IS_WINDOWS:
            subprocess.run(
                ["powershell", "-Command",
                 f"Add-Type -AssemblyName System.Windows.Forms;"
                 f"$bmp=New-Object System.Drawing.Bitmap("
                 f"[System.Windows.Forms.SystemInformation]::VirtualScreen.Width,"
                 f"[System.Windows.Forms.SystemInformation]::VirtualScreen.Height);"
                 f"$g=[System.Drawing.Graphics]::FromImage($bmp);"
                 f"$g.CopyFromScreen(0,0,0,0,$bmp.Size);"
                 f"$bmp.Save('{out}')"],
                creationflags=_NO_WIN_FLAG, timeout=15
            )
        elif IS_MACOS:
            subprocess.run(["screencapture", str(out)])
        else:
            # [FIX-SCREENSHOT] Try multiple Linux screenshot tools in order.
            # scrot, gnome-screenshot, import (ImageMagick), xwd — use whichever is installed.
            taken = False
            for tool in ["scrot", "gnome-screenshot", "import", "xwd"]:
                tool_path = shutil.which(tool)
                if not tool_path:
                    continue
                try:
                    if tool == "gnome-screenshot":
                        subprocess.run([tool_path, "-f", str(out)], timeout=15)
                    elif tool == "import":
                        subprocess.run([tool_path, "-window", "root", str(out)], timeout=15)
                    elif tool == "xwd":
                        # xwd produces XWD format; convert to PNG via ImageMagick convert
                        xwd_tmp = str(out) + ".xwd"
                        subprocess.run([tool_path, "-root", "-silent", "-out", xwd_tmp], timeout=15)
                        convert_path = shutil.which("convert")
                        if convert_path:
                            subprocess.run([convert_path, xwd_tmp, str(out)], timeout=10)
                            Path(xwd_tmp).unlink(missing_ok=True)
                        else:
                            Path(xwd_tmp).unlink(missing_ok=True)
                            continue
                    else:
                        subprocess.run([tool_path, str(out)], timeout=15)
                    taken = True
                    break
                except Exception as tool_err:
                    logger.debug(f"Screenshot tool {tool} failed: {tool_err}")
            if not taken:
                return False, ("Screenshot not available — install scrot, gnome-screenshot, "
                               "or imagemagick (sudo apt install scrot)")
        return True, f"Screenshot saved: {fname}"

    @safe_exec()
    def scroll(self, direction: str, amount: int = 3) -> Tuple[bool, str]:
        direction = direction.lower().strip()
        amount    = max(1, int(amount))

        if PAG_OK:
            if direction == "up":
                pyautogui.scroll(amount)
            elif direction == "down":
                pyautogui.scroll(-amount)
            elif direction == "left":
                pyautogui.hscroll(-amount)
            elif direction == "right":
                pyautogui.hscroll(amount)
            else:
                return False, f"Unknown scroll direction: {direction}"
            return True, f"Scrolled {direction} by {amount}"

        key_map = {"up": "pageup", "down": "pagedown", "left": "left", "right": "right"}
        if KB_OK and direction in key_map:
            for _ in range(amount):
                keyboard.press_and_release(key_map[direction])
            return True, f"Scrolled {direction}"

        return False, "Scroll not available (install pyautogui)"

    @safe_exec()
    def scroll_to_top(self) -> Tuple[bool, str]:
        if PAG_OK:
            pyautogui.hotkey("ctrl", "home")
            return True, "Scrolled to top"
        return False, "pyautogui not available"

    @safe_exec()
    def scroll_to_bottom(self) -> Tuple[bool, str]:
        if PAG_OK:
            pyautogui.hotkey("ctrl", "end")
            return True, "Scrolled to bottom"
        return False, "pyautogui not available"

    @safe_exec()
    def start_recording(self) -> Tuple[bool, str]:
        if PAG_OK:
            pyautogui.hotkey("win", "g")
            return True, "Opened Xbox Game Bar for recording"
        return False, "Press Win+G manually to open Game Bar"

    @safe_exec()
    def type_text(self, text: str) -> Tuple[bool, str]:
        if PAG_OK:
            pyautogui.typewrite(text, interval=0.03)
            return True, f"Typed: {text[:30]}..."
        return False, "pyautogui not available"

    @safe_exec()
    def click(self, x: int = None, y: int = None, button: str = "left") -> Tuple[bool, str]:
        if not PAG_OK:
            return False, "pyautogui not available"
        if x and y:
            pyautogui.click(x, y, button=button)
        else:
            pyautogui.click(button=button)
        return True, f"Clicked {button}"

    @safe_exec()
    def hotkey(self, *keys) -> Tuple[bool, str]:
        if not PAG_OK:
            return False, "pyautogui not available"
        pyautogui.hotkey(*keys)
        return True, f"Hotkey: {'+'.join(keys)}"


# ══════════════════════════════════════════════════════════════════════════════
# 16. MODULE J — Browser Controller
# ══════════════════════════════════════════════════════════════════════════════
class BrowserController:
    """
    [m-1] FIX: duplicate_tab now correctly presses Ctrl+L to focus the address
    bar, then Enter to navigate to the same URL — effectively duplicating the tab.
    The original code only did Ctrl+L (focus) without the Enter keystroke.

    [v4.0] NEW: open_in_browser() detects installed browsers and opens
    browser-specific pages (history, settings, downloads, bookmarks, devtools)
    in the requested browser by launching it with the correct URL/flag.
    Browser URLs (chrome-specific, brave uses same):
      history   → chrome://history
      downloads → chrome://downloads
      settings  → chrome://settings
      bookmarks → chrome://bookmarks
      extensions→ chrome://extensions
      devtools  → F12 (keyboard only; cannot open via URL directly)
    Firefox uses about: protocol, Edge uses edge:// protocol.

    [FIX-V11] Every hotkey method now goes through self.session.send_hotkey
    which focuses the browser BEFORE sending the shortcut. This fixes the
    long-standing bug where "open history in Brave" / "close tab" /
    "open new tab" would either do nothing or hit the wrong application
    because Brave wasn't focused.

    The legacy bare-hotkey methods (new_tab, close_tab, refresh, etc.) are
    kept for backward compat with the rest of the codebase but they now
    target the last-detected browser (set via set_active_browser()) or
    fall back to "brave".
    """

    _DEFAULT_BROWSER = "brave"

    # Internal pages per browser engine
    _BROWSER_INTERNAL = {
        "chrome":  {
            "history":    "chrome://history",
            "downloads":  "chrome://downloads",
            "settings":   "chrome://settings",
            "bookmarks":  "chrome://bookmarks",
            "extensions": "chrome://extensions",
            "newtab":     "chrome://newtab",
            "flags":      "chrome://flags",
            "task manager": None,  # keyboard only
        },
        "brave": {
            "history":    "brave://history",
            "downloads":  "brave://downloads",
            "settings":   "brave://settings",
            "bookmarks":  "brave://bookmarks",
            "extensions": "brave://extensions",
            "newtab":     "brave://newtab",
            "flags":      "brave://flags",
        },
        "edge": {
            "history":    "edge://history",
            "downloads":  "edge://downloads",
            "settings":   "edge://settings",
            "bookmarks":  "edge://bookmarks",
            "extensions": "edge://extensions",
            "newtab":     "edge://newtab",
            "flags":      "edge://flags",
        },
        "firefox": {
            "history":    None,   # Firefox: Ctrl+H shortcut
            "downloads":  "about:downloads",
            "settings":   "about:preferences",
            "bookmarks":  None,   # Firefox: Ctrl+Shift+B
            "extensions": "about:addons",
            "newtab":     "about:newtab",
        },
    }

    _BROWSER_PATHS = {
        "brave": [
            r"C:\Program Files\BraveSoftware\Brave-Browser\Application\brave.exe",
            r"C:\Program Files (x86)\BraveSoftware\Brave-Browser\Application\brave.exe",
            "/usr/bin/brave-browser",
            "/Applications/Brave Browser.app/Contents/MacOS/Brave Browser",
        ],
        "chrome": [
            r"C:\Program Files\Google\Chrome\Application\chrome.exe",
            r"C:\Program Files (x86)\Google\Chrome\Application\chrome.exe",
            "/usr/bin/google-chrome",
            "/usr/bin/chromium-browser",
            "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome",
        ],
        "edge": [
            r"C:\Program Files (x86)\Microsoft\Edge\Application\msedge.exe",
            r"C:\Program Files\Microsoft\Edge\Application\msedge.exe",
            "/usr/bin/microsoft-edge",
            "/Applications/Microsoft Edge.app/Contents/MacOS/Microsoft Edge",
        ],
        "firefox": [
            r"C:\Program Files\Mozilla Firefox\firefox.exe",
            r"C:\Program Files (x86)\Mozilla Firefox\firefox.exe",
            "/usr/bin/firefox",
            "/Applications/Firefox.app/Contents/MacOS/firefox",
        ],
    }

    def _find_browser_exe(self, name: str) -> Optional[str]:
        """Find browser executable on disk; return None if not installed."""
        n = name.lower().strip()
        aliases = {
            "microsoft edge": "edge", "google chrome": "chrome",
            "brave browser": "brave", "mozilla firefox": "firefox",
        }
        n = aliases.get(n, n)
        for p in self._BROWSER_PATHS.get(n, []):
            if "*" in p:
                m = glob.glob(p)
                if m:
                    return m[0]
            elif os.path.exists(p):
                return p
        return shutil.which(n)

    def __init__(self) -> None:
        # FIX-V11: each BrowserController owns a BrowserSessionManager so
        # every command focuses the browser before sending hotkeys.
        self.session = BrowserSessionManager()
        self._active_browser = self._DEFAULT_BROWSER

    def set_active_browser(self, browser: str) -> None:
        """Remember which browser the user is currently controlling.
        Called by the intent parser whenever a browser name is detected.
        """
        self._active_browser = self.session.normalize(browser)

    def open_in_browser(self, page: str, browser: str = "brave") -> Tuple[bool, str]:
        """
        [FIX-V11] Open a browser internal page (history, settings, downloads…)
        in the specified browser.

        New strategy (delegates to BrowserSessionManager):
          • If browser is running → focus it, send hotkey (Ctrl+H/J/Shift+O/T)
            for pages with shortcuts, or Ctrl+L + type URL + Enter for pages
            without shortcuts. NEVER spawns a new browser process.
          • If browser is NOT running → launch it with --new-tab <URL> so it
            opens as a single tab in a single fresh window.
        """
        browser = self.session.normalize(browser)
        self._active_browser = browser
        page    = page.lower().strip().replace(" ", "")
        # Normalise page aliases
        page_aliases = {
            "newtab": "newtab", "new tab": "newtab",
            "dev": "devtools", "developer": "devtools",
            "ext": "extensions", "add-ons": "extensions", "addons": "extensions",
        }
        page = page_aliases.get(page, page)

        # Special case: devtools = F12 key
        if page in ("devtools", "developer tools"):
            return self.session.send_hotkey(browser, "f12")

        url = (self._BROWSER_INTERNAL.get(browser) or {}).get(page)

        # Map of pages → keyboard shortcuts (Chromium defaults; Firefox
        # differences handled inside _firefox_hotkey).
        hotkey_map = {
            "history":   ("ctrl", "h"),
            "downloads": ("ctrl", "j"),
            "bookmarks": ("ctrl", "shift", "o"),
            "extensions":("ctrl", "shift", "e"),
            "newtab":    ("ctrl", "t"),
        }
        if browser == "firefox":
            # Firefox uses different shortcuts for history/bookmarks
            hotkey_map["history"]   = ("ctrl", "h")
            hotkey_map["bookmarks"] = ("ctrl", "shift", "b")

        running = self.session.is_running(browser)

        # ── Path 1: browser is running → focus + hotkey (or focus + URL) ──
        if running:
            if page in hotkey_map:
                return self.session.send_hotkey(browser, *hotkey_map[page])
            if url:
                # Page like "settings" with no shortcut → open as URL in
                # the current window via Ctrl+L → type → Enter.
                return self.session.open_url_in_existing(browser, url)
            # Page not recognized
            return False, f"Cannot open '{page}' in running {browser.title()}"

        # ── Path 2: browser NOT running → launch with --new-tab URL ──
        if url:
            return self.session.launch_with_url(browser, url)
        # Page has no URL (e.g. keyboard-only) → just launch the browser
        exe = self._find_browser_exe(browser) or self.session.find_exe(browser)
        if exe:
            try:
                subprocess.Popen([exe], creationflags=_NO_WIN_FLAG)
                time.sleep(1.0)
                # After launch, send the hotkey if we have one
                if page in hotkey_map:
                    return self.session.send_hotkey(browser, *hotkey_map[page])
                return True, f"Launched {browser.title()}"
            except OSError as exc:
                return False, f"Failed to launch {browser.title()}: {exc}"
        return False, f"{browser.title()} is not installed"

    # [REFACTOR] _hk consolidated to module-level send_hotkey().
    # Kept as a thin delegate for backward compat with existing callers.
    def _hk(self, *k) -> Tuple[bool, str]:
        """Legacy direct-hotkey (no focus). Kept for backward compat.
        Prefer session.send_hotkey for all new code.
        """
        return send_hotkey(*k)

    # ── FIX-V11: All hotkey methods now focus the active browser first ──
    # The intent parser calls set_active_browser() whenever it detects a
    # browser name in the command, so these methods always target the right
    # window. If no browser was explicitly detected, they default to Brave.

    def new_tab(self):          return self.session.send_hotkey(self._active_browser, "ctrl", "t")
    def close_tab(self):        return self.session.send_hotkey(self._active_browser, "ctrl", "w")
    def reopen_tab(self):       return self.session.send_hotkey(self._active_browser, "ctrl", "shift", "t")
    def refresh(self):          return self.session.send_hotkey(self._active_browser, "ctrl", "r")
    def hard_refresh(self):     return self.session.send_hotkey(self._active_browser, "ctrl", "shift", "r")
    def go_back(self):          return self.session.send_hotkey(self._active_browser, "alt", "left")
    def go_forward(self):       return self.session.send_hotkey(self._active_browser, "alt", "right")
    def open_history(self):     return self.session.send_hotkey(self._active_browser, "ctrl", "h")
    def open_downloads(self):   return self.session.send_hotkey(self._active_browser, "ctrl", "j")
    def zoom_in(self):          return self.session.send_hotkey(self._active_browser, "ctrl", "+")
    def zoom_out(self):         return self.session.send_hotkey(self._active_browser, "ctrl", "-")
    def zoom_reset(self):       return self.session.send_hotkey(self._active_browser, "ctrl", "0")
    def find_on_page(self):     return self.session.send_hotkey(self._active_browser, "ctrl", "f")
    def open_devtools(self):    return self.session.send_hotkey(self._active_browser, "f12")
    def view_source(self):      return self.session.send_hotkey(self._active_browser, "ctrl", "u")
    def focus_address_bar(self):return self.session.send_hotkey(self._active_browser, "ctrl", "l")
    def bookmark_page(self):    return self.session.send_hotkey(self._active_browser, "ctrl", "d")
    def open_bookmarks(self):
        if self._active_browser == "firefox":
            return self.session.send_hotkey(self._active_browser, "ctrl", "shift", "b")
        return self.session.send_hotkey(self._active_browser, "ctrl", "shift", "o")
    def fullscreen(self):       return self.session.send_hotkey(self._active_browser, "f11")
    def print_page(self):       return self.session.send_hotkey(self._active_browser, "ctrl", "p")
    def save_page(self):        return self.session.send_hotkey(self._active_browser, "ctrl", "s")
    def next_tab(self):         return self.session.send_hotkey(self._active_browser, "ctrl", "tab")
    def prev_tab(self):         return self.session.send_hotkey(self._active_browser, "ctrl", "shift", "tab")
    def mute_tab(self):         return self.session.send_hotkey(self._active_browser, "ctrl", "m")
    def scroll_up(self):        return self.session.send_hotkey(self._active_browser, "pageup")
    def scroll_down(self):      return self.session.send_hotkey(self._active_browser, "pagedown")
    def scroll_top(self):       return self.session.send_hotkey(self._active_browser, "ctrl", "home")
    def scroll_bottom(self):    return self.session.send_hotkey(self._active_browser, "ctrl", "end")
