    def open_task_manager(self):return self.session.send_hotkey(self._active_browser, "shift", "esc")
    def reading_mode(self):     return self.session.send_hotkey(self._active_browser, "f9")

    def duplicate_tab(self) -> Tuple[bool, str]:
        """
        [BUG-6] FIX: True tab duplication = 5-step sequence.
        Ctrl+L (focus address bar) → Ctrl+C (copy URL) → Ctrl+T (new tab)
        → Ctrl+V (paste URL) → Enter (navigate).
        """
        if not PAG_OK:
            return False, "pyautogui not available"
        pyautogui.hotkey("ctrl", "l")
        time.sleep(0.1)
        pyautogui.hotkey("ctrl", "c")
        time.sleep(0.05)
        pyautogui.hotkey("ctrl", "t")
        time.sleep(0.2)
        pyautogui.hotkey("ctrl", "v")
        time.sleep(0.05)
        pyautogui.press("enter")
        return True, "Duplicated tab"


