# NEW MODULE — QR Code Generator  [R-10 FIX — class was documented, never built]
# ══════════════════════════════════════════════════════════════════════════════
class QRCodeGenerator:
    """
    Generate a QR code image from any text/URL.
    Strategy:
      1. Use the 'qrcode' pip package if available (best quality).
      2. Fall back to the goqr.me public REST API (no key needed).
      3. If both fail, return a friendly error message.
    """

    def generate(self, text: str) -> Tuple[bool, str]:
        """Save a QR PNG to ~/qr_<hash>.png and return the path."""
        if not text or not isinstance(text, str):
            return False, "Please provide text or a URL for the QR code"
        text = text.strip()
        fname = HOME / f"qr_{hashlib.md5(text.encode()).hexdigest()[:8]}.png"

        # Strategy 1: qrcode library
        try:
            import importlib
            qrcode_mod = importlib.import_module("qrcode")
            img = qrcode_mod.make(text)
            img.save(str(fname))
            print(f"\n📱  QR code saved: {fname}\n")
            return True, f"QR code saved: {fname.name}"
        except ImportError:
            pass
        except Exception as e:
            logger.debug(f"qrcode lib failed: {e}")

        # Strategy 2: goqr.me REST API
        try:
            encoded = quote_plus(text)
            url = f"https://api.qrserver.com/v1/create-qr-code/?size=300x300&data={encoded}"
            req = Request(url, headers={"User-Agent": "ARJUN/2.0"})
            with urlopen(req, timeout=10) as resp:
                data = resp.read()
            with open(str(fname), "wb") as fp:
                fp.write(data)
            print(f"\n📱  QR code saved: {fname}\n")
            return True, f"QR code saved: {fname.name}"
        except Exception as e:
            logger.debug(f"QR API failed: {e}")

        return False, "QR code generation unavailable. Install: pip install qrcode[pil]"


