# NEW MODULE — Color Converter  [F-10 FIX — documented but never implemented]
# ══════════════════════════════════════════════════════════════════════════════
class ColorConverter:
    """
    Convert between hex color codes and RGB/HSL and display color info.
    No external libraries needed — pure Python math.
    """

    @staticmethod
    def _hex_to_rgb(hex_str: str) -> Tuple[int, int, int]:
        h = hex_str.lstrip("#")
        if len(h) == 3:
            h = "".join(c * 2 for c in h)
        if len(h) != 6:
            raise ValueError(f"Invalid hex color: {hex_str!r}")
        return (int(h[0:2], 16), int(h[2:4], 16), int(h[4:6], 16))

    @staticmethod
    def _rgb_to_hsl(r: int, g: int, b: int) -> Tuple[float, float, float]:
        rf, gf, bf = r / 255, g / 255, b / 255
        cmax, cmin = max(rf, gf, bf), min(rf, gf, bf)
        delta = cmax - cmin
        l = (cmax + cmin) / 2
        s = 0 if delta == 0 else delta / (1 - abs(2 * l - 1))
        if delta == 0:
            h = 0
        elif cmax == rf:
            h = 60 * (((gf - bf) / delta) % 6)
        elif cmax == gf:
            h = 60 * (((bf - rf) / delta) + 2)
        else:
            h = 60 * (((rf - gf) / delta) + 4)
        return round(h, 1), round(s * 100, 1), round(l * 100, 1)

    def from_hex(self, hex_str: str) -> Tuple[bool, str]:
        try:
            r, g, b = self._hex_to_rgb(hex_str)
            h, s, l = self._rgb_to_hsl(r, g, b)
            name = hex_str.upper() if hex_str.startswith("#") else f"#{hex_str.upper()}"
            msg = (f"🎨  Color {name}:\n"
                   f"    RGB: rgb({r}, {g}, {b})\n"
                   f"    HSL: hsl({h}°, {s}%, {l}%)\n"
                   f"    Dec: {(r << 16 | g << 8 | b):,}")
            print(msg)
            return True, f"Color {name} → RGB({r},{g},{b})"
        except ValueError as e:
            return False, str(e)

    def from_rgb(self, r: int, g: int, b: int) -> Tuple[bool, str]:
        try:
            for val, name in [(r, "R"), (g, "G"), (b, "B")]:
                if not 0 <= int(val) <= 255:
                    return False, f"{name} value must be 0-255, got {val}"
            r, g, b = int(r), int(g), int(b)
            hex_str = f"#{r:02X}{g:02X}{b:02X}"
            h, s, l = self._rgb_to_hsl(r, g, b)
            msg = (f"🎨  Color rgb({r}, {g}, {b}):\n"
                   f"    Hex: {hex_str}\n"
                   f"    HSL: hsl({h}°, {s}%, {l}%)\n"
                   f"    Dec: {(r << 16 | g << 8 | b):,}")
            print(msg)
            return True, f"RGB({r},{g},{b}) → {hex_str}"
        except (TypeError, ValueError) as e:
            return False, f"Invalid RGB values: {e}"


