# NEW MODULE — Pomodoro Timer  [F-9 FIX — documented but never implemented]
# ══════════════════════════════════════════════════════════════════════════════
class PomodoroTimer:
    """
    Simple Pomodoro technique timer.
    Work interval: 25 min  |  Short break: 5 min  |  Long break: 15 min
    Counts completed pomodoros; every 4th triggers a long break.
    Runs entirely in daemon threads — no blocking.
    """

    WORK_MIN   = 25
    SHORT_MIN  =  5
    LONG_MIN   = 15

    def __init__(self):
        self._count    = 0        # completed pomodoros
        self._phase    = "idle"   # idle | work | short_break | long_break
        self._thread: Optional[threading.Thread] = None
        self._stop_evt = threading.Event()
        self._end_time: Optional[float] = None

    def start(self) -> Tuple[bool, str]:
        if self._phase not in ("idle", "done"):
            return False, (f"Pomodoro already running ({self._phase}). "
                           f"Say 'stop pomodoro' first.")
        self._stop_evt.clear()
        self._phase    = "work"
        self._end_time = time.monotonic() + self.WORK_MIN * 60
        self._thread   = threading.Thread(target=self._run, daemon=True, name="Pomodoro")
        self._thread.start()
        return True, (f"🍅  Pomodoro #{self._count + 1} started — "
                      f"{self.WORK_MIN} min work session. Stay focused!")

    def _run(self):
        while not self._stop_evt.is_set():
            remaining = self._end_time - time.monotonic()
            if remaining <= 0:
                if self._phase == "work":
                    self._count += 1
                    if self._count % 4 == 0:
                        self._phase    = "long_break"
                        self._end_time = time.monotonic() + self.LONG_MIN * 60
                        print(f"\n🍅  Pomodoro #{self._count} complete! "
                              f"Long break: {self.LONG_MIN} min\n")
                    else:
                        self._phase    = "short_break"
                        self._end_time = time.monotonic() + self.SHORT_MIN * 60
                        print(f"\n🍅  Pomodoro #{self._count} complete! "
                              f"Short break: {self.SHORT_MIN} min\n")
                else:  # break finished
                    self._phase = "done"
                    print("\n🍅  Break over! Say 'start pomodoro' to begin next session.\n")
                    break
            time.sleep(5)

    def stop(self) -> Tuple[bool, str]:
        if self._phase == "idle":
            return False, "No Pomodoro running"
        self._stop_evt.set()
        self._phase = "idle"
        return True, "🍅  Pomodoro stopped"

    def status(self) -> Tuple[bool, str]:
        if self._phase == "idle":
            return True, (f"🍅  Pomodoro idle — "
                          f"{self._count} session(s) completed. "
                          f"Say 'start pomodoro' to begin.")
        if self._end_time is None:
            return True, f"🍅  Phase: {self._phase} | Completed: {self._count}"
        remaining_s = max(0, int(self._end_time - time.monotonic()))
        m, s = divmod(remaining_s, 60)
        phase_label = {"work": "Work", "short_break": "Short Break",
                       "long_break": "Long Break", "done": "Done"}.get(self._phase, self._phase)
        return True, (f"🍅  {phase_label} — {m:02d}:{s:02d} remaining | "
                      f"Completed: {self._count}")


