# v6.0 MODULE — Browser Plugin Registry  (MODULAR MULTI-BROWSER SUPPORT)
# ══════════════════════════════════════════════════════════════════════════════
# [FIX-V12-MODULAR] Replaces every hardcoded (brave|chrome|edge|firefox|opera)
# list in the codebase with a single source of truth: BROWSER_REGISTRY.
#
# To add a new browser, you only need to add ONE entry to BROWSER_REGISTRY
# at the bottom of this block. Every other part of ARJUN (intent parser,
# session manager, regex patterns, _detect_browser) reads from the registry
# and automatically supports the new browser.
#
# Each plugin defines:
#   • canonical name  (e.g. "vivaldi")
#   • aliases         (e.g. ["vivaldi browser", "vivaldi browser snapshot"])
#   • process names   (for psutil detection)
#   • exe paths       (Windows / Linux / macOS)
#   • PATH commands   (for shutil.which fallback)
#   • internal URLs   (history, downloads, settings, bookmarks, ...)
#   • hotkey overrides (Firefox uses different shortcuts than Chromium)
#   • macOS app name  (for osascript focus)
#   • CDP support     (Chromium-based browsers expose the DevTools protocol
#                       on a debug port — most reliable automation path)
#   • incognito flag  (--incognito vs --private vs --inprivate)
# ══════════════════════════════════════════════════════════════════════════════
from typing import TypedDict as _TypedDict

class BrowserPlugin(_TypedDict, total=False):
    """Schema for a browser plugin entry. TypedDict gives IDE autocomplete."""
    canonical: str                     # "brave"
    display: str                       # "Brave Browser"
    aliases: List[str]                 # ["brave browser", "brave-browser"]
    process_names: List[str]           # ["brave.exe", "brave"]  (lowercase)
    exe_paths: List[str]               # OS-specific search paths (glob ok)
    path_cmds: List[str]               # for shutil.which fallback
    urls: Dict[str, Optional[str]]     # page_key → URL or None (keyboard-only)
    hotkey_overrides: Dict[str, Tuple[str, ...]]  # page_key → keys
    macos_app: str                     # "Brave Browser" for osascript
    cdp_support: bool                  # True for Chromium-based browsers
    incognito_flag: str                # "--incognito" / "--private" / "--inprivate"
    new_tab_flag: str                  # "--new-tab" (Chromium) / "-new-tab" (Firefox)
    desc: str                          # human-readable description


