class TestCommandSplitter(unittest.TestCase):
    def setUp(self):
        self.s = CommandSplitter()

    # ── parallel splitting ─────────────────────────────────────────────
    def test_simple_and(self):
        tasks = self.s.split("open chrome and settings")
        self.assertEqual(len(tasks), 2)
        self.assertIn("chrome", tasks[0].raw.lower())
        self.assertIn("settings", tasks[1].raw.lower())
        self.assertEqual(tasks[0].mode, ExecMode.PARALLEL)
        self.assertEqual(tasks[1].mode, ExecMode.PARALLEL)

    def test_three_items_oxford_comma(self):
        tasks = self.s.split("open chrome, settings, and VS Code")
        self.assertGreaterEqual(len(tasks), 2)

    def test_while_connector(self):
        tasks = self.s.split(
            "search for bus ticket in downloads while opening chrome"
        )
        self.assertGreaterEqual(len(tasks), 2)
        # Both should be PARALLEL (while = concurrent)
        self.assertTrue(all(t.mode == ExecMode.PARALLEL for t in tasks))

    def test_brave_private_telugu_vscode(self):
        tasks = self.s.split(
            "open a private window in brave, play Telugu songs, and launch VS Code"
        )
        self.assertGreaterEqual(len(tasks), 2)
        raws = " ".join(t.raw.lower() for t in tasks)
        self.assertIn("brave", raws)

    def test_simultaneous_phrase_stripped(self):
        tasks = self.s.split("open chrome and settings at the same time")
        raws = " ".join(t.raw.lower() for t in tasks)
        self.assertNotIn("at the same time", raws)

    def test_single_command_unchanged(self):
        tasks = self.s.split("what time is it")
        self.assertEqual(len(tasks), 1)
        self.assertIn("time", tasks[0].raw.lower())

    # ── sequential splitting ───────────────────────────────────────────
    def test_then_sequential(self):
        tasks = self.s.split("open chrome then go to gmail")
        self.assertGreaterEqual(len(tasks), 2)
        # Later tasks depend on earlier ones
        self.assertTrue(any(t.depends_on for t in tasks))

    def test_after_that_sequential(self):
        tasks = self.s.split("open VS Code after that install python extension")
        self.assertGreaterEqual(len(tasks), 2)

    # ── is_compound ────────────────────────────────────────────────────
    def test_is_compound_true(self):
        self.assertTrue(self.s.is_compound("open chrome and settings"))

    def test_is_compound_false(self):
        self.assertFalse(self.s.is_compound("what time is it"))

    # ── music enrichment ───────────────────────────────────────────────
    def test_telugu_songs_enriched(self):
        tasks = self.s.split("play Telugu songs")
        self.assertIn("youtube", tasks[0].raw.lower())

    def test_verb_propagation(self):
        tasks = self.s.split("open chrome and settings")
        # "settings" should get "open" prepended
        self.assertIn("open", tasks[1].raw.lower())

    def test_empty_input(self):
        tasks = self.s.split("")
        self.assertEqual(tasks, [])

    def test_four_items(self):
        tasks = self.s.split(
            "open chrome, brave, VS Code, and settings"
        )
        self.assertGreaterEqual(len(tasks), 3)


class TestDependencyGraph(unittest.TestCase):
    def setUp(self):
        self.g = DependencyGraph()

    def test_all_parallel(self):
        tasks = [
            ParallelTask(id="t0", raw="a", mode=ExecMode.PARALLEL),
            ParallelTask(id="t1", raw="b", mode=ExecMode.PARALLEL),
            ParallelTask(id="t2", raw="c", mode=ExecMode.PARALLEL),
        ]
        waves = self.g.build_waves(tasks)
        self.assertEqual(len(waves), 1)
        self.assertEqual(len(waves[0]), 3)

    def test_sequential_chain(self):
        tasks = [
            ParallelTask(id="t0", raw="a", mode=ExecMode.SEQUENTIAL, depends_on=[]),
            ParallelTask(id="t1", raw="b", mode=ExecMode.SEQUENTIAL, depends_on=["t0"]),
            ParallelTask(id="t2", raw="c", mode=ExecMode.SEQUENTIAL, depends_on=["t1"]),
        ]
        waves = self.g.build_waves(tasks)
        self.assertEqual(len(waves), 3)
        self.assertEqual(waves[0][0].id, "t0")
        self.assertEqual(waves[1][0].id, "t1")
        self.assertEqual(waves[2][0].id, "t2")

    def test_mixed_parallel_sequential(self):
        tasks = [
            ParallelTask(id="t0", raw="a", mode=ExecMode.PARALLEL,   depends_on=[]),
            ParallelTask(id="t1", raw="b", mode=ExecMode.PARALLEL,   depends_on=[]),
            ParallelTask(id="t2", raw="c", mode=ExecMode.SEQUENTIAL, depends_on=["t0","t1"]),
        ]
        waves = self.g.build_waves(tasks)
        self.assertEqual(len(waves), 2)
        self.assertEqual(len(waves[0]), 2)   # t0 + t1 in parallel
        self.assertEqual(waves[1][0].id, "t2")

    def test_empty_tasks(self):
        self.assertEqual(self.g.build_waves([]), [])

    def test_single_task(self):
        tasks = [ParallelTask(id="t0", raw="a")]
        waves = self.g.build_waves(tasks)
        self.assertEqual(len(waves), 1)


class TestResultAggregator(unittest.TestCase):
    def setUp(self):
        self.agg = ResultAggregator()

    def _make_task(self, id, raw, success, message, intent="app_control", params=None):
        from unittest.mock import MagicMock
        t = ParallelTask(id=id, raw=raw, success=success, message=message)
        spec = MagicMock()
        spec.intent     = intent
        spec.parameters = params or {"app_name": raw}
        t.task_spec     = spec
        return t

    def test_single_task_passthrough(self):
        t = self._make_task("t0", "open chrome", True, "Chrome opened")
        result = self.agg.aggregate([t], "open chrome", 100.0)
        self.assertEqual(result.summary, "Chrome opened")
        self.assertEqual(result.total, 1)
        self.assertEqual(result.succeeded, 1)

    def test_two_success(self):
        tasks = [
            self._make_task("t0", "open chrome",   True, "Chrome opened",   params={"app_name": "chrome"}),
            self._make_task("t1", "open settings", True, "Settings opened", params={"app_name": "settings"}),
        ]
        result = self.agg.aggregate(tasks, "open chrome and settings", 120.0)
        self.assertEqual(result.succeeded, 2)
        self.assertIn("and", result.summary)

    def test_partial_failure(self):
        tasks = [
            self._make_task("t0", "open chrome",   True,  "Chrome opened",  params={"app_name": "chrome"}),
            self._make_task("t1", "open settings", False, "Settings failed", params={"app_name": "settings"}),
        ]
        result = self.agg.aggregate(tasks, "open chrome and settings", 120.0)
        self.assertEqual(result.succeeded, 1)
        self.assertEqual(result.failed, 1)
        self.assertIn("but", result.summary.lower())

    def test_all_fail(self):
        tasks = [
            self._make_task("t0", "open chrome",   False, "Failed"),
            self._make_task("t1", "open settings", False, "Failed"),
        ]
        result = self.agg.aggregate(tasks, "open chrome and settings", 50.0)
        self.assertEqual(result.all_ok, False)
        self.assertIn("fail", result.summary.lower())

    def test_three_success_oxford_and(self):
        tasks = [
            self._make_task("t0", "open chrome",   True, "ok", params={"app_name": "chrome"}),
            self._make_task("t1", "open settings", True, "ok", params={"app_name": "settings"}),
            self._make_task("t2", "open VS Code",  True, "ok", params={"app_name": "VS Code"}),
        ]
        result = self.agg.aggregate(tasks, "...", 150.0)
        self.assertEqual(result.succeeded, 3)
        self.assertIn(",", result.summary)
        self.assertIn("and", result.summary)


