class TestParallelOrchestratorMocked(unittest.TestCase):
    """Tests ParallelOrchestrator with a mocked ARJUN."""

    def setUp(self):
        from unittest.mock import MagicMock

        self.arjun = MagicMock()
        self.arjun._last_response = ""
        self.arjun.running        = True

        # Mock pipeline
        pipe           = MagicMock()
        pipe.brain     = MagicMock()
        pipe._llm_brain= None
        pipe.normalizer= MagicMock()
        pipe.memory    = MagicMock()
        pipe.memory.record = MagicMock()

        spec           = MagicMock()
        spec.intent    = "app_control"
        spec.task      = "open_app"
        spec.confidence= 0.92
        spec.parameters= {"app_name": "chrome"}
        pipe.brain.understand.return_value = spec
        pipe.normalizer.normalize = lambda x: x.lower()
        self.arjun.pipeline = pipe

        # Make _raw_process update _last_response + call _respond
        def _fake_process(cmd):
            self.arjun._last_response = f"Done: {cmd[:30]}"
            self.arjun._respond(True, f"Done: {cmd[:30]}", tts=False)
        self.arjun._raw_process = _fake_process

        orig_respond = MagicMock()
        self.arjun._respond = orig_respond

        self.orch = ParallelOrchestrator(self.arjun, display=False)

    def test_single_command(self):
        result = self.orch.execute("open chrome")
        self.assertIsInstance(result, MultiTaskResult)
        self.assertEqual(result.total, 1)

    def test_parallel_two_commands(self):
        result = self.orch.execute("open chrome and settings")
        self.assertIsInstance(result, MultiTaskResult)
        self.assertGreaterEqual(result.total, 2)

    def test_all_tasks_complete(self):
        result = self.orch.execute("open chrome and settings")
        self.assertEqual(result.total, result.succeeded + result.failed)

    def test_empty_command(self):
        result = self.orch.execute("")
        self.assertEqual(result.total, 0)

    def test_patch_arjun(self):
        self.orch.patch_arjun(self.arjun)
        # After patching, arjun.process should be the patched version
        self.assertTrue(callable(self.arjun.process))
        # Call it
        self.arjun.process("open chrome")
        # _last_response should be set
        self.assertIsInstance(self.arjun._last_response, str)

    def test_three_parallel_tasks(self):
        result = self.orch.execute("open chrome, settings, and VS Code")
        self.assertGreaterEqual(result.total, 2)
        self.assertEqual(result.total, result.succeeded + result.failed)

    def test_result_has_summary(self):
        result = self.orch.execute("open chrome and settings")
        self.assertIsInstance(result.summary, str)
        self.assertGreater(len(result.summary), 0)

