class TestShellInjectionFix(unittest.TestCase):
    """[S-1] subprocess.Popen must not use shell=True — except inside the
    TerminalAgent class, where shell=True is DELIBERATE (the user explicitly
    asked to run a shell command) and is gated behind the SafetyGate which
    requires explicit user confirmation before execution.
    """
    def test_no_shell_true_in_launch(self):
        import ast as _ast
        src = open(__file__, encoding="utf-8").read()
        tree = _ast.parse(src)
        # Find the line range of the TerminalAgent class so we can exclude it
        terminal_agent_start = None
        terminal_agent_end = None
        for node in _ast.walk(tree):
            if isinstance(node, _ast.ClassDef) and node.name == "TerminalAgent":
                terminal_agent_start = node.lineno
                terminal_agent_end = node.end_lineno or (node.lineno + 200)
                break
        class ShellFinder(_ast.NodeVisitor):
            def __init__(self):
                self.violations = []
            def visit_Call(self, node):
                if isinstance(node.func, _ast.Attribute) and node.func.attr in ("Popen","run","call"):
                    for kw in node.keywords:
                        if kw.arg == "shell" and isinstance(kw.value, _ast.Constant) and kw.value.value is True:
                            # Allow shell=True inside TerminalAgent (deliberate, safety-gated)
                            if terminal_agent_start and terminal_agent_start <= node.lineno <= terminal_agent_end:
                                continue
                            self.violations.append(node.lineno)
                self.generic_visit(node)
        sf = ShellFinder()
        sf.visit(tree)
        self.assertEqual(sf.violations, [], f"shell=True found at lines: {sf.violations}")


